import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import "./index.css";
import { App } from "./App";
import PWAProvider from "./PWAProvider";

/**
 * Глубокая очистка кэшей файлов и IndexedDB.
 * LocalStorage уже очищен синхронно в index.html.
 */
function performFinalCleanup() {
  // 1. Очистка Cache Storage (в фоне)
  if ('caches' in window) {
    caches.keys().then(names => {
      for (const name of names) caches.delete(name);
    });
  }

  // 2. Очистка IndexedDB (в фоне)
  if (window.indexedDB && window.indexedDB.databases) {
    window.indexedDB.databases().then(dbs => {
      for (const db of dbs) {
        if (db.name) window.indexedDB.deleteDatabase(db.name);
      }
    });
  }
  
  // 3. Очистка URL БЕЗ перезагрузки
  const url = new URL(window.location.href);
  url.searchParams.delete('clear_cache');
  url.searchParams.delete('v');
  window.history.replaceState({}, document.title, url.pathname);
}

function bootstrap() {
  const params = new URLSearchParams(window.location.search);
  
  if (params.has('clear_cache')) {
    performFinalCleanup();
  }

  const container = document.getElementById("root");
  if (container) {
    createRoot(container).render(
      <StrictMode>
        <PWAProvider>
          <App />
        </PWAProvider>
      </StrictMode>
    );
  }
}

bootstrap();
