// src/generator/components/ui/ToolButtons.tsx
import React from "react";
import { cn } from "../../../utils/cn";

export function ZoomBtn({ icon, onClick, title }: { icon: React.ReactNode; onClick: () => void; title: string }) {
  return (
    <button
      onClick={onClick}
      title={title}
      aria-label={title}
      className={cn(
        "w-11 h-11 rounded-xl flex items-center justify-center transition-all duration-300 active:scale-90 border-2 shadow-sm",
        "bg-white/40 dark:bg-slate-800/40 border-slate-100 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-white hover:text-indigo-600 dark:hover:text-white"
      )}
    >
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
        {icon}
      </svg>
    </button>
  );
}

export function GridBtn({ label, active, onClick }: { label: string; active: boolean; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      aria-label={label}
      aria-pressed={active}
      className={cn(
        "py-1.5 px-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all duration-300 min-h-[44px] border-2 active:scale-95 shadow-sm",
        active
          ? "bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/20"
          : "bg-white/40 dark:bg-slate-800/40 border-slate-100 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-white"
      )}
    >
      {label}
    </button>
  );
}

export function VisualGridBtn({ 
  active, 
  onClick, 
  title, 
  icon 
}: { 
  active: boolean; 
  onClick: () => void; 
  title: string;
  icon: React.ReactNode;
}) {
  return (
    <button
      onClick={onClick}
      title={title}
      aria-label={title}
      aria-pressed={active}
      className={cn(
        "w-12 h-12 rounded-2xl flex items-center justify-center transition-all duration-300 border-2 active:scale-90 shadow-sm",
        active
          ? "bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/25 scale-105"
          : "bg-slate-50/50 dark:bg-slate-800/50 border-slate-100 dark:border-slate-700 text-slate-400 dark:text-slate-500 hover:bg-white dark:hover:bg-slate-700 hover:text-slate-600"
      )}
    >
      <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
        {icon}
      </svg>
    </button>
  );
}

export function ToolMenuItem({ icon, label, active, onClick }: { icon: React.ReactNode; label: string; active: boolean; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all duration-300 text-left active:scale-[0.98] border-2 shadow-sm",
        active
          ? "bg-indigo-50 dark:bg-indigo-900/20 border-indigo-100 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400"
          : "bg-white dark:bg-slate-900 border-slate-50 dark:border-slate-800 text-slate-500 dark:text-slate-400 hover:border-indigo-200 dark:hover:border-indigo-900"
      )}
    >
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className={cn("shrink-0", active ? "text-indigo-500" : "text-slate-400")}>{icon}</svg>
      <span className="flex-1">{label}</span>
      {active && <div className="w-2 h-2 rounded-full bg-indigo-500 shadow-lg shadow-indigo-500/50" />}
    </button>
  );
}

export function ViewToggle({ active, onClick, label, icon }: { active: boolean; onClick: () => void; label: string; icon: "numbers" | "fill" | "contours" }) {
  return (
    <button
      onClick={onClick}
      aria-label={label}
      aria-pressed={active}
      title={label}
      className={cn(
        "px-5 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all duration-300 flex items-center gap-2 border-2 active:scale-95 shadow-sm",
        active
          ? "bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/25"
          : "bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-slate-50 hover:text-slate-700"
      )}
    >
      {icon === "numbers" ? (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" className="shrink-0">
          <path d="M4 7h4M4 17h4M4 12h3" /><path d="M14 7h2v4M14 17h4M14 13h2v4" />
        </svg>
      ) : icon === "contours" ? (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="shrink-0">
          <path d="M12 3c-4.97 0-9 4.03-9 9s4.03 9 9 9 9-4.03 9-9c0-4.97-4.03-9-9-9z" />
          <path d="M12 8a4 4 0 1 0 0 8 4 4 0 0 0 0-8z" />
        </svg>
      ) : (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="shrink-0">
          {active ? (
            <><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" /><circle cx="12" cy="12" r="3" /></>
          ) : (
            <><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94" /><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19" /><line x1="1" y1="1" x2="23" y2="23" /></>
          )}
        </svg>
      )}
      {label}
    </button>
  );
}