// src/store/appStore.ts
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { DEFAULT_ENGINE_SETTINGS, BASE_COLORS, PAINT_PROFILES, type EngineSettings, type ColorComponent, type RGB } from '../config';
import type { HistoryEntry } from '../types';
import type { CalibrationEntry } from '../calibration';

interface AppState {
  isDark: boolean;
  customColors: ColorComponent[];
  overrides: Record<string, RGB>;
  deletedBuiltIns: string[];
  selectedNames: string[];
  engineSettings: EngineSettings;
  totalPartsLimit: string | number;
  history: HistoryEntry[];
  favorites: string[];

  // Actions
  toggleTheme: () => void;
  setTheme: (isDark: boolean) => void;
  saveColor: (color: ColorComponent, isBuiltIn: boolean, originalName?: string) => void;
  deleteColor: (name: string, isCustom: boolean) => void;
  restoreBuiltIn: (name: string) => void;
  toggleColorSelection: (name: string) => void;
  setAllColorsSelection: (names: string[]) => void;
  resetPalette: () => void;
  updateEngineSettings: (patch: Partial<EngineSettings>) => void;
  setTotalPartsLimit: (limit: string | number) => void;
  addHistory: (entries: HistoryEntry[]) => void;
  clearHistory: () => void;
  toggleFavorite: (key: string) => void;
  clearFavorites: () => void;
  importCalibration: (entries: CalibrationEntry[]) => void;
}

export const useAppStore = create<AppState>()(
  persist(
    (set, get) => ({
      isDark: window.matchMedia ? window.matchMedia('(prefers-color-scheme: dark)').matches : false,
      customColors: [],
      overrides: {},
      deletedBuiltIns: [],
      selectedNames: BASE_COLORS.map(c => c.name),
      engineSettings: DEFAULT_ENGINE_SETTINGS,
      totalPartsLimit: 'авто',
      history: [],
      favorites: [],

      toggleTheme: () => set((state) => ({ isDark: !state.isDark })),
      
      setTheme: (isDark) => set({ isDark }),

      saveColor: (c, isBuiltIn, originalName) => set((state) => {
        if (originalName) {
          // Если имя изменилось, обновляем его в selectedNames, чтобы цвет не пропал из палитры
          const updatedSelectedNames = state.selectedNames.map(n => n === originalName ? c.name : n);
          
          if (isBuiltIn) {
            const newOverrides = { ...state.overrides };
            if (c.name !== originalName) delete newOverrides[originalName];
            newOverrides[c.name] = c.rgb;
            return { overrides: newOverrides, selectedNames: updatedSelectedNames };
          } else {
            return { 
              customColors: state.customColors.map(x => x.name === originalName ? c : x),
              selectedNames: updatedSelectedNames
            };
          }
        } else {
          return {
            customColors: [...state.customColors, c],
            selectedNames: Array.from(new Set([...state.selectedNames, c.name]))
          };
        }
      }),

      deleteColor: (name, isCustom) => set((state) => {
        if (isCustom) {
          return {
            customColors: state.customColors.filter(c => c.name !== name),
            selectedNames: state.selectedNames.filter(n => n !== name)
          };
        } else {
          const { [name]: _, ...restOverrides } = state.overrides;
          return {
            deletedBuiltIns: Array.from(new Set([...state.deletedBuiltIns, name])),
            selectedNames: state.selectedNames.filter(n => n !== name),
            overrides: restOverrides
          };
        }
      }),

      restoreBuiltIn: (name) => set((state) => {
        const { [name]: _, ...restOverrides } = state.overrides;
        return {
          deletedBuiltIns: state.deletedBuiltIns.filter(n => n !== name),
          selectedNames: Array.from(new Set([...state.selectedNames, name])),
          overrides: restOverrides
        };
      }),

      toggleColorSelection: (name) => set((state) => ({
        selectedNames: state.selectedNames.includes(name)
          ? state.selectedNames.filter(n => n !== name)
          : [...state.selectedNames, name]
      })),

      setAllColorsSelection: (names) => set({ selectedNames: names }),

      resetPalette: () => set({ selectedNames: BASE_COLORS.map(c => c.name) }),

      updateEngineSettings: (patch) => set((state) => {
        const newSettings = { ...state.engineSettings, ...patch };
        // Автоматически подстраиваем maxColorsInMix под рекомендуемое значение при смене типа краски
        if (patch.paintType && patch.paintType !== state.engineSettings.paintType) {
          newSettings.maxColorsInMix = PAINT_PROFILES[patch.paintType].maxColorsInMix;
        }
        return { engineSettings: newSettings };
      }),

      setTotalPartsLimit: (limit) => set({ totalPartsLimit: limit }),

      addHistory: (entries) => set((state) => {
        // Защита от дубликатов (спама) при многократном нажатии "Рассчитать"
        if (state.history.length > 0 && entries.length === 1) {
          const last = state.history[0];
          const curr = entries[0];
          if (last.hex === curr.hex && last.paintType === curr.paintType) {
            return state; 
          }
        }
        return { history: [...entries, ...state.history].slice(0, 50) };
      }),

      clearHistory: () => set({ history: [] }),

      toggleFavorite: (key) => set((state) => ({
        favorites: state.favorites.includes(key)
          ? state.favorites.filter(k => k !== key)
          : [...state.favorites, key]
      })),

      clearFavorites: () => set({ favorites: [] }),

      importCalibration: (entries) => set((state) => {
        const overridesCopy = { ...state.overrides };
        const customColorsCopy = [...state.customColors];

        for (const e of entries) {
          const customIdx = customColorsCopy.findIndex(c => c.name === e.name);
          if (customIdx !== -1) {
            // Кастомный цвет обновляем напрямую, чтобы его можно было удалить потом
            customColorsCopy[customIdx] = { ...customColorsCopy[customIdx], rgb: e.calibratedRgb };
          } else {
            // Встроенный пишем в overrides
            overridesCopy[e.name] = e.calibratedRgb;
          }
        }
        return { overrides: overridesCopy, customColors: customColorsCopy };
      }),
    }),
    {
      name: 'melura_global_state',
      partialize: (state) => ({
        isDark: state.isDark,
        customColors: state.customColors,
        overrides: state.overrides,
        deletedBuiltIns: state.deletedBuiltIns,
        selectedNames: state.selectedNames,
        engineSettings: state.engineSettings,
        totalPartsLimit: state.totalPartsLimit,
        history: state.history,
        favorites: state.favorites,
      }),
      merge: (persistedState: any, currentState) => ({
        ...currentState,
        ...persistedState,
        engineSettings: {
          ...currentState.engineSettings,
          ...(persistedState?.engineSettings || {})
        }
      })
    }
  )
);