import type { RGB } from '../../config';
import { getLuminance, clamp01, lerp, lerpHue, lerpRgb } from './mathHelpers';
import { rgbToHsl, hslToRgb, rgbToLab, deltaE00 } from '../colorMath';

export function warmCoolStrategy(rgb: RGB): RGB {
  const lum = getLuminance(rgb);
  const coldHue = 220;
  const coldSat = 0.35;
  const warmHue = 35;
  const warmSat = 0.55;
  const neutralSat = 0.15;
  const t = clamp01(lum / 255);

  let newH: number, newS: number;

  if (t < 0.3) {
    const localT = t / 0.3;
    newH = lerpHue(coldHue, warmHue, localT * 0.3);
    newS = lerp(coldSat, neutralSat, localT);
  } else if (t > 0.7) {
    const localT = (t - 0.7) / 0.3;
    newH = lerpHue(warmHue * 0.3, warmHue, localT);
    newS = lerp(neutralSat, warmSat, localT);
  } else {
    const localT = (t - 0.3) / 0.4;
    newH = lerpHue(coldHue * 0.1, warmHue * 0.2, localT);
    newS = neutralSat;
  }

  const newL = lerp(0.15, 0.85, t);
  return hslToRgb(newH, newS, newL);
}

export function fauvismStrategy(rgb: RGB): RGB {
  const [h, s, l] = rgbToHsl(rgb);
  const lum = getLuminance(rgb);
  
  const hueShift = 120;
  const newH = ((h + hueShift) % 360 + 360) % 360;
  const newS = lerp(0.85, 1.0, s);
  
  const t = clamp01(lum / 255);
  const newL = t < 0.5
    ? lerp(0.1, 0.5, t * 2) * 0.8
    : lerp(0.5, 0.9, (t - 0.5) * 2) * 1.15;
    
  return hslToRgb(newH, newS, clamp01(newL));
}

export function impressionismStrategy(rgb: RGB): RGB {
  const [h, s, l] = rgbToHsl(rgb);
  const hueVariations = [-25, -12, 0, 12, 25];
  const hueIndex = Math.min(4, Math.floor((h % 360) / 72));
  const hueShift = hueVariations[hueIndex];
  
  const newH = ((h + hueShift) % 360 + 360) % 360;
  const newS = lerp(0.55, 0.90, s);
  const newL = Math.max(0.25, l) * 1.12;
  
  return hslToRgb(newH, newS, clamp01(newL));
}

export function noirStrategy(rgb: RGB): RGB {
  const [h, s, l] = rgbToHsl(rgb);
  const lum = getLuminance(rgb);
  const t = clamp01(lum / 255);
  const isAccent = s > 0.5 && lum > 120;

  if (isAccent) {
    const accentHues = [180, 300, 270];
    const accentIndex = Math.min(2, Math.floor(t * 3));
    return hslToRgb(accentHues[accentIndex], 0.95, 0.65);
  }

  const newH = 210;
  const newS = lerp(0.08, 0.35, t);
  const newL = lerp(0.08, 0.45, t);
  return hslToRgb(newH, newS, newL);
}

export function vintageStrategy(rgb: RGB): RGB {
  const [h, s, l] = rgbToHsl(rgb);
  const lum = getLuminance(rgb);
  const t = clamp01(lum / 255);
  
  const sepiaHue = 35;
  const vintageFactor = lerp(0.75, 0.55, t);
  const newH = lerpHue(h, sepiaHue, vintageFactor);
  const newS = l * 0.15 + s * (1 - vintageFactor) * 0.35;
  const newL = l * 0.88;
  
  return hslToRgb(newH, clamp01(newS), clamp01(newL));
}

export function popArtStrategy(rgb: RGB): RGB {
  const lum = getLuminance(rgb);
  const t = clamp01(lum / 255);
  
  const palette: RGB[] = [
    [255, 0, 100],
    [0, 200, 255],
    [255, 200, 0],
    [150, 0, 255],
    [0, 255, 150],
    [255, 100, 0],
  ];

  const floatIndex = t * (palette.length - 1);
  const index = Math.floor(floatIndex);
  const frac = floatIndex - index;

  const safeIndex = Math.min(palette.length - 2, Math.max(0, index));
  return lerpRgb(palette[safeIndex], palette[safeIndex + 1], frac);
}

export function customPaletteStrategy(rgb: RGB, palette: RGB[]): RGB {
  if (palette.length === 0) return rgb;
  const lab = rgbToLab(rgb);
  let bestColor = palette[0];
  let bestDist = Infinity;

  for (const candidate of palette) {
    const candidateLab = rgbToLab(candidate);
    const dist = deltaE00(lab, candidateLab);
    if (dist < bestDist) {
      bestDist = dist;
      bestColor = candidate;
    }
  }

  return bestColor;
}