import { cn } from '../utils/cn';

export function ResultSkeleton() {
  const pulse = "animate-pulse bg-slate-100 dark:bg-slate-800/50 rounded-2xl";
  return (
    <div className="w-full max-w-2xl mx-auto p-5 sm:p-8 space-y-8">
      {/* Hero Skeleton */}
      <div className="flex justify-center py-6 relative">
         <div className={cn(pulse, "w-32 h-32 sm:w-40 sm:h-40 rounded-2xl transform -rotate-6 -translate-x-6")} />
         <div className={cn(pulse, "w-32 h-32 sm:w-40 sm:h-40 rounded-2xl transform rotate-6 translate-x-6 absolute")} />
      </div>

      {/* Dashboard Skeleton */}
      <div className={cn(pulse, "h-32 rounded-2xl")} />

      {/* List Skeleton */}
      <div className="space-y-4">
        <div className="flex items-center gap-2">
           <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
           <div className={cn(pulse, "w-24 h-3 rounded-full")} />
           <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
        </div>
        <div className="space-y-3">
          {[1, 2, 3].map(i => (
            <div key={i} className={cn(pulse, "h-20 rounded-2xl")} />
          ))}
        </div>
      </div>
    </div>
  );
}
