import { useState, useCallback, useEffect } from "react";
import { useAppStore } from "../store";
import { useBackButton } from "../../hooks/useBackButton";
import { cn } from "../../utils/cn";

export function UrlModal({ onLoadImage }: { onLoadImage: (file: File) => void }) {
  const isDark = useAppStore((s) => s.isDark);
  const isOpen = useAppStore((s) => s.urlModalOpen);
  const update = useAppStore((s) => s.update);

  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [progress, setProgress] = useState(0);
  const [statusText, setStatusText] = useState("");

  const close = useCallback(() => {
    update({ urlModalOpen: false });
    setUrl("");
    setError("");
    setLoading(false);
    setProgress(0);
    setStatusText("");
  }, [update]);

  useBackButton(isOpen, close);

  const load = useCallback(async () => {
    if (!url.trim()) return;
    setLoading(true);
    setError("");
    setProgress(10);
    setStatusText("Анализ ссылки...");

    let cleanUrl = url.trim();
    
    // 1. Пытаемся извлечь og:image
    try {
      setStatusText("Поиск изображения на странице...");
      setProgress(20);
      const htmlProxyUrl = `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(cleanUrl)}`;
      const htmlResp = await fetch(htmlProxyUrl, { cache: 'no-store' });
      if (htmlResp.ok) {
        const html = await htmlResp.text();
        if (html && typeof html === 'string') {
          const parser = new DOMParser();
          const doc = parser.parseFromString(html, "text/html");
          const ogImage = doc.querySelector('meta[property="og:image"]')?.getAttribute('content');
          const twitterImage = doc.querySelector('meta[name="twitter:image"]')?.getAttribute('content');
          const imgUrl = ogImage || twitterImage;
          if (imgUrl && imgUrl.startsWith('http')) {
            cleanUrl = imgUrl;
          }
        }
      }
    } catch (e) {
      // Игнорируем ошибки
    }

    // 2. Очистка URL
    try {
      const u = new URL(cleanUrl);
      if (u.hostname.includes('pinimg.com')) {
        cleanUrl = u.origin + u.pathname;
        cleanUrl = cleanUrl.replace(/\/\d+x\//, '/originals/');
      }
    } catch(e) {}

    // 3. Расширенный список прокси
    const proxyList = [
      { url: (u: string) => u, name: "Прямой запрос" },
      { url: (u: string) => `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(u)}`, name: "Сервер 1" },
      { url: (u: string) => `https://wsrv.nl/?url=${encodeURIComponent(u)}`, name: "Сервер 2" },
      { url: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}`, name: "Сервер 3" },
      { url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}`, name: "Сервер 4" },
      { url: (u: string) => `https://thingproxy.freeboard.io/fetch/${encodeURIComponent(u)}`, name: "Сервер 5" },
    ];

    const proxyStep = 60 / proxyList.length;
    let currentProgress = 30;

    for (let i = 0; i < proxyList.length; i++) {
      const proxy = proxyList[i];
      try {
        setStatusText(`Подключение: ${proxy.name}...`);
        setProgress(Math.min(90, currentProgress));
        
        const target = proxy.url(cleanUrl);
        const resp = await fetch(target, { cache: 'no-store', mode: 'cors' });
        if (!resp.ok) {
           currentProgress += proxyStep;
           continue;
        }
        
        setStatusText("Скачивание файла...");
        setProgress(95);

        const blob = await resp.blob();
        if (!blob.type.startsWith('image/')) {
           currentProgress += proxyStep;
           continue;
        }
        
        setStatusText("Успешно!");
        setProgress(100);

        const file = new File([blob], `image.${blob.type.split('/')[1] || 'jpg'}`, { type: blob.type });
        onLoadImage(file);
        
        setTimeout(() => close(), 400);
        return;
      } catch (e) {
        currentProgress += proxyStep;
        continue;
      }
    }

    setProgress(0);
    setStatusText("");
    setError("Сайт блокирует автоматическую загрузку. Пожалуйста, откройте ссылку, сохраните фото вручную и загрузите его как файл.");
    setLoading(false);
  }, [url, onLoadImage, close]);

  if (!isOpen) return null;

  const isPinterest = url.toLowerCase().includes('pinterest') || url.toLowerCase().includes('pinimg');

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 sm:p-6 pt-[max(1rem,env(safe-area-inset-top))]" role="dialog" aria-modal="true" aria-label="Загрузка по ссылке">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity" onClick={close} />
      <div className={cn("relative z-10 w-full max-w-md rounded-2xl shadow-premium flex flex-col overflow-hidden animate-fade-in-up", isDark ? "bg-slate-900 border border-white/10" : "bg-white border border-black/5")}>
        <div className="px-6 pt-5 pb-4 border-b flex items-center justify-between">
           <h2 className={cn("text-base sm:text-lg font-bold", isDark ? "text-white" : "text-slate-900")}>Загрузить по ссылке</h2>
           <button onClick={close} className="w-9 h-9 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200" aria-label="Закрыть"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12" /></svg></button>
        </div>
        <div className="p-6 space-y-5">
          <input type="url" value={url} onChange={e => setUrl(e.target.value)} onKeyDown={e => e.key === "Enter" && load()} placeholder="Вставьте ссылку на фото..." className={cn("w-full px-5 py-4 rounded-2xl text-sm font-bold border-2 transition-all shadow-inner", isDark ? "bg-slate-800 border-transparent text-white focus:border-indigo-500/50" : "bg-slate-50 border-transparent text-slate-900 focus:border-indigo-500/50")} />
          
          {loading && (
            <div className="space-y-2 py-2">
              <div className="flex justify-between text-xs font-bold text-slate-500 uppercase tracking-wider">
                <span>{statusText}</span>
                <span>{Math.round(progress)}%</span>
              </div>
              <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-500 transition-all duration-300 ease-out rounded-full"
                  style={{ width: `${progress}%` }}
                />
              </div>
            </div>
          )}

          {!loading && isPinterest && !error && (
             <div className="p-3 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-900/30 flex items-center gap-3">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-indigo-500"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4M12 8h.01"/></svg>
                <p className="text-xs font-black text-indigo-700 dark:text-indigo-300 uppercase tracking-tighter">Pinterest часто блокирует ссылки. Если не сработает — используйте кнопку ниже.</p>
             </div>
          )}

          {!loading && error && (
             <div className="p-4 rounded-2xl bg-red-50 dark:bg-red-900/10 border border-red-100 dark:border-red-900/20 space-y-3">
                <p className="text-xs font-black text-red-600 dark:text-red-400 uppercase tracking-tight text-center">{error}</p>
                <button onClick={() => window.open(url, '_blank')} className="w-full py-2.5 rounded-xl bg-white dark:bg-slate-800 text-xs font-black uppercase tracking-widest text-slate-600 dark:text-slate-300 border border-slate-200 shadow-sm active:scale-95 transition-all">Открыть и сохранить вручную</button>
             </div>
          )}

          <button onClick={load} disabled={!url.trim() || loading} className="w-full py-4 rounded-2xl font-black text-xs uppercase tracking-widest bg-indigo-600 text-white shadow-lg shadow-indigo-600/25 hover:bg-indigo-700 disabled:opacity-40 transition-all">{loading ? "Загрузка..." : "Начать импорт"}</button>
        </div>
      </div>
    </div>
  );
}
