import type { ImageProfileStats } from "../store/types";

export interface AutoParamsResult {
  level: "simple" | "balanced" | "complex";
  label: string;
  numColors: number;
  detail: number;
}

export function calculateAutoParams(profile: ImageProfileStats): AutoParamsResult[] {
  // ФИЛОСОФИЯ РАСКРАСОК ПО НОМЕРАМ:
  // 1. Человек раскрашивает руками и кисточками (размера 0, 1, 2, реже 00). 
  // 2. Микроскопические зоны (размером с 1-2 пикселя) - это брак. Их невозможно раскрасить, они вызывают раздражение и усталость глаз.
  // 3. Более 25-30 цветов на стандартном холсте - это абсурд. Человеческий глаз едва различает близкие оттенки краски, 
  //    а мыть кисть и открывать/закрывать 40+ баночек ради пары мазков - это мучение, а не хобби.
  // 4. Суть картины по номерам - это стилизация, обобщение (color blocking) и выделение ГЛАВНОГО, а не фотореализм.

  // БАЗОВЫЕ ЛИМИТЫ КРАСОК (Ориентир на реальные физические наборы):
  // Простые картины: 10-15 баночек (крупные мазки, декоративный стиль)
  // Оптимальные: 16-22 баночки (достаточно для объема лица или пейзажа)
  // Сложные: 24-28 баночек (максимум для гурманов)
  
  let targetColors = 18; // Золотая середина

  // Легкая корректировка от фото, но без выхода за человеческие рамки
  if (profile.distinctHues < 10 || profile.isMonochrome) {
    targetColors -= 4; // ЧБ или пастельные тона
  } else if (profile.colorfulness > 0.6) {
    targetColors += 2; // Очень пестрые фото (попугаи, цветы)
  }

  // ОПРЕДЕЛЕНИЕ ДЕТАЛИЗАЦИИ (Размер зон):
  // Детализация 1-3: Огромные формы (кисть №2-3). Лица превратятся в грубую абстракцию.
  // Детализация 4-6: Средние формы (кисть №1-0). Отлично для лиц крупным планом, объектов.
  // Детализация 7-9: Мелкие формы (кисть №00). Трудоемко. Нужно для пейзажей или мелких лиц.
  // Детализация 10: Машинный мусор (конфетти).
  
  let targetDetail = 6; // Стандарт для сохранения черт лица

  // Защита от "Конфетти" (шума)
  if (profile.complexity > 0.08) {
    // Если на фото кусты, трава или шерсть, алгоритм хочет раздробить их на тысячи зон.
    // Мы ЗАПРЕЩАЕМ ему это делать и заставляем слить траву в крупные мазки (уменьшаем детализацию).
    targetDetail = 5; 
  } else if (profile.complexity < 0.03) {
    // Гладкие фото (студийный портрет, макросъемка). Мусора нет,
    // поэтому можно безопасно поднять детализацию, чтобы красиво отрисовать ресницы и блики губ.
    targetDetail = 7; 
  }

  const clamp = (val: number, min: number, max: number) => Math.max(min, Math.min(max, Math.round(val)));

  return [
    {
      level: "simple",
      label: "Простая",
      // Для релакса или детей. Крупные пятна, минимум баночек. 
      // (Не подходит для лиц мелким планом, но отлично для декора)
      numColors: clamp(targetColors - 6, 8, 15),
      detail: clamp(targetDetail - 2, 3, 4),
    },
    {
      level: "balanced",
      label: "Оптимальная",
      // Баланс между узнаваемостью (особенно лиц) и комфортом кисти.
      // 16-22 цвета - стандарт индустрии. Детализация 5-7 сохранит черты, не создавая мусора.
      numColors: clamp(targetColors, 16, 22),
      detail: clamp(targetDetail, 5, 7),
    },
    {
      level: "complex",
      label: "Сложная",
      // Максимум реализма, который еще можно осилить кистью №00 и не сойти с ума.
      // Строгий лимит в 28 цветов! Больше человеку не нужно.
      numColors: clamp(targetColors + 6, 24, 28),
      detail: clamp(targetDetail + 2, 7, 9),
    }
  ];
}