import type { ProcessingResult } from "./types";

function rgbToHueDegrees(r: number, g: number, b: number): number {
  const rn = r / 255;
  const gn = g / 255;
  const bn = b / 255;

  const mx = Math.max(rn, gn, bn);
  const mn = Math.min(rn, gn, bn);
  const d = mx - mn;

  if (d === 0) return 0;

  let h = 0;
  switch (mx) {
    case rn:
      h = ((gn - bn) / d + (gn < bn ? 6 : 0)) * 60;
      break;
    case gn:
      h = ((bn - rn) / d + 2) * 60;
      break;
    case bn:
      h = ((rn - gn) / d + 4) * 60;
      break;
  }

  return h;
}

export function profileImageQuick(data: Uint8ClampedArray, w: number, h: number): any {
  const total = w * h;
  const skip = Math.max(1, Math.floor(total / 8000));

  const hueBins = new Float64Array(36);
  let n = 0;
  let satSum = 0;
  const chromaValues: number[] = [];

  for (let i = 0; i < total; i += skip) {
    const p = i * 4;
    const r = data[p];
    const g = data[p + 1];
    const b = data[p + 2];

    const mx = Math.max(r, g, b);
    const mn = Math.min(r, g, b);
    const s = mx === 0 ? 0 : (mx - mn) / mx;

    if (s > 0.08) {
      const hue = rgbToHueDegrees(r, g, b);
      hueBins[Math.min(35, Math.floor((hue / 360) * 36))]++;
    }

    satSum += s;
    n++;

    const dr = r - g;
    const dg = g - b;
    const db = b - r;
    chromaValues.push(Math.sqrt(dr * dr + dg * dg + db * db) / 3);
  }

  const chromaTotal = hueBins.reduce((a, b) => a + b, 0);
  let distinctHues = 0;
  for (const c of hueBins) if (c > chromaTotal * 0.01) distinctHues++;

  let colorfulness = 0;
  for (const c of chromaValues) colorfulness += c;
  colorfulness = chromaValues.length > 0 ? Math.min(1, colorfulness / chromaValues.length / 45) : 0;

  const satMean = n > 0 ? satSum / n : 0;

  let edges = 0;
  const edgeStep = Math.max(2, Math.floor(Math.sqrt(total / 20000)));

  for (let y = 1; y < h - 1; y += edgeStep) {
    for (let x = 1; x < w - 1; x += edgeStep) {
      const l2 = (y * w + (x - 1)) * 4;
      const r2 = (y * w + (x + 1)) * 4;
      const u = ((y - 1) * w + x) * 4;
      const d2 = ((y + 1) * w + x) * 4;

      const gx =
        Math.abs(data[r2] - data[l2]) +
        Math.abs(data[r2 + 1] - data[l2 + 1]) +
        Math.abs(data[r2 + 2] - data[l2 + 2]);

      const gy =
        Math.abs(data[d2] - data[u]) +
        Math.abs(data[d2 + 1] - data[u + 1]) +
        Math.abs(data[d2 + 2] - data[u + 2]);

      if (gx + gy > 80) edges++;
    }
  }

  const totalEdgeSamples = total / (edgeStep * edgeStep);
  const complexity = totalEdgeSamples > 0 ? Math.min(1, edges / totalEdgeSamples) : 0;

  const coarse = new Map<number, number>();
  for (let i = 0; i < total; i += skip) {
    const p = i * 4;
    const key = ((data[p] >> 4) << 8) | ((data[p + 1] >> 4) << 4) | (data[p + 2] >> 4);
    coarse.set(key, (coarse.get(key) ?? 0) + 1);
  }

  let maxBucket = 0;
  for (const v of coarse.values()) if (v > maxBucket) maxBucket = v;
  const dominance = n > 0 ? maxBucket / n : 0;

  return {
    distinctHues,
    satMean,
    complexity,
    colorfulness,
    dominance,
    isMonochrome: satMean < 0.08,
    isSimple: complexity < 0.03 && dominance > 0.25,
    isComplex: complexity > 0.08,
  };
}

export function generateColorPreview(res: ProcessingResult, targetSize: number = 120): string {
  const { imgW, imgH, labelMask, colorPalette } = res;
  const scale = Math.min(targetSize / imgW, targetSize / imgH);
  const previewW = Math.round(imgW * scale);
  const previewH = Math.round(imgH * scale);

  const canvas = document.createElement("canvas");
  canvas.width = previewW;
  canvas.height = previewH;
  const ctx = canvas.getContext("2d");
  if (!ctx) return "";

  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";

  const fillCanvas = document.createElement("canvas");
  fillCanvas.width = imgW;
  fillCanvas.height = imgH;
  const fCtx = fillCanvas.getContext("2d");
  if (!fCtx) return "";

  const imgData = fCtx.createImageData(imgW, imgH);
  const d = imgData.data;

  for (let i = 0; i < imgW * imgH; i++) {
    const label = labelMask[i];
    const color = colorPalette[label];

    if (color) {
      d[i * 4] = color[0];
      d[i * 4 + 1] = color[1];
      d[i * 4 + 2] = color[2];
      d[i * 4 + 3] = 255;
    } else {
      d[i * 4] = 255;
      d[i * 4 + 1] = 255;
      d[i * 4 + 2] = 255;
      d[i * 4 + 3] = 255;
    }
  }

  fCtx.putImageData(imgData, 0, 0);
  ctx.drawImage(fillCanvas, 0, 0, imgW, imgH, 0, 0, previewW, previewH);

  return canvas.toDataURL("image/jpeg", 0.8);
}