// src/generator/components/ToolBar.tsx
import { useRef } from "react";
import { useAppStore } from "../store";
import { cn } from "../../utils/cn";

interface Props {
  onLoadImage: (file: File) => void;
  onCancel: () => void;
  onExport: () => void;
  hasResult: boolean;
}

export function Toolbar({ onLoadImage, onCancel, onExport, hasResult }: Props) {
  const fileRef = useRef<HTMLInputElement>(null);
  const isDark = useAppStore((s) => s.isDark);
  const isProcessing = useAppStore((s) => s.isProcessing);
  const hasOrig = useAppStore((s) => !!s.originalImageUrl);
  const historyCount = useAppStore((s) => s.generationHistory.length);
  const presetKey = useAppStore((s) => s.presetKey);
  const update = useAppStore((s) => s.update);

  const isArtistic = presetKey === "artistic";

  const drop = (e: React.DragEvent) => {
    e.preventDefault();
    const f = e.dataTransfer.files[0];
    if (f?.type.startsWith("image/")) onLoadImage(f);
  };

  const btnBase =
    "inline-flex items-center justify-center flex-shrink-0 gap-2 rounded-xl text-[13px] font-bold transition-all duration-200 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed whitespace-nowrap h-11 px-4";

  const btnNeutral = cn(
    btnBase,
    "border-2 transition-all duration-300 shadow-sm",
    isDark
      ? "bg-slate-800/40 border-slate-700/50 text-slate-300 hover:bg-slate-700 hover:border-slate-600 hover:text-white"
      : "bg-white/60 border-slate-100 text-slate-600 hover:bg-white hover:border-slate-200 hover:text-slate-900"
  );

  const iconBtn = cn(
    "inline-flex items-center justify-center flex-shrink-0 w-11 h-11 rounded-xl transition-all duration-300 border-2 active:scale-90 shadow-sm",
    isDark
      ? "bg-slate-800/40 border-slate-700/50 text-slate-400 hover:bg-slate-700 hover:border-slate-600 hover:text-white"
      : "bg-white/60 border-slate-100 text-slate-500 hover:bg-white hover:border-slate-200 hover:text-slate-900"
  );

  return (
    <header
      className={cn(
        "flex-shrink-0 flex items-center justify-between gap-1 sm:gap-3 px-3 sm:px-5 h-16 relative z-30 overflow-x-auto scrollbar-none shadow-premium border-b",
        isDark ? "bg-slate-900/80 backdrop-blur-xl border-slate-800" : "bg-white/70 backdrop-blur-xl border-slate-100"
      )}
      onDrop={drop}
      onDragOver={(e) => e.preventDefault()}
      role="toolbar"
      aria-label="Панель инструментов"
    >
      <input
        ref={fileRef}
        type="file"
        accept="image/jpeg,image/png,image/webp"
        className="hidden"
        aria-hidden="true"
        onChange={(e) => {
          const f = e.target.files?.[0];
          if (f) onLoadImage(f);
          e.target.value = "";
        }}
      />

      {/* ЛЕВАЯ ГРУППА */}
      <div className="flex items-center gap-1.5 sm:gap-3">
        <div className="flex items-center gap-2.5 pr-2 sm:pr-3 border-r border-slate-200/50 dark:border-slate-800/50 mr-1 sm:mr-2">
          <div className="w-9 h-9 rounded-xl bg-indigo-600 flex items-center justify-center shadow-lg shadow-indigo-500/30 shrink-0 relative overflow-hidden group">
             <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-white/20 opacity-0 group-hover:opacity-100 transition-opacity" />
             <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 19l7-7 3 3-7 7-3-3z" />
                <path d="m18 13-1.5-7.5L2 2l3.5 14.5L13 18l5-5z" />
             </svg>
          </div>
          <div className="hidden lg:block">
            <div className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tighter leading-none mt-0.5">Melura</div>
          </div>
        </div>

        <button
          className={cn(btnNeutral, "px-3 sm:px-5 group")}
          onClick={() => fileRef.current?.click()}
          aria-label="Загрузить изображение"
          title="Загрузить с устройства"
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" aria-hidden="true" className="flex-shrink-0 text-indigo-500 transition-transform">
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M17 8l-5-5-5 5M12 3v12" />
          </svg>
          <span className="hidden sm:inline">Файл</span>
        </button>

        <button
          className={cn(btnNeutral, "px-3 sm:px-4")}
          onClick={() => update({ urlModalOpen: true })}
          aria-label="Загрузить по URL"
          title="Загрузить по ссылке"
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" aria-hidden="true" className="flex-shrink-0 text-slate-400 dark:text-slate-500">
            <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
            <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
          </svg>
          <span className="hidden md:inline">URL</span>
        </button>

        {hasOrig && (
          <button
            className={cn(btnNeutral, "px-3 sm:px-4")}
            onClick={() => update({ cropModalOpen: true })}
            aria-label="Обрезать изображение"
            title="Кадрировать"
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" className="flex-shrink-0 text-slate-400 dark:text-slate-500">
              <path d="M6.13 1L6 16a2 2 0 0 0 2 2h15" />
              <path d="M1 6.13L16 6a2 2 0 0 1 2 2v15" />
            </svg>
            <span className="hidden md:inline">Обрезка</span>
          </button>
        )}
      </div>

      {/* ЦЕНТР (скрыт) */}
      <div className="flex-1 min-w-[5px]" />

      {/* ПРАВАЯ ГРУППА */}
      <div className="flex items-center gap-1.5 sm:gap-2.5 justify-end shrink-0 after:content-[''] after:w-1 after:shrink-0 sm:after:hidden">
        {isProcessing && (
          <button
            className={cn(btnBase, "bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-500/25 px-4 sm:px-6 animate-pulse border-none")}
            onClick={onCancel}
            aria-label="Остановить генерацию"
            title="Остановить расчет"
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" aria-hidden="true" className="flex-shrink-0">
              <line x1="18" y1="6" x2="6" y2="18" />
              <line x1="6" y1="6" x2="18" y2="18" />
            </svg>
            <span className="hidden sm:inline">Отмена</span>
          </button>
        )}

        {historyCount > 0 && !isProcessing && (
          <button
            className={iconBtn}
            onClick={() => update({ historyModalOpen: true })}
            aria-label="История генераций"
            title="История генераций"
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" className="flex-shrink-0">
              <path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" />
              <path d="M3 3v5h5" />
              <path d="M12 7v5l4 2" />
            </svg>
          </button>
        )}

        {hasResult && !isProcessing && (
          <button
            className={cn(btnBase, "bg-indigo-600 text-white hover:bg-indigo-500 shadow-lg shadow-indigo-600/30 border-none px-4 sm:px-6 group")}
            onClick={onExport}
            aria-label="Экспорт"
            title="Сохранить результат"
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" className="flex-shrink-0 group-hover:translate-y-0.5 transition-transform">
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" />
            </svg>
            <span className="hidden sm:inline">Экспорт</span>
          </button>
        )}

        {(hasOrig || hasResult) && (
          <button
            className={cn("lg:hidden", iconBtn)}
            onClick={() => update({ mobileSettingsOpen: true })}
            aria-label="Настройки панели"
            title="Настройки"
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" className="flex-shrink-0">
              <line x1="4" x2="20" y1="12" y2="12" />
              <line x1="4" x2="20" y1="6" y2="6" />
              <line x1="4" x2="20" y1="18" y2="18" />
            </svg>
          </button>
        )}
      </div>
    </header>
  );
}