import type { ArtisticModeState, PbnModeState, AppState } from "./types";

export function getModeState(mode: "artistic" | "pbn", artisticState: ArtisticModeState, pbnState: PbnModeState) {
  return mode === "artistic" ? artisticState : pbnState;
}

export function buildFlatState(mode: "artistic" | "pbn", artisticState: ArtisticModeState, pbnState: PbnModeState) {
  const current = getModeState(mode, artisticState, pbnState);
  return {
    numColors: current.numColors,
    detail: current.detail,
    activeColors: new Set(current.activeColors),
    contourWeight: current.contourWeight,
    showContours: current.showContours,
    numberWeight: current.numberWeight,
    showNumbers: current.showNumbers,
    artisticStep: artisticState.artisticStep,
    artisticPresetId: artisticState.artisticPresetId,
    notanLevels: artisticState.notanLevels,
    notanThreshold: artisticState.notanThreshold,
    selectedZoneId: current.selectedZoneId,
    zoneInfoVisible: current.zoneInfoVisible,
    customArtPalette: [...artisticState.customArtPalette],
    zoneGuideActive: current.zoneGuideActive,
    currentZoneIndex: current.currentZoneIndex,
    gridType: current.gridType,
    gridSize: current.gridSize,
    flipHorizontal: current.flipHorizontal,
    showTemperatureMap: current.showTemperatureMap,
    artIntensity: artisticState.artIntensity,
    detailsPhotoOpacity: artisticState.detailsPhotoOpacity,
    prevArtisticStep: artisticState.prevArtisticStep,
    stepTransitioning: artisticState.stepTransitioning,
    artisticSplitMode: current.artisticSplitMode,
    artisticNumColors: artisticState.numColors,
    artisticDetail: artisticState.detail,
    artisticContourWeight: artisticState.contourWeight,
    pbnContourWeight: pbnState.contourWeight,
    viewTransform: { ...current.viewTransform },
  };
}

export function syncCurrentFlatIntoModes(state: AppState): { artisticState: ArtisticModeState; pbnState: PbnModeState } {
  const artisticState: ArtisticModeState = {
    ...state.artisticState,
    numColors: state.activeMode === "artistic" ? state.numColors : state.artisticState.numColors,
    detail: state.activeMode === "artistic" ? state.detail : state.artisticState.detail,
    activeColors: state.activeMode === "artistic" ? new Set(state.activeColors) : new Set(state.artisticState.activeColors),
    artisticStep: state.artisticStep,
    artisticPresetId: state.artisticPresetId,
    notanLevels: state.notanLevels,
    notanThreshold: state.notanThreshold,
    selectedZoneId: state.activeMode === "artistic" ? state.selectedZoneId : state.artisticState.selectedZoneId,
    zoneInfoVisible: state.activeMode === "artistic" ? state.zoneInfoVisible : state.artisticState.zoneInfoVisible,
    customArtPalette: [...state.customArtPalette],
    zoneGuideActive: state.activeMode === "artistic" ? state.zoneGuideActive : state.artisticState.zoneGuideActive,
    currentZoneIndex: state.activeMode === "artistic" ? state.currentZoneIndex : state.artisticState.currentZoneIndex,
    gridType: state.activeMode === "artistic" ? state.gridType : state.artisticState.gridType,
    gridSize: state.activeMode === "artistic" ? state.gridSize : state.artisticState.gridSize,
    flipHorizontal: state.activeMode === "artistic" ? state.flipHorizontal : state.artisticState.flipHorizontal,
    showTemperatureMap: state.activeMode === "artistic" ? state.showTemperatureMap : state.artisticState.showTemperatureMap,
    artIntensity: state.artIntensity,
    detailsPhotoOpacity: state.detailsPhotoOpacity,
    prevArtisticStep: state.prevArtisticStep,
    stepTransitioning: state.stepTransitioning,
    artisticSplitMode: state.activeMode === "artistic" ? state.artisticSplitMode : state.artisticState.artisticSplitMode,
    contourWeight: state.activeMode === "artistic" ? state.contourWeight : state.artisticState.contourWeight,
    showContours: state.activeMode === "artistic" ? state.showContours : state.artisticState.showContours,
    showNumbers: state.activeMode === "artistic" ? state.showNumbers : state.artisticState.showNumbers,
    numberWeight: state.activeMode === "artistic" ? state.numberWeight : state.artisticState.numberWeight,
    viewTransform: state.activeMode === "artistic" ? { ...state.viewTransform } : { ...state.artisticState.viewTransform },
  };

  const pbnState: PbnModeState = {
    ...state.pbnState,
    numColors: state.activeMode === "pbn" ? state.numColors : state.pbnState.numColors,
    detail: state.activeMode === "pbn" ? state.detail : state.pbnState.detail,
    activeColors: state.activeMode === "pbn" ? new Set(state.activeColors) : new Set(state.pbnState.activeColors),
    contourWeight: state.activeMode === "pbn" ? state.contourWeight : state.pbnState.contourWeight,
    showContours: state.activeMode === "pbn" ? state.showContours : state.pbnState.showContours,
    numberWeight: state.activeMode === "pbn" ? state.numberWeight : state.pbnState.numberWeight,
    showNumbers: state.activeMode === "pbn" ? state.showNumbers : state.pbnState.showNumbers,
    selectedZoneId: state.activeMode === "pbn" ? state.selectedZoneId : state.pbnState.selectedZoneId,
    zoneInfoVisible: state.activeMode === "pbn" ? state.zoneInfoVisible : state.pbnState.zoneInfoVisible,
    zoneGuideActive: state.activeMode === "pbn" ? state.zoneGuideActive : state.pbnState.zoneGuideActive,
    currentZoneIndex: state.activeMode === "pbn" ? state.currentZoneIndex : state.pbnState.currentZoneIndex,
    gridType: state.activeMode === "pbn" ? state.gridType : state.pbnState.gridType,
    gridSize: state.activeMode === "pbn" ? state.gridSize : state.pbnState.gridSize,
    flipHorizontal: state.activeMode === "pbn" ? state.flipHorizontal : state.pbnState.flipHorizontal,
    showTemperatureMap: state.activeMode === "pbn" ? state.showTemperatureMap : state.pbnState.showTemperatureMap,
    artisticSplitMode: state.activeMode === "pbn" ? state.artisticSplitMode : state.pbnState.artisticSplitMode,
    viewTransform: state.activeMode === "pbn" ? { ...state.viewTransform } : { ...state.pbnState.viewTransform },
  };

  return { artisticState, pbnState };
}