// src/generator/utils/pdfExport.ts
import { renderSchemeCanvas, type ProcessingResult } from "./imageProcessing";
import { calculateDrops, type RecipeVariant, type RGB } from "../../engine";
import {
  PAINT_PROFILES,
  BASE_COLORS,
  formatParts,
  type PaintType,
  type SurfaceType,
  type ColorComponent,
  type EngineSettings,
} from "../../config";
import type { ArtisticPresetId } from "../../config";

export interface PdfExportParams {
  res: ProcessingResult;
  originalImageUrl: string | null;
  paperSize: "a4" | "a3" | "a2";
  dpi: number;
  tileMode: boolean;
  includeRecipes: boolean;
  activeComps: ColorComponent[];
  exportPaintType: PaintType;
  exportSurfaceType: SurfaceType;
  isArtistic: boolean;
  contourWeight: number;
  numberWeight: number;
  artisticPresetId?: ArtisticPresetId;
  notanLevels: number;
  notanThreshold: number;
  artIntensity: number;
  customArtPalette?: RGB[];
  detailsPhotoOpacity: number;
  totalPartsLimit: number | null;
  engineSettings: EngineSettings;
  updateProgress: (msg: string, pct: number) => void;
}

export async function generatePdf(params: PdfExportParams): Promise<void> {
  const {
    res, originalImageUrl, paperSize, dpi, tileMode, includeRecipes, activeComps,
    exportPaintType, exportSurfaceType, isArtistic, contourWeight, numberWeight,
    artisticPresetId, notanLevels, notanThreshold, artIntensity, customArtPalette,
    detailsPhotoOpacity, totalPartsLimit, engineSettings, updateProgress
  } = params;

  const { jsPDF } = await import("jspdf");

  const orient = res.imgW > res.imgH ? "l" : "p";
  const pdf = new jsPDF({ orientation: orient, unit: "mm", format: paperSize });
  
  const pw = pdf.internal.pageSize.getWidth();
  const ph = pdf.internal.pageSize.getHeight();
  
  // High-resolution canvas for rendering (approx 300 DPI for A4)
  const renderW = orient === "p" ? 2480 : 3508;
  const renderH = orient === "p" ? 3508 : 2480;

  const addCanvasPage = (drawFn: (ctx: CanvasRenderingContext2D, w: number, h: number) => void, isCover = false) => {
    const c = document.createElement("canvas");
    c.width = renderW;
    c.height = renderH;
    const ctx = c.getContext("2d")!;
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, renderW, renderH);
    
    // Smooth rendering
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = "high";
    
    drawFn(ctx, renderW, renderH);
    
    // Premium Footer
    if (!isCover && pdf.internal.pages.length > 0) {
      const footerY = renderH - 100;
      ctx.strokeStyle = "#f1f5f9";
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.moveTo(150, footerY - 40); ctx.lineTo(renderW - 150, footerY - 40); ctx.stroke();
      
      ctx.fillStyle = "#94a3b8";
      ctx.font = "bold 28px sans-serif";
      ctx.textAlign = "left";
      ctx.letterSpacing = "2px";
      ctx.fillText("MELURA", 150, footerY);
      
      ctx.textAlign = "right";
      ctx.font = "32px monospace";
      // Fixed numbering: Current total pages - 1 (excluding cover)
      const pageNum = (pdf as any).internal.getNumberOfPages();
      ctx.fillText(String(pageNum).padStart(2, '0'), renderW - 150, footerY);
      ctx.letterSpacing = "0px";
    }

    pdf.addImage(c.toDataURL("image/jpeg", 0.95), "JPEG", 0, 0, pw, ph);
    c.width = 0;
    c.height = 0;
  };

  const drawHeader = (ctx: CanvasRenderingContext2D, title: string, subtitle: string, w: number) => {
    const headerY = 160;
    ctx.fillStyle = "#0f172a";
    ctx.font = "bold 100px sans-serif";
    ctx.textAlign = "left";
    ctx.letterSpacing = "-2px";
    ctx.fillText(title, 150, headerY);
    
    ctx.fillStyle = "#6366f1";
    ctx.font = "bold 36px sans-serif";
    ctx.letterSpacing = "4px";
    ctx.fillText(subtitle.toUpperCase(), 155, headerY + 60);
    ctx.letterSpacing = "0px";
    
    ctx.strokeStyle = "#e2e8f0";
    ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(150, headerY + 110); ctx.lineTo(w - 150, headerY + 110); ctx.stroke();
  };

  const drawDecorativeBorder = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.strokeStyle = "#e2e8f0";
    ctx.lineWidth = 2;
    // Main frame
    ctx.strokeRect(80, 80, w - 160, h - 160);
    
    // Decorative corners
    ctx.strokeStyle = "#cbd5e1";
    ctx.lineWidth = 12;
    const len = 150;
    const gap = 60;
    
    // Top-Left
    ctx.beginPath(); ctx.moveTo(gap, gap + len); ctx.lineTo(gap, gap); ctx.lineTo(gap + len, gap); ctx.stroke();
    // Top-Right
    ctx.beginPath(); ctx.moveTo(w - gap - len, gap); ctx.lineTo(w - gap, gap); ctx.lineTo(w - gap, gap + len); ctx.stroke();
    // Bottom-Left
    ctx.beginPath(); ctx.moveTo(gap, h - gap - len); ctx.lineTo(gap, h - gap); ctx.lineTo(gap + len, h - gap); ctx.stroke();
    // Bottom-Right
    ctx.beginPath(); ctx.moveTo(w - gap - len, h - gap); ctx.lineTo(w - gap, h - gap); ctx.lineTo(w - gap, h - gap - len); ctx.stroke();
  };

  if (isArtistic) {
    const stepNames = ["Эскиз и композиция", "Светотеневой разбор", "Цветовая база", "Экспрессия и колорит", "Финальные акценты"];
    updateProgress("Создание обложки...", 10);
    
    addCanvasPage((ctx, w, h) => {
      drawDecorativeBorder(ctx, w, h);

      // Logo Treatment
      ctx.fillStyle = "#0f172a";
      ctx.font = "bold 180px sans-serif";
      ctx.textAlign = "center";
      ctx.letterSpacing = "12px";
      ctx.fillText("MELURA", w / 2, h * 0.15);
      
      ctx.fillStyle = "#6366f1";
      ctx.font = "bold 44px sans-serif";
      ctx.letterSpacing = "8px";
      ctx.fillText("ART-PRACTICUM", w / 2, h * 0.185);
      ctx.letterSpacing = "0px";

      const availH = h * 0.55;
      const availW = w * 0.75;
      let pW = availW;
      let pH = pW * (res.imgH / res.imgW);
      if (pH > availH) { pH = availH; pW = pH * (res.imgW / res.imgH); }

      const pX = (w - pW) / 2;
      const pY = h * 0.23 + (availH - pH) / 2;

      // Multi-layered Shadow Effect - isolated with save/restore
      ctx.save();
      ctx.shadowColor = "rgba(15, 23, 42, 0.1)";
      ctx.shadowBlur = 120;
      ctx.shadowOffsetY = 60;
      
      const tmp = document.createElement("canvas");
      tmp.width = res.imgW;
      tmp.height = res.imgH;
      tmp.getContext("2d")!.putImageData(res.previewImageData, 0, 0);
      
      ctx.drawImage(tmp, pX, pY, pW, pH);
      ctx.restore();

      // Bottom Info
      ctx.fillStyle = "#334155";
      ctx.font = "italic 60px serif";
      ctx.fillText("Индивидуальная стратегия живописи", w / 2, pY + pH + 140);
      
      ctx.fillStyle = "#94a3b8";
      ctx.font = "bold 32px sans-serif";
      ctx.letterSpacing = "2px";
      ctx.fillText("VERSION 2.0 • PROFESSIONAL EDITION", w / 2, h - 160);
    }, true);

    const margin = 12;
    const availW = pw - margin * 2;
    const availH = ph - margin * 3;
    let fitW = availW;
    let fitH = availW / (res.imgW / res.imgH);
    if (fitH > availH) { fitH = availH; fitW = availH * (res.imgW / res.imgH); }
    const pxPerMm = dpi / 25.4;
    const scale = (Math.round(fitW * pxPerMm)) / res.imgW;

    let origImg: HTMLImageElement | null = null;
    if (originalImageUrl) {
      origImg = new Image();
      origImg.crossOrigin = "anonymous";
      origImg.src = originalImageUrl;
      await new Promise((resolve, reject) => {
        origImg!.onload = resolve; origImg!.onerror = reject;
      });
    }

    for (let step = 0; step < 5; step++) {
      updateProgress(`Генерация шага ${step + 1} из 5...`, 20 + step * 15);
      pdf.addPage();
      const rc = document.createElement("canvas");
      rc.width = res.imgW * scale;
      rc.height = res.imgH * scale;

      renderSchemeCanvas(
        rc, res, contourWeight, numberWeight, new Set(), false, scale, true, step,
        artisticPresetId, notanLevels, notanThreshold, artIntensity,
        customArtPalette && customArtPalette.length >= 2 ? customArtPalette : undefined,
        false, false, -1, detailsPhotoOpacity, true
      );

      addCanvasPage((ctx, w, h) => {
        drawHeader(ctx, `ШАГ 0${step + 1}`, stepNames[step], w);

        const imgAreaY = 320;
        const imgAreaH = h - imgAreaY - 200;
        const imgAreaW = w - 300;
        
        let dW = imgAreaW;
        let dH = dW * (rc.height / rc.width);
        if (dH > imgAreaH) { dH = imgAreaH; dW = dH * (rc.width / rc.height); }

        const dX = 150 + (imgAreaW - dW) / 2;
        const dY = imgAreaY + (imgAreaH - dH) / 2;

        if (step === 4 && origImg) {
          ctx.globalAlpha = 0.3;
          ctx.drawImage(origImg, dX, dY, dW, dH);
          ctx.globalAlpha = 1.0;
        }

        ctx.shadowColor = "rgba(0,0,0,0.1)";
        ctx.shadowBlur = 40;
        ctx.drawImage(rc, dX, dY, dW, dH);
        ctx.shadowBlur = 0;
        
        ctx.strokeStyle = "#e2e8f0";
        ctx.lineWidth = 2;
        ctx.strokeRect(dX, dY, dW, dH);
      });
    }
  } else {
    // Режим "По номерам"
    const sl = [...res.validLabels].sort((a, b) => a - b);
    const recipes: { id: number; variant: RecipeVariant }[] = [];

    if (includeRecipes) {
      const displayComps = activeComps.length > 0 ? activeComps : BASE_COLORS.slice(0, 12);
      
      for (let i = 0; i < sl.length; i++) {
        updateProgress(`Расчёт рецептов... ${i + 1} из ${sl.length}`, Math.round((i / sl.length) * 30));
        await new Promise((r) => setTimeout(r, 10));

        const target = res.colorPalette[sl[i]];
        const calc = await calculateDrops(
          target, displayComps,
          { ...engineSettings, paintType: exportPaintType, surfaceType: exportSurfaceType, targetTotalParts: totalPartsLimit },
          () => {}
        );

        const best = calc.variants.find((v) => v.deltaE < 3.5) || calc.variants[0];
        recipes.push({ id: sl[i], variant: best });
      }
    }

    updateProgress("Создание обложки...", 35);
    addCanvasPage((ctx, w, h) => {
      drawDecorativeBorder(ctx, w, h);
      ctx.fillStyle = "#0f172a";
      ctx.font = "bold 200px sans-serif";
      ctx.textAlign = "center";
      ctx.letterSpacing = "16px";
      ctx.fillText("MELURA", w / 2, h * 0.16);
      ctx.fillStyle = "#6366f1";
      ctx.font = "bold 44px sans-serif";
      ctx.letterSpacing = "6px";
      ctx.fillText("PREMIUM PAINT-BY-NUMBERS", w / 2, h * 0.195);
      ctx.letterSpacing = "0px";

      const availH = h * 0.5;
      const availW = w * 0.8;
      let pW = availW;
      let pH = pW * (res.imgH / res.imgW);
      if (pH > availH) { pH = availH; pW = pH * (res.imgW / res.imgH); }
      const pX = (w - pW) / 2;
      const pY = h * 0.26 + (availH - pH) / 2;

      const tmp = document.createElement("canvas");
      tmp.width = res.imgW; tmp.height = res.imgH;
      tmp.getContext("2d")!.putImageData(res.previewImageData, 0, 0);

      ctx.save();
      ctx.shadowColor = "rgba(15, 23, 42, 0.15)";
      ctx.shadowBlur = 120;
      ctx.shadowOffsetY = 60;
      ctx.drawImage(tmp, pX, pY, pW, pH);
      ctx.restore();

      // Russian pluralization logic for "оттенок"
      const n = sl.length;
      const n10 = n % 10;
      const n100 = n % 100;
      let label = "";
      if (n10 === 1 && n100 !== 11) {
        label = `${n} ИСКЛЮЧИТЕЛЬНЫЙ ОТТЕНОК`;
      } else if (n10 >= 2 && n10 <= 4 && (n100 < 10 || n100 >= 20)) {
        label = `${n} ИСКЛЮЧИТЕЛЬНЫХ ОТТЕНКА`;
      } else {
        label = `${n} ИСКЛЮЧИТЕЛЬНЫХ ОТТЕНКОВ`;
      }

      ctx.fillStyle = "#0f172a";
      ctx.font = "bold 70px sans-serif";
      ctx.fillText(label, w / 2, pY + pH + 180);
      
      ctx.fillStyle = "#64748b";
      ctx.font = "36px sans-serif";
      ctx.fillText(`ПРОФИЛЬ: ${PAINT_PROFILES[exportPaintType].name.toUpperCase()} / ${exportSurfaceType.toUpperCase()}`, w / 2, h - 140);
    }, true);

    // Palette Overview Page
    updateProgress("Генерация обзора палитры...", 45);
    pdf.addPage();
    addCanvasPage((ctx, w, h) => {
      drawHeader(ctx, "ПАЛИТРА", "Обзор выбранных оттенков", w);
      
      const startY = 320;
      const itemsPerRow = orient === "p" ? 6 : 8;
      const gap = 40;
      const size = (w - 300 - (itemsPerRow - 1) * gap) / itemsPerRow;
      
      sl.forEach((id, i) => {
        const r = Math.floor(i / itemsPerRow);
        const c = i % itemsPerRow;
        const cx = 150 + c * (size + gap);
        const cy = startY + r * (size + gap + 80);
        
        const col = res.colorPalette[id];
        ctx.fillStyle = `rgb(${col[0]},${col[1]},${col[2]})`;
        ctx.beginPath();
        ctx.roundRect(cx, cy, size, size, 24);
        ctx.fill();
        ctx.strokeStyle = "rgba(0,0,0,0.05)";
        ctx.lineWidth = 2;
        ctx.stroke();
        
        ctx.fillStyle = "#475569";
        ctx.font = "bold 36px monospace";
        ctx.textAlign = "center";
        ctx.fillText(String(id + 1).padStart(2, '0'), cx + size / 2, cy + size + 45);
      });
    });

    updateProgress("Отрисовка схемы...", 60);
    await new Promise((r) => setTimeout(r, 50));

    const margin = 10;
    const availW = pw - margin * 2;
    const availH = ph - margin * 2;
    let fitW = availW;
    let fitH = availW / (res.imgW / res.imgH);

    if (fitH > availH) {
      fitH = availH;
      fitW = availH * (res.imgW / res.imgH);
    }

    const tilesX = tileMode ? 2 : 1;
    const tilesY = tileMode ? 2 : 1;
    const totalPhysicalW = fitW * tilesX;
    
    const pxPerMm = dpi / 25.4;
    const canvasW = Math.round(totalPhysicalW * pxPerMm);
    const scale = canvasW / res.imgW;

    // При экспорте в PDF увеличиваем базовую толщину, так как на печати линии выглядят тоньше
    const pdfContourWeight = contourWeight * 1.2; 
    const pdfNumberWeight = numberWeight * 1.1;

    const rc = document.createElement("canvas");
    renderSchemeCanvas(
      rc, res, pdfContourWeight, pdfNumberWeight, new Set(), true, scale, false, 0, undefined, 2, 128, 100, undefined, false, false, -1, 60, true
    );

    if (!tileMode) {
      pdf.addPage();
      pdf.addImage(rc.toDataURL("image/jpeg", 0.9), "JPEG", (pw - fitW) / 2, (ph - fitH) / 2, fitW, fitH);
    } else {
      const tc = document.createElement("canvas");
      const tw = Math.floor(rc.width / tilesX);
      const th = Math.floor(rc.height / tilesY);
      tc.width = tw;
      tc.height = th;
      const tCtx = tc.getContext("2d")!;

      for (let y = 0; y < tilesY; y++) {
        for (let x = 0; x < tilesX; x++) {
          pdf.addPage();
          tCtx.fillStyle = "#fff";
          tCtx.fillRect(0, 0, tw, th);
          tCtx.drawImage(rc, x * tw, y * th, tw, th, 0, 0, tw, th);
          pdf.addImage(tc.toDataURL("image/jpeg", 0.9), "JPEG", (pw - fitW) / 2, (ph - fitH) / 2, fitW, fitH);
        }
      }
    }

    if (includeRecipes && recipes.length > 0) {
      updateProgress("Верстка книги рецептов...", 85);
      let recIdx = 0;
      let pageNum = 1;
      const paintProfile = PAINT_PROFILES[exportPaintType];

      while (recIdx < recipes.length) {
        pdf.addPage();
        addCanvasPage((ctx, w, h) => {
          drawHeader(ctx, "РЕЦЕПТЫ", pageNum === 1 ? "Инструкции по смешиванию" : `Инструкции (Часть ${pageNum})`, w);
          
          // Material Info Card (Premium detail)
          if (pageNum === 1) {
            ctx.fillStyle = "#f8fafc";
            ctx.beginPath(); ctx.roundRect(w - 750, 145, 600, 110, 16); ctx.fill();
            ctx.fillStyle = "#6366f1";
            ctx.font = "bold 24px sans-serif";
            ctx.textAlign = "right";
            ctx.fillText(paintProfile.name.toUpperCase(), w - 180, 190);
            ctx.fillStyle = "#94a3b8";
            ctx.font = "20px sans-serif";
            ctx.fillText(paintProfile.drying.description, w - 180, 225);
          }

          let cy = 340;
          const cols = orient === "p" ? 2 : 3;
          const cardW = Math.floor((w - 300 - (cols - 1) * 80) / cols);
          const cardH = 500;
          let cx = 150;
          let colCount = 0;

          while (recIdx < recipes.length && cy < h - cardH - 120) {
            const { id, variant } = recipes[recIdx];
            const col = res.colorPalette[id];

            ctx.save();
            ctx.translate(cx, cy);
            
            // Card Base with soft elevation
            ctx.fillStyle = "#ffffff";
            ctx.shadowColor = "rgba(0,0,0,0.03)";
            ctx.shadowBlur = 20;
            ctx.beginPath(); ctx.roundRect(0, 0, cardW, cardH, 24); ctx.fill();
            ctx.strokeStyle = "#f1f5f9";
            ctx.lineWidth = 2;
            ctx.stroke();
            ctx.restore();

            // Color Swatch Strip
            ctx.fillStyle = `rgb(${col[0]},${col[1]},${col[2]})`;
            ctx.beginPath(); ctx.roundRect(cx + 20, cy + 20, 120, cardH - 40, 16); ctx.fill();
            
            // ID Label
            ctx.fillStyle = "#0f172a";
            ctx.font = "bold 64px monospace";
            ctx.textAlign = "left";
            ctx.fillText(String(id + 1).padStart(2, '0'), cx + 170, cy + 85);
            
            ctx.strokeStyle = "#f1f5f9";
            ctx.lineWidth = 2;
            ctx.beginPath(); ctx.moveTo(cx + 170, cy + 115); ctx.lineTo(cx + cardW - 40, cy + 115); ctx.stroke();

            let ry = cy + 185;
            for (const item of variant.recipe) {
              // Ingredient Swatch
              ctx.fillStyle = `rgb(${item.rgb[0]},${item.rgb[1]},${item.rgb[2]})`;
              ctx.beginPath(); ctx.arc(cx + 195, ry - 16, 24, 0, Math.PI * 2); ctx.fill();
              
              ctx.fillStyle = "#334155";
              ctx.font = "bold 40px sans-serif";
              ctx.textAlign = "left";
              let name = item.name; if(name.length > 16) name = name.substring(0, 14) + "...";
              ctx.fillText(name, cx + 235, ry);

              ctx.fillStyle = "#6366f1";
              ctx.font = "bold 44px monospace";
              ctx.textAlign = "right";
              ctx.fillText(formatParts(item.parts, paintProfile), cx + cardW - 40, ry);
              ry += 70;
            }
            
            // Accuracy Indicator (DeltaE converted to %)
            if (variant.deltaE > 0.1) {
              const accuracy = Math.max(0, 100 - variant.deltaE * 2).toFixed(1);
              ctx.fillStyle = "#cbd5e1";
              ctx.font = "bold 24px monospace";
              ctx.textAlign = "right";
              ctx.fillText(`ACCURACY: ${accuracy}%`, cx + cardW - 40, cy + cardH - 35);
            }

            cx += cardW + 80;
            colCount++;
            if (colCount % cols === 0) { cx = 150; cy += cardH + 80; }
            recIdx++;
          }
        });
        pageNum++;
      }
    }
  }

  updateProgress("Сохранение PDF...", 98);
  pdf.save(`melura_${isArtistic ? "art" : "pbn"}_${Date.now()}.pdf`);
}