import React from 'react';
import { formatParts, type PaintProfile } from '../config';
import type { RecipeVariant } from '../engine';
import { cn } from '../utils/cn';
import { getAccuracyInfo } from '../utils/formatting';
import { StarsRating } from './ui/StarsRating';

function VariantCard({ variant, isActive, onClick, profile }: {
  variant: RecipeVariant; 
  isActive: boolean; 
  onClick: () => void; 
  profile: PaintProfile;
}) {
  const isExcellent = variant.deltaE <= 2.0;
  
  let score: number;
  if (variant.deltaE < 1) score = 100;
  else if (variant.deltaE < 2) score = 98;
  else if (variant.deltaE < 3.5) score = 92;
  else if (variant.deltaE < 6) score = 85;
  else score = Math.max(10, Math.round(100 - variant.deltaE * 4));

  return (
    <button 
      onClick={onClick} 
      className={cn(
        "relative flex items-center gap-3 p-2 rounded-2xl border-2 transition-all duration-300 w-full text-left active:scale-[0.98] overflow-hidden",
        isActive 
          ? "border-indigo-600 bg-white dark:bg-slate-900 shadow-sm z-10" 
          : "border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/30"
      )}
    >
      <div 
        className="w-10 h-10 rounded-xl shadow-inner border border-black/5 dark:border-white/10 shrink-0 relative overflow-hidden"
        style={{ backgroundColor: `rgb(${variant.approxRgb})` }} 
      >
         <div className="absolute inset-0 bg-gradient-to-tr from-black/10 to-white/10" />
      </div>
      
      <div className="flex-1 min-w-0 flex items-center justify-between gap-2">
         <div className="min-w-0">
            <div className="flex items-center gap-2 mb-0.5">
               <span className={cn("text-sm font-black tabular-nums leading-none", isExcellent ? "text-emerald-500" : "text-indigo-600 dark:text-indigo-400")}>
                 {score}%
               </span>
               <span className="text-xs font-black font-mono text-slate-400 uppercase">
                 ΔE {variant.deltaE.toFixed(1)}
               </span>
            </div>
            <div className="flex gap-0.5 opacity-60">
               {variant.recipe.slice(0, 6).map((r, i) => (
                 <div key={i} className="w-1.5 h-1.5 rounded-full border border-black/5 shadow-inner" style={{ backgroundColor: `rgb(${r.rgb})` }} />
               ))}
            </div>
         </div>

         <div className="flex flex-col items-end gap-1 shrink-0">
            <div className="flex items-center gap-1.5">
               <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="text-slate-400"><path d="M12 22a7 7 0 0 0 7-7c0-2-1-3.9-3-5.5s-3.5-4-4-6.5c-.5 2.5-2 4.9-4 6.5C6 11.1 5 13 5 15a7 7 0 0 0 7 7z"/></svg>
               <span className="text-xs font-black text-slate-500 dark:text-slate-400 tabular-nums">{formatParts(variant.totalDrops, profile)}</span>
            </div>
            <div className="flex items-center gap-1.5">
               <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="text-slate-400"><circle cx="13.5" cy="6.5" r=".5" fill="currentColor"/><path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10c.926 0 1.648-.746 1.648-1.688 0-.437-.18-.835-.437-1.125-.29-.289-.438-.652-.438-1.125a1.64 1.64 0 0 1 1.668-1.668h1.996c3.051 0 5.555-2.503 5.555-5.554C21.965 6.012 17.461 2 12 2z"/></svg>
               <span className="text-xs font-black text-slate-500 dark:text-slate-400 tabular-nums">{variant.usedColors} цв.</span>
            </div>
         </div>
      </div>
    </button>
  );
}

export function VariantSelector({ variants, activeVariant, onSelect, profile }: {
  variants: RecipeVariant[]; 
  activeVariant: number; 
  onSelect: (i: number) => void;
  isMobile: boolean; 
  profile: PaintProfile;
}) {
  if (variants.length <= 1) return null;

  return (
    <div className="pt-1">
      <div className="grid grid-cols-1 gap-2">
        {variants.map((v, i) => (
          <VariantCard 
            key={`${v.deltaE}-${v.usedColors}-${v.totalDrops}-${i}`} 
            variant={v} 
            isActive={activeVariant === i} 
            onClick={() => onSelect(i)} 
            profile={profile} 
          />
        ))}
      </div>
    </div>
  );
}
