// src/generator/hooks/useGeneratorLogic.ts
import { useCallback, useEffect, useRef } from "react";
import { useAppStore } from "../store";
import { processImage, generateColorPreview, type ProcessingResult } from "../utils/imageProcessing";
import { applyCorrection } from "../utils/imageProcessing/imageCorrection";
import { profileImageQuick } from "../utils/imageProcessing/profiler";

const MAX_FILE_SIZE = 50 * 1024 * 1024;
const MAX_SIDE = 1600;
const ACCEPTED_TYPES = new Set(["image/jpeg", "image/png", "image/webp"]);

export function useGeneratorLogic(isOpen: boolean, isDark: boolean) {
  const update = useAppStore((s) => s.update);
  
  // Подписки на состояние для триггера авто-генерации
  const originalImageUrl = useAppStore((s) => s.originalImageUrl);
  const hasOriginal = !!originalImageUrl;
  const activeMode = useAppStore((s) => s.activeMode);
  const numColors = useAppStore((s) => s.numColors);
  const detail = useAppStore((s) => s.detail);
  const artisticState = useAppStore((s) => s.artisticState);
  const pbnState = useAppStore((s) => s.pbnState);
  const correction = useAppStore((s) => s.correction);
  const isInteracting = useAppStore((s) => s.isInteracting);

  const processingRef = useRef(false);
  const autoGenTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const lastProcessingSignatureRef = useRef<string>("");
  const resultCache = useRef<Map<string, ProcessingResult>>(new Map());

  useEffect(() => {
    resultCache.current.clear();
    lastProcessingSignatureRef.current = "";
  }, [originalImageUrl]);

  useEffect(() => {
    if (isOpen) useAppStore.getState().initHistory();
  }, [isOpen]);

  useEffect(() => {
    if (isOpen) update({ isDark });
  }, [isDark, isOpen, update]);

  const buildProcessingParams = useCallback(() => {
    const s = useAppStore.getState();
    if (s.activeMode === "artistic") {
      return {
        mode: "artistic",
        numColors: s.artisticState.numColors,
        detail: s.artisticState.detail,
        correction: s.correction,
      };
    }
    return {
      mode: "pbn",
      numColors: s.pbnState.numColors,
      detail: s.pbnState.detail,
      correction: s.correction,
    };
  }, []);

  const buildProcessingSignature = useCallback(() => {
    const s = useAppStore.getState();
    const srcUrl = s.originalImageUrl || "";
    const params = buildProcessingParams();
    return JSON.stringify({
      srcUrl,
      mode: params.mode,
      numColors: params.numColors,
      detail: params.detail,
      correction: params.correction,
    });
  }, [buildProcessingParams]);

  const buildProcessingCacheKey = useCallback(() => {
    const s = useAppStore.getState();
    const srcUrl = s.originalImageUrl || "no-image";
    const params = buildProcessingParams();
    return JSON.stringify({
      srcUrl,
      mode: params.mode,
      numColors: params.numColors,
      detail: params.detail,
      correction: params.correction,
    });
  }, [buildProcessingParams]);

  const startProcessing = useCallback(async () => {
    if (processingRef.current) return;

    const s = useAppStore.getState();
    const srcUrl = s.originalImageUrl;
    if (!srcUrl) return;

    const signature = buildProcessingSignature();
    if (signature === lastProcessingSignatureRef.current && s.result) {
      return;
    }

    const cacheKey = buildProcessingCacheKey();
    if (resultCache.current.has(cacheKey)) {
      const cachedResult = resultCache.current.get(cacheKey)!;
      lastProcessingSignatureRef.current = signature;
      update({
        result: cachedResult,
        isProcessing: false,
        progress: 100,
        statusMsg: `Готово (из кэша) — ${cachedResult.validLabels.size} цветов`,
        activeColors: new Set(cachedResult.validLabels),
        abortController: null,
      });
      return;
    }

    const prev = useAppStore.getState().abortController;
    if (prev) prev.abort();

    const ac = new AbortController();
    processingRef.current = true;
    update({
      isProcessing: true,
      progress: 0,
      statusMsg: "Анализ изображения...",
      activeColors: new Set(),
      abortController: ac,
    });

    try {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = srcUrl;

      await new Promise((resolve, reject) => {
        img.onload = resolve;
        img.onerror = reject;
      });

      const c = document.createElement("canvas");
      c.width = img.width;
      c.height = img.height;
      const ctx = c.getContext("2d")!;
      ctx.drawImage(img, 0, 0);

      let imgData = ctx.getImageData(0, 0, img.width, img.height);
      const params = buildProcessingParams();

      if (params.correction.brightness !== 0 || params.correction.contrast !== 0 || params.correction.saturation !== 0 || params.correction.sharpness !== 0) {
        imgData = applyCorrection(imgData, params.correction);
        ctx.putImageData(imgData, 0, 0); // Обновляем канвас для сохранения в историю
      }

      const newResult = await processImage(
        imgData,
        params.numColors,
        params.detail,
        (msg, pct) => {
          if (!ac.signal.aborted) {
            update({ statusMsg: msg, progress: pct ?? 0 });
          }
        },
        ac.signal
      );

      if (!ac.signal.aborted) {
        resultCache.current.set(cacheKey, newResult);
        lastProcessingSignatureRef.current = signature;

        update({
          result: newResult,
          isProcessing: false,
          progress: 100,
          statusMsg: `Готово — ${newResult.validLabels.size} цветов, ${newResult.contoursData.length} зон`,
          activeColors: new Set(newResult.validLabels),
          abortController: null,
        });

        try {
          const colorPreviewDataUrl = generateColorPreview(newResult);
          const originalImageStr = c.toDataURL("image/webp", 0.7);

          await useAppStore.getState().addToHistory({
            timestamp: Date.now(),
            presetKey: s.presetKey,
            numColors: params.numColors,
            detail: params.detail,
            result: newResult,
            colorPreviewDataUrl,
            originalImageStr,
          });
        } catch {}
      }
    } catch (e: unknown) {
      if ((e as Error).name !== "AbortError" && !ac.signal.aborted) {
        update({
          isProcessing: false,
          statusMsg: `Ошибка: ${(e as Error).message}`,
          abortController: null,
        });
      }
    } finally {
      processingRef.current = false;
    }
  }, [update, buildProcessingCacheKey, buildProcessingSignature, buildProcessingParams]);

  const cancelProcessing = useCallback(() => {
    const ac = useAppStore.getState().abortController;
    if (ac) {
      ac.abort();
      update({
        isProcessing: false,
        isExporting: false,
        abortController: null,
        statusMsg: "Отменено",
        progress: 0,
      });
      processingRef.current = false;
    }
  }, [update]);

  const loadImage = useCallback((file: File) => {
    if (!ACCEPTED_TYPES.has(file.type)) {
      update({ statusMsg: "Неподдерживаемый формат." });
      return;
    }
    if (file.size > MAX_FILE_SIZE) {
      update({ statusMsg: "Файл слишком большой." });
      return;
    }
    update({ statusMsg: "Подготовка изображения…" });

    const prepareImage = async () => {
      try {
        const bmp = await createImageBitmap(file);
        const scale = Math.min(1, MAX_SIDE / Math.max(bmp.width, bmp.height));
        const w = Math.round(bmp.width * scale);
        const h = Math.round(bmp.height * scale);

        const c = document.createElement("canvas");
        c.width = w;
        c.height = h;
        const ctx = c.getContext("2d")!;
        ctx.drawImage(bmp, 0, 0, w, h);
        bmp.close();

        const imageData = ctx.getImageData(0, 0, w, h);
        const profile = profileImageQuick(imageData.data, w, h);

        c.toBlob((blob) => {
          if (!blob) throw new Error("Не удалось конвертировать изображение");
          const url = URL.createObjectURL(blob);

          const s = useAppStore.getState();
          if (s.originalImageUrl && s.originalImageUrl.startsWith("blob:")) {
            URL.revokeObjectURL(s.originalImageUrl);
          }
          if (s.correctedImageUrl && s.correctedImageUrl.startsWith("blob:")) {
            URL.revokeObjectURL(s.correctedImageUrl);
          }

          resultCache.current.clear();
          lastProcessingSignatureRef.current = "";

          update({
            imageFile: file,
            originalImageUrl: url,
            imageDimensions: { w, h },
            imageProfile: profile,
            correctedImageUrl: null,
            result: null,
            activeColors: new Set(),
            statusMsg: `Загружено: ${w}×${h}`,
            mobilePaletteExpanded: false,
            zoneGuideActive: false,
            showTemperatureMap: false,
            artisticSplitMode: false,
            selectedZoneId: null,
            zoneInfoVisible: false,
            flipHorizontal: false,
            viewTransform: { x: 0, y: 0, z: 1, splitPos: 0.5 },
          });

          useAppStore.getState().resetCorrection();
          const currentKey = useAppStore.getState().presetKey;
          if (currentKey !== "custom") {
            setTimeout(() => useAppStore.getState().applyPreset(currentKey), 0);
          }
        }, "image/webp", 0.9);
      } catch (err) {
        update({ statusMsg: `Ошибка: ${(err as Error).message}` });
      }
    };
    prepareImage();
  }, [update]);

  useEffect(() => {
    if (!isOpen || !hasOriginal || isInteracting) return;

    const nextSignature = buildProcessingSignature();
    if (nextSignature === lastProcessingSignatureRef.current) return;

    if (autoGenTimerRef.current) clearTimeout(autoGenTimerRef.current);

    const hasExistingResult = !!useAppStore.getState().result;
    const delay = hasExistingResult ? 700 : 120;

    autoGenTimerRef.current = setTimeout(() => {
      const latestSignature = buildProcessingSignature();
      if (latestSignature !== lastProcessingSignatureRef.current) {
        startProcessing();
      }
    }, delay);

    return () => {
      if (autoGenTimerRef.current) clearTimeout(autoGenTimerRef.current);
    };
  }, [
    isOpen, hasOriginal, originalImageUrl, activeMode, correction, isInteracting,
    numColors, detail, artisticState.numColors, artisticState.detail,
    pbnState.numColors, pbnState.detail, buildProcessingSignature, startProcessing
  ]);

  useEffect(() => {
    const h = (e: KeyboardEvent) => {
      if (!isOpen) return;
      if (
        e.target instanceof HTMLInputElement ||
        e.target instanceof HTMLTextAreaElement ||
        e.target instanceof HTMLSelectElement
      ) return;

      const s = useAppStore.getState();
      const isArtistic = s.presetKey === "artistic";

      if (e.key === "Escape") {
        if (s.zoneInfoVisible) {
          useAppStore.getState().selectZone(null);
          return;
        }
        if (s.exportModalOpen) {
          update({ exportModalOpen: false });
          return;
        }
        if (s.historyModalOpen) {
          update({ historyModalOpen: false });
          return;
        }
        if (s.cropModalOpen) {
          update({ cropModalOpen: false });
          return;
        }
        if (s.urlModalOpen) {
          update({ urlModalOpen: false });
          return;
        }
        if (s.mobileSettingsOpen) {
          update({ mobileSettingsOpen: false });
          return;
        }
        if (s.isProcessing || s.isExporting) cancelProcessing();
      }

      if (e.key === "z" && (e.ctrlKey || e.metaKey) && !e.shiftKey) {
        e.preventDefault();
        useAppStore.getState().undoCorrection();
      }

      if ((e.key === "y" && (e.ctrlKey || e.metaKey)) || (e.key === "z" && (e.ctrlKey || e.metaKey) && e.shiftKey)) {
        e.preventDefault();
        useAppStore.getState().redoCorrection();
      }

      if (isArtistic && !!s.result && !e.ctrlKey && !e.metaKey && !e.altKey) {
        if (e.key >= "1" && e.key <= "5") {
          e.preventDefault();
          useAppStore.getState().setArtisticStepAnimated(parseInt(e.key) - 1);
        }
        if (e.key === "0") {
          e.preventDefault();
          useAppStore.getState().setArtisticStepAnimated(0);
        }
        if (e.key === "f" || e.key === "F" || e.key === "а" || e.key === "А") {
          e.preventDefault();
          useAppStore.getState().toggleFlip();
        }
        if (e.key === "t" || e.key === "T" || e.key === "е" || e.key === "Е") {
          e.preventDefault();
          useAppStore.getState().toggleTemperatureMap();
        }
        if (e.key === "z" || e.key === "Z" || e.key === "я" || e.key === "Я") {
          e.preventDefault();
          useAppStore.getState().toggleZoneGuide();
        }
        if (e.key === "s" || e.key === "S" || e.key === "ы" || e.key === "Ы") {
          e.preventDefault();
          useAppStore.getState().toggleArtisticSplit();
        }
      }

      if (s.zoneGuideActive) {
        if (e.key === "ArrowRight") {
          e.preventDefault();
          useAppStore.getState().nextZone();
        }
        if (e.key === "ArrowLeft") {
          e.preventDefault();
          useAppStore.getState().prevZone();
        }
      }
    };

    document.addEventListener("keydown", h);
    return () => document.removeEventListener("keydown", h);
  }, [isOpen, cancelProcessing, update]);

  useEffect(() => {
    if (!isOpen) return;

    const handlePaste = (e: ClipboardEvent) => {
      const items = e.clipboardData?.items;
      if (!items) return;
      for (const item of Array.from(items)) {
        if (item.type.startsWith("image/")) {
          const file = item.getAsFile();
          if (file) {
            e.preventDefault();
            loadImage(file);
            return;
          }
        }
      }
    };

    document.addEventListener("paste", handlePaste);
    return () => document.removeEventListener("paste", handlePaste);
  }, [isOpen, loadImage]);

  return { loadImage, cancelProcessing };
}
