import { useRef, useState, useCallback, useEffect } from 'react';
import { cn } from '../utils/cn';

export function MaxColorsSlider({ value, onChange, recommended }: {
  value: number; onChange: (v: number) => void; recommended: number;
}) {
  const min = 2;
  const max = 8;
  const percent = ((recommended - min) / (max - min)) * 100;
  const isOptimal = value === recommended;

  const [localValue, setLocalValue] = useState(value);
  const isDragging = useRef(false);
  const isScrolling = useRef(false);
  const startPos = useRef<{ x: number, y: number } | null>(null);

  useEffect(() => {
    if (!isDragging.current) {
      setLocalValue(value);
    }
  }, [value]);

  const handleMove = useCallback((clientX: number, rect: DOMRect) => {
    const percent = Math.max(0, Math.min(1, (clientX - rect.left - 10) / (rect.width - 20)));
    const v = Math.round(percent * (max - min) + min);
    setLocalValue(v);
    onChange(v);
  }, [onChange, min, max]);

  const onTouchStart = (e: React.TouchEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const startX = e.touches[0].clientX;
    const startY = e.touches[0].clientY;
    let isSliding = false;
    let isScrolling = false;

    const move = (te: TouchEvent) => {
      if (isScrolling) return;
      const currentX = te.touches[0].clientX;
      const currentY = te.touches[0].clientY;
      const dx = Math.abs(currentX - startX);
      const dy = Math.abs(currentY - startY);

      if (!isSliding && !isScrolling) {
        if (dy > dx && dy > 8) { isScrolling = true; return; }
        if (dx > 8 || dx > dy) { isSliding = true; isDragging.current = true; }
      }

      if (isSliding) {
        if (te.cancelable) te.preventDefault();
        te.stopPropagation();
        handleMove(currentX, rect);
      }
    };

    const end = () => {
      isDragging.current = false;
      document.removeEventListener("touchmove", move);
      document.removeEventListener("touchend", end);
    };

    document.addEventListener("touchmove", move, { passive: false });
    document.addEventListener("touchend", end);
  };

  const onMouseDown = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    isDragging.current = true;
    handleMove(e.clientX, rect);

    const move = (me: MouseEvent) => { handleMove(me.clientX, rect); };
    const up = () => {
      isDragging.current = false;
      document.removeEventListener("mousemove", move);
      document.removeEventListener("mouseup", up);
    };

    document.addEventListener("mousemove", move);
    document.addEventListener("mouseup", up);
  };

  return (
    <div className="space-y-1 mb-3">
      <div className="flex justify-between items-center mb-1 px-1">
        <span className="text-sm font-bold text-slate-800 dark:text-white">
          Разнообразие цветов
        </span>
        <span className={cn("text-xs font-black px-2 py-0.5 rounded-md transition-all duration-300 tabular-nums shadow-sm",
          isOptimal 
            ? "bg-indigo-600 text-white scale-110 shadow-indigo-200 dark:shadow-indigo-900/40" 
            : "bg-slate-100 dark:bg-white/10 text-slate-800 dark:text-white shadow-inner"
        )}>
          {localValue}
        </span>
      </div>

      <div className="relative h-9 flex items-center px-2.5">
        {/* Визуальная дорожка-инфографика под слайдером */}
        <div className="absolute inset-x-2.5 h-1.5 bg-slate-200 dark:bg-white/10 rounded-full overflow-hidden shadow-inner">
          {/* Зона рекомендуемого охвата */}
          <div 
            className="absolute inset-y-0 left-0 bg-indigo-500/20 dark:bg-indigo-400/20 border-r border-indigo-400/40" 
            style={{ width: `${percent}%` }} 
          />
        </div>

        {/* Метка рекомендации и подпись (двигаются динамически) */}
        <div 
          className="absolute top-0 bottom-0 flex flex-col items-center z-0 pointer-events-none"
          style={{ left: `calc(${percent}% + 10px)`, transform: "translateX(-50%)" }}
        >
          <div className="w-0.5 h-3 bg-indigo-500/40 dark:bg-indigo-400/40 rounded-full mt-3.5" />
          <div className="mt-1">
            <svg width="8" height="8" viewBox="0 0 24 24" fill="currentColor" className="text-indigo-500/50 dark:text-indigo-400/50">
              <path d="M12 21l-12-18h24z" />
            </svg>
          </div>
          <span className="text-xs font-black text-indigo-500/70 dark:text-indigo-400/70 uppercase tracking-tighter mt-1.5 whitespace-nowrap">
            Рекомендуется
          </span>
        </div>

        <div 
          className="absolute inset-x-0 w-full h-8 flex items-center cursor-pointer touch-pan-y select-none z-20"
          onTouchStart={onTouchStart}
          onMouseDown={onMouseDown}
        />
        
        {/* Видимая головка ползунка */}
        <div 
          className={cn(
            "absolute pointer-events-none transition-all duration-100 flex items-center justify-center top-1.5 z-10",
            isDragging.current && "scale-110"
          )}
          style={{ left: `calc(${((localValue - min) / (max - min)) * 100}% + 10px - 10px)`, width: 20, height: 20 }}
        >
          <div className={`w-4.5 h-4.5 rounded-full border-2 bg-white shadow-md transform transition-transform ${isOptimal ? "border-indigo-500 scale-125" : "border-slate-400"}`} />
        </div>
      </div>

      <div className="h-1" />
    </div>
  );
}
