// src/generator/components/PreviewPanel.tsx
import React, { useRef, useMemo, useState, useCallback } from "react";
import { useAppStore } from "../store";
import { generateGridLines } from "../../utils/colorStrategies";
import { CorrectionOverlay } from "./CorrectionOverlay";
import { cn } from "../../utils/cn";
import { PreviewControls } from "./PreviewControls";
import { usePanZoom } from "../hooks/usePanZoom";
import { useSchemeRenderer } from "../hooks/useSchemeRenderer";

interface Props {
  onLoadImage?: (file: File) => void;
}

export const PreviewPanel = React.memo(function PreviewPanel({ onLoadImage }: Props) {
  const result = useAppStore((s) => s.result);
  const presetKey = useAppStore((s) => s.presetKey);
  const activeMode = useAppStore((s) => s.activeMode);
  const contourWeight = useAppStore((s) => s.presetKey === "artistic" ? s.artisticContourWeight : s.pbnContourWeight);
  const numberWeight = useAppStore((s) => s.numberWeight);
  const activeColors = useAppStore((s) => s.activeColors);
  const showNumbers = useAppStore((s) => s.showNumbers);
  const showContours = useAppStore((s) => s.showContours);
  const originalImageUrl = useAppStore((s) => s.originalImageUrl);
  const correctedImageUrl = useAppStore((s) => s.correctedImageUrl);
  const imageDimensions = useAppStore((s) => s.imageDimensions);
  const isProcessing = useAppStore((s) => s.isProcessing);
  const progressVal = useAppStore((s) => s.progress);
  const statusMsg = useAppStore((s) => s.statusMsg);
  const artisticStep = useAppStore((s) => s.artisticStep);
  const artisticPresetId = useAppStore((s) => s.artisticPresetId);
  const notanLevels = useAppStore((s) => s.notanLevels);
  const notanThreshold = useAppStore((s) => s.notanThreshold);
  const customArtPalette = useAppStore((s) => s.customArtPalette);
  const zoneGuideActive = useAppStore((s) => s.zoneGuideActive);
  const currentZoneIndex = useAppStore((s) => s.currentZoneIndex);
  const gridType = useAppStore((s) => s.gridType);
  const gridSize = useAppStore((s) => s.gridSize);
  const flipHorizontal = useAppStore((s) => s.flipHorizontal);
  const showTemperatureMap = useAppStore((s) => s.showTemperatureMap);
  const artIntensity = useAppStore((s) => s.artIntensity);
  const detailsPhotoOpacity = useAppStore((s) => s.detailsPhotoOpacity);
  const artisticSplitMode = useAppStore((s) => s.artisticSplitMode);
  const viewTransform = useAppStore((s) => s.viewTransform);
  const setViewTransform = useAppStore((s) => s.setViewTransform);
  const colorPickerActive = useAppStore((s) => s.colorPickerActive);
  const pickedColor = useAppStore((s) => s.pickedColor);
  const colorPickerPanelOpen = useAppStore((s) => s.colorPickerPanelOpen);
  const correction = useAppStore((s) => s.correction);

  const isArtistic = presetKey === "artistic";

  const fileRef = useRef<HTMLInputElement>(null);
  const schemeCanvasRef = useRef<HTMLCanvasElement>(null);

  const getCorrectionFilter = useCallback(() => {
    const { brightness, contrast, saturation } = correction;
    if (brightness === 0 && contrast === 0 && saturation === 0) return "none";
    let f = "";
    if (brightness !== 0) f += `brightness(${100 + brightness}%) `;
    if (contrast !== 0) f += `contrast(${100 + Math.max(-50, contrast)}%) `;
    if (saturation !== 0) f += `saturate(${100 + saturation}%) `;
    return f.trim();
  }, [correction]);

  const handleColorPicked = useCallback((rgb: [number, number, number]) => {
    useAppStore.setState({ pickedColor: rgb, colorPickerPanelOpen: true });
  }, []);

  const {
    containerRef,
    transformLayerRef,
    zoomTextRef,
    splitHandleRef,
    splitClip1Ref,
    splitClip2Ref,
    draggingCursor,
    resetView,
    doZoom,
    flushViewSnapshotToStore,
    applySplit,
  } = usePanZoom({
    result,
    imageDimensions,
    isArtistic,
    artisticSplitMode,
    viewTransform,
    setViewTransform,
    flipHorizontal,
    activeMode,
    originalImageUrl,
    correctedImageUrl,
    colorPickerActive,
    onColorPicked: handleColorPicked,
    schemeCanvasRef,
    correction,
    artisticStep,
    detailsPhotoOpacity,
  });

  useSchemeRenderer({
    result,
    schemeCanvasRef,
    contourWeight,
    numberWeight,
    activeColors,
    showNumbers,
    showContours,
    isArtistic,
    artisticStep,
    artisticPresetId,
    notanLevels,
    notanThreshold,
    artIntensity,
    customArtPalette,
    showTemperatureMap,
    zoneGuideActive: false,
    currentZoneContourId: -1,
    detailsPhotoOpacity,
    applySplit,
  });

  const gridLines = gridType !== "none" ? generateGridLines(gridType, gridSize) : [];
  const displayImageUrl = correctedImageUrl || originalImageUrl;

  return (
    <div className="flex-1 flex flex-col min-h-0 relative bg-gray-100 dark:bg-gray-950">
      <PreviewControls
        doZoom={doZoom}
        resetView={resetView}
        flushViewSnapshotToStore={flushViewSnapshotToStore}
        zoomTextRef={zoomTextRef}
      />

      <div
        ref={containerRef}
        className={`flex-1 relative overflow-hidden select-none ${
          colorPickerActive
            ? "cursor-crosshair"
            : draggingCursor
              ? "cursor-grabbing"
              : "cursor-grab"
        }`}
        style={{ touchAction: "none" }}
        onDrop={(e) => { e.preventDefault(); const f = e.dataTransfer.files[0]; if (f?.type.startsWith("image/") && onLoadImage) onLoadImage(f); }}
        onDragOver={(e) => e.preventDefault()}
      >
        {(!displayImageUrl || !imageDimensions) && (
          <div 
            className="absolute inset-0 flex flex-col items-center justify-center p-8 cursor-pointer group" 
            onClick={() => fileRef.current?.click()} 
            role="button" 
            aria-label="Загрузить изображение"
            tabIndex={0} 
            onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); fileRef.current?.click(); } }}
          >
            <input ref={fileRef} type="file" accept="image/jpeg,image/png,image/webp" className="hidden" aria-hidden="true" onChange={(e) => { const f = e.target.files?.[0]; if (f && onLoadImage) onLoadImage(f); e.target.value = ""; }} />
            
            <div className="relative mb-8">
               <div className="absolute inset-0 bg-indigo-500/20 dark:bg-indigo-500/10 blur-3xl rounded-full scale-150 animate-pulse" />
               <div className="w-24 h-24 sm:w-32 sm:h-32 rounded-2xl bg-white dark:bg-slate-900 shadow-premium border border-slate-100 dark:border-slate-800 flex items-center justify-center relative z-10 transition-transform duration-500">
                  <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" className="text-indigo-500 sm:w-16 sm:h-16" strokeWidth="1.2" strokeLinecap="round" aria-hidden="true">
                    <rect x="3" y="3" width="18" height="18" rx="2" ry="2" /><circle cx="8.5" cy="8.5" r="1.5" /><polyline points="21 15 16 10 5 21" />
                  </svg>
                  <div className="absolute -bottom-2 -right-2 w-10 h-10 rounded-2xl bg-indigo-600 text-white flex items-center justify-center shadow-lg border-4 border-white dark:border-slate-900 transition-transform">
                     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 5v14M5 12h14"/></svg>
                  </div>
               </div>
            </div>

            <div className="relative z-10 text-center space-y-2">
               <h2 className="text-lg sm:text-xl font-black text-slate-800 dark:text-white uppercase tracking-tight">Начните проект</h2>
               <p className="text-xs sm:text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">Загрузите фото для анализа</p>            </div>

            <div className="mt-12 flex flex-col items-center gap-4 text-xs font-black uppercase tracking-widest text-slate-300 dark:text-slate-600">
               <div className="flex items-center gap-3">
                  <span className="px-2 py-1 rounded-md border border-slate-200 dark:border-slate-800">Перетащите файл</span>
                  <span className="w-1 h-1 rounded-full bg-slate-200 dark:border-slate-800" />
                  <span className="px-2 py-1 rounded-md border border-slate-200 dark:border-slate-800">CTRL + V</span>
               </div>
            </div>
          </div>
        )}

        {displayImageUrl && imageDimensions && !result && (
          <div ref={transformLayerRef} style={{ transformOrigin: "0 0", position: "absolute", top: 0, left: 0, willChange: "transform" }}>
            <img src={displayImageUrl} alt="Оригинал" style={{ display: "block", maxWidth: "none", maxHeight: "none", width: imageDimensions.w, height: imageDimensions.h, pointerEvents: "none", filter: getCorrectionFilter() }} draggable={false} />
          </div>
        )}

        {displayImageUrl && imageDimensions && result && (
          <>
            <div ref={transformLayerRef} style={{ transformOrigin: "0 0", position: "absolute", top: 0, left: 0, willChange: "transform" }}>
              <div style={{ transform: flipHorizontal ? "scaleX(-1)" : "none", transformOrigin: `${result.imgW / 2}px ${result.imgH / 2}px` }}>
                <div style={{ position: "relative", width: result.imgW, height: result.imgH }}>
                  <div ref={splitClip1Ref} style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
                    <img src={displayImageUrl} alt="Оригинал" style={{ display: "block", maxWidth: "none", maxHeight: "none", width: "100%", height: "100%", pointerEvents: "none", filter: getCorrectionFilter() }} draggable={false} />
                  </div>
                  <div ref={splitClip2Ref} style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
                    {isArtistic && artisticStep === 3 && (
                      <div style={{ position: "absolute", inset: 0, filter: "brightness(0.9)", opacity: detailsPhotoOpacity / 100 }} className="dark:brightness-75">
                        <img src={displayImageUrl} alt="Оригинал с тенью" style={{ display: "block", maxWidth: "none", maxHeight: "none", width: "100%", height: "100%", pointerEvents: "none", filter: getCorrectionFilter() }} draggable={false} />
                      </div>
                    )}
                    {isArtistic && artisticStep === 0 && (
                      <div style={{ position: "absolute", inset: 0, opacity: detailsPhotoOpacity / 100, pointerEvents: "none" }}>
                        <img src={displayImageUrl} alt="Оригинал" style={{ display: "block", maxWidth: "none", maxHeight: "none", width: "100%", height: "100%", pointerEvents: "none", filter: getCorrectionFilter() }} draggable={false} />
                      </div>
                    )}
                    <canvas ref={schemeCanvasRef} style={{ width: result.imgW, height: result.imgH, imageRendering: "auto", position: "relative", zIndex: 10 }} />
                  </div>

                  {gridLines.length > 0 && (
                    <svg style={{ position: "absolute", inset: 0, width: result.imgW, height: result.imgH, pointerEvents: "none", zIndex: 100, mixBlendMode: "difference" }} viewBox={`0 0 ${result.imgW} ${result.imgH}`}>
                      {gridLines.map((line, i) => (
                        <line 
                          key={i} 
                          x1={line.x1 * result.imgW} 
                          y1={line.y1 * result.imgH} 
                          x2={line.x2 * result.imgW} 
                          y2={line.y2 * result.imgH} 
                          stroke="rgba(255, 255, 255, 0.85)"
                          strokeWidth={Math.max(1.5, result.imgW / 600)}
                          strokeDasharray={gridType === "grid" ? `${Math.max(4, result.imgW/200)},${Math.max(4, result.imgW/200)}` : "none"} 
                        />
                      ))}
                    </svg>
                  )}
                </div>
              </div>
            </div>

            <div ref={splitHandleRef} data-sh="1" className="absolute z-20 cursor-col-resize will-change-transform" style={{ width: 36, top: 0, left: 0 }}>
              <div className="absolute left-1/2 -translate-x-px w-0.5 h-full bg-white/80 shadow-[0_0_8px_rgba(0,0,0,0.4)] pointer-events-none" />
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 sm:w-8 sm:h-8 rounded-full bg-indigo-600 border-2 border-white shadow-lg inline-flex items-center justify-center pointer-events-none">
                <svg width="14" height="14" viewBox="0 0 12 12" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" aria-hidden="true"><path d="M4 2L2 6l2 4M8 2l2 4-2 4" /></svg>
              </div>
            </div>
          </>
        )}

        {colorPickerPanelOpen && colorPickerActive && pickedColor && (
          null
        )}
      </div>

      {isProcessing && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-sm z-30">
          <div className="rounded-2xl p-5 sm:p-6 flex flex-col items-center gap-3 shadow-2xl mx-4 min-w-[240px] sm:min-w-[260px] bg-white dark:bg-gray-900 dark:border dark:border-gray-800" role="alert" aria-live="assertive">
            <svg className="w-10 h-10 animate-spin text-indigo-500" viewBox="0 0 48 48" fill="none" stroke="currentColor" strokeWidth="4" aria-hidden="true"><circle cx="24" cy="24" r="20" strokeOpacity=".12" /><path d="M24 4a20 20 0 0 1 20 20" strokeLinecap="round" /></svg>
            <p className="text-sm font-semibold text-center text-gray-700 dark:text-gray-200">{statusMsg}</p>
            <div 
              className="w-full rounded-full h-1.5 bg-gray-200 dark:bg-gray-700" 
              role="progressbar" 
              aria-label="Прогресс обработки"
              aria-valuenow={progressVal} 
              aria-valuemin={0} 
              aria-valuemax={100}
            >
              <div className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 rounded-full transition-all duration-500" style={{ width: `${progressVal}%` }} />
            </div>
            <p className="text-xs text-indigo-400 font-mono">{progressVal}%</p>
          </div>
        </div>
      )}

      <CorrectionOverlay />
    </div>
  );
});