import { create, type StateCreator } from "zustand";
import { persist } from "zustand/middleware";
import { saveHistoryEntry, getHistoryEntries, deleteHistoryEntry } from "../../utils/idb";
import { 
  PRESETS, DEFAULT_CORRECTION, DEFAULT_VIEW_TRANSFORM, MAX_HISTORY, 
  DEFAULT_ARTISTIC_STATE, DEFAULT_PBN_STATE, SYNC_KEYS 
} from "./constants";
import { buildFlatState, syncCurrentFlatIntoModes } from "./utils";
import { profileImageQuick } from "../utils/imageProcessing/profiler";
import type { 
  AppState, UISlice, EngineSlice, CorrectionSlice, HistorySlice, HistoryEntry, 
  ArtisticModeState, PbnModeState 
} from "./types";

export * from "./types";
export * from "./constants";

const createUISlice: StateCreator<AppState, [], [], UISlice> = (set) => ({
  isDark: (() => {
    try {
      const v = localStorage.getItem("pbn-dark");
      if (v === "1") return true;
      if (v === "0") return false;
    } catch {}
    return window.matchMedia("(prefers-color-scheme: dark)").matches;
  })(),
  isProcessing: false,
  isExporting: false,
  progress: 0,
  statusMsg: "",
  abortController: null,
  mobileSettingsOpen: false,
  mobileCorrectionOpen: false,
  mobilePaletteExpanded: false,
  cropModalOpen: false,
  urlModalOpen: false,
  exportModalOpen: false,
  historyModalOpen: false,
  colorPickerActive: false,
  pickedColor: null,
  colorPickerPanelOpen: false,
  isInteracting: false,
  update: (partial) =>
    set((state) => {
      const needsSync = Object.keys(partial).some((k) => SYNC_KEYS.has(k));
      if (!needsSync) {
        return partial as Partial<AppState>;
      }
      const merged = { ...state, ...partial } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { ...partial, ...synced } as Partial<AppState>;
    }),
});

const createEngineSlice: StateCreator<AppState, [], [], EngineSlice> = (set, get) => {
  const artisticState = { ...DEFAULT_ARTISTIC_STATE, activeColors: new Set<number>(), viewTransform: { ...DEFAULT_VIEW_TRANSFORM } };
  const pbnState = { ...DEFAULT_PBN_STATE, activeColors: new Set<number>(), viewTransform: { ...DEFAULT_VIEW_TRANSFORM } };
  const flat = buildFlatState("artistic", artisticState, pbnState);

  return {
    imageFile: null, originalImageUrl: null, correctedImageUrl: null, imageDimensions: null, imageProfile: null,
    cropRect: null, result: null, presetKey: "artistic", activeMode: "artistic", artisticState, pbnState,
    ...flat,

    switchMode: (mode) => set((state) => {
      const synced = syncCurrentFlatIntoModes(state);
      const flatState = buildFlatState(mode, synced.artisticState, synced.pbnState);
      return { activeMode: mode, presetKey: mode === "artistic" ? "artistic" : "custom", artisticState: synced.artisticState, pbnState: synced.pbnState, ...flatState };
    }),

    applyPreset: (key) => {
      const p = PRESETS.find((x) => x.key === key);
      const state = get();
      const synced = syncCurrentFlatIntoModes(state);

      if (key === "artistic") {
        const nextArtistic = { ...synced.artisticState, numColors: p?.numColors ?? synced.artisticState.numColors, detail: p?.detail ?? synced.artisticState.detail, showNumbers: false };
        const flatState = buildFlatState("artistic", nextArtistic, synced.pbnState);
        set({ presetKey: "artistic", activeMode: "artistic", artisticState: nextArtistic, pbnState: synced.pbnState, ...flatState });
        return;
      }

      const nextPbn = p ? { ...synced.pbnState, numColors: p.numColors, detail: p.detail, showNumbers: true } : synced.pbnState;
      const flatState = buildFlatState("pbn", synced.artisticState, nextPbn);
      set({ presetKey: key, activeMode: "pbn", artisticState: synced.artisticState, pbnState: nextPbn, ...flatState });
    },

    setArtisticPreset: (presetId) => set((state) => {
      const nextArtistic = { ...state.artisticState, artisticPresetId: presetId };
      return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    toggleColor: (id) => set((state) => {
      const next = new Set(state.activeColors);
      if (next.has(id)) next.delete(id); else next.add(id);
      const merged = { ...state, activeColors: next } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { activeColors: next, ...synced };
    }),

    toggleAllColors: () => set((state) => {
      if (!state.result) return {};
      const all = Array.from(state.result.validLabels);
      const allOn = state.activeColors.size === all.length;
      const next = allOn ? new Set<number>() : new Set(all);
      const merged = { ...state, activeColors: next } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { activeColors: next, ...synced };
    }),

    isolateColor: (id) => set((state) => {
      if (!state.result) return {};
      const next = new Set<number>();
      if (state.activeColors.size === 1 && state.activeColors.has(id)) {
        state.result.validLabels.forEach((label) => {
          if (label !== id) next.add(label);
        });
      } else {
        next.add(id);
      }
      const merged = { ...state, activeColors: next } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { activeColors: next, ...synced };
    }),

    setNotanLevels: (levels) => set((state) => {
      const value = Math.max(2, Math.min(5, levels));
      const nextArtistic = { ...state.artisticState, notanLevels: value };
      return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    setNotanThreshold: (threshold) => set((state) => {
      const value = Math.max(0, Math.min(255, threshold));
      const nextArtistic = { ...state.artisticState, notanThreshold: value };
      return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    selectZone: (id) => set((state) => {
      const merged = { ...state, selectedZoneId: id, zoneInfoVisible: id !== null } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { selectedZoneId: id, zoneInfoVisible: id !== null, ...synced };
    }),

    setCustomArtPalette: (colors) => set((state) => {
      const nextArtistic = { ...state.artisticState, customArtPalette: colors };
      return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    toggleZoneGuide: () => set((state) => {
      const next = !state.zoneGuideActive;
      const merged = { ...state, zoneGuideActive: next, currentZoneIndex: next ? state.currentZoneIndex : 0 } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { zoneGuideActive: next, currentZoneIndex: next ? state.currentZoneIndex : 0, ...synced };
    }),

    nextZone: () => set((state) => {
      if (!state.result) return {};
      const totalZones = state.result.contoursData.length;
      if (totalZones === 0) return {};
      const currentZoneIndex = (state.currentZoneIndex + 1) % totalZones;
      const merged = { ...state, currentZoneIndex } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { currentZoneIndex, ...synced };
    }),

    prevZone: () => set((state) => {
      if (!state.result) return {};
      const totalZones = state.result.contoursData.length;
      if (totalZones === 0) return {};
      const currentZoneIndex = (state.currentZoneIndex - 1 + totalZones) % totalZones;
      const merged = { ...state, currentZoneIndex } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { currentZoneIndex, ...synced };
    }),

    setGridType: (type) => set((state) => {
      const merged = { ...state, gridType: type } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { gridType: type, ...synced };
    }),

    setGridSize: (size) => set((state) => {
      const value = Math.max(2, Math.min(20, size));
      const merged = { ...state, gridSize: value } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { gridSize: value, ...synced };
    }),

    toggleFlip: () => set((state) => {
      const merged = { ...state, flipHorizontal: !state.flipHorizontal } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { flipHorizontal: !state.flipHorizontal, ...synced };
    }),

    toggleTemperatureMap: () => set((state) => {
      const merged = { ...state, showTemperatureMap: !state.showTemperatureMap } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { showTemperatureMap: !state.showTemperatureMap, ...synced };
    }),

    setArtIntensity: (intensity) => set((state) => {
      const value = Math.max(0, Math.min(100, intensity));
      const nextArtistic = { ...state.artisticState, artIntensity: value };
      return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    setDetailsPhotoOpacity: (opacity) => set((state) => {
      const value = Math.max(0, Math.min(100, opacity));
      const nextArtistic = { ...state.artisticState, detailsPhotoOpacity: value };
      return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    setArtisticNumColors: (colors) => set((state) => {
      const value = Math.max(4, Math.min(50, colors));
      const nextArtistic = { ...state.artisticState, numColors: value };
      return { artisticState: nextArtistic, artisticNumColors: value, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    setArtisticDetail: (detail) => set((state) => {
      const value = Math.max(1, Math.min(10, detail));
      const nextArtistic = { ...state.artisticState, detail: value };
      return { artisticState: nextArtistic, artisticDetail: value, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
    }),

    setArtisticStepAnimated: (step) => {
      const s = get();
      if (s.artisticStep === step) return;
      set((state) => {
        const nextArtistic = { ...state.artisticState, prevArtisticStep: state.artisticStep, stepTransitioning: true, artisticStep: step, selectedZoneId: null, zoneInfoVisible: false };
        return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
      });
      setTimeout(() => {
        set((state) => {
          const nextArtistic = { ...state.artisticState, stepTransitioning: false };
          return { artisticState: nextArtistic, ...(state.activeMode === "artistic" ? buildFlatState("artistic", nextArtistic, state.pbnState) : {}) };
        });
      }, 300);
    },

    toggleArtisticSplit: () => set((state) => {
      const merged = { ...state, artisticSplitMode: !state.artisticSplitMode } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { artisticSplitMode: !state.artisticSplitMode, ...synced };
    }),

    setViewTransform: (patch) => set((state) => {
      const merged = { ...state, viewTransform: { ...state.viewTransform, ...patch } } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { viewTransform: { ...state.viewTransform, ...patch }, ...synced };
    }),

    resetViewTransform: () => set((state) => {
      const merged = { ...state, viewTransform: { ...DEFAULT_VIEW_TRANSFORM } } as AppState;
      const synced = syncCurrentFlatIntoModes(merged);
      return { viewTransform: { ...DEFAULT_VIEW_TRANSFORM }, ...synced };
    }),
  };
};

const createCorrectionSlice: StateCreator<AppState, [], [], CorrectionSlice> = (set, get) => ({
  correction: { ...DEFAULT_CORRECTION },
  correctionHistory: [{ ...DEFAULT_CORRECTION }],
  correctionHistoryIndex: 0,
  updateCorrection: (partial) => {
    const current = get().correction;
    set({ correction: { ...current, ...partial } });
  },
  pushCorrectionHistory: () => {
    const s = get();
    const history = s.correctionHistory.slice(0, s.correctionHistoryIndex + 1);
    history.push({ ...s.correction });
    if (history.length > 50) history.shift();
    set({ correctionHistory: history, correctionHistoryIndex: history.length - 1 });
  },
  resetCorrection: () => {
    const def = { ...DEFAULT_CORRECTION };
    const s = get();
    const history = s.correctionHistory.slice(0, s.correctionHistoryIndex + 1);
    history.push(def);
    if (s.correctedImageUrl && s.correctedImageUrl.startsWith("blob:")) {
      URL.revokeObjectURL(s.correctedImageUrl);
    }
    set({ correction: def, correctedImageUrl: null, correctionHistory: history, correctionHistoryIndex: history.length - 1 });
  },
  undoCorrection: () => {
    const s = get();
    if (s.correctionHistoryIndex <= 0) return;
    const newIndex = s.correctionHistoryIndex - 1;
    set({ correction: { ...s.correctionHistory[newIndex] }, correctionHistoryIndex: newIndex });
  },
  redoCorrection: () => {
    const s = get();
    if (s.correctionHistoryIndex >= s.correctionHistory.length - 1) return;
    const newIndex = s.correctionHistoryIndex + 1;
    set({ correction: { ...s.correctionHistory[newIndex] }, correctionHistoryIndex: newIndex });
  },
});

const createHistorySlice: StateCreator<AppState, [], [], HistorySlice> = (set, get) => ({
  generationHistory: [],
  historyCounter: 0,
  initHistory: async () => {
    try {
      const entries = await getHistoryEntries();
      entries.sort((a, b) => b.timestamp - a.timestamp);
      set({ generationHistory: entries, historyCounter: entries.length > 0 ? Math.max(...entries.map((e) => e.id)) : 0 });
    } catch (e) {
      console.error(e);
    }
  },
  addToHistory: async (entry) => {
    const s = get();
    const id = s.historyCounter + 1;
    const newEntry = { ...entry, id };
    const list = [newEntry, ...s.generationHistory].slice(0, MAX_HISTORY);
    set({ generationHistory: list, historyCounter: id });
    try {
      await saveHistoryEntry(newEntry as HistoryEntry);
      if (s.generationHistory.length >= MAX_HISTORY) {
        const toDelete = s.generationHistory.slice(MAX_HISTORY - 1);
        for (const old of toDelete) await deleteHistoryEntry(old.id);
      }
    } catch (e) {
      console.error(e);
    }
  },
  loadFromHistory: async (id) => {
    const s = get();
    const entry = s.generationHistory.find((e) => e.id === id);
    if (!entry) return;
    const allColors = new Set(Array.from(entry.result.validLabels));
    let originalImageUrl = s.originalImageUrl;
    let imageDimensions = s.imageDimensions;
    let imageProfile = s.imageProfile;
    if (entry.originalImageStr) {
      try {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = entry.originalImageStr;
        await new Promise((resolve, reject) => { img.onload = resolve; img.onerror = reject; });
        originalImageUrl = entry.originalImageStr;
        imageDimensions = { w: img.width, h: img.height };
        
        const c = document.createElement("canvas");
        c.width = img.width;
        c.height = img.height;
        const ctx = c.getContext("2d");
        if (ctx) {
          ctx.drawImage(img, 0, 0);
          const imageData = ctx.getImageData(0, 0, img.width, img.height);
          imageProfile = profileImageQuick(imageData.data, img.width, img.height);
        }
      } catch (e) {
        console.error(e);
      }
    }
    if (s.correctedImageUrl && s.correctedImageUrl.startsWith("blob:")) {
      URL.revokeObjectURL(s.correctedImageUrl);
    }
    const mode: "artistic" | "pbn" = entry.presetKey === "artistic" ? "artistic" : "pbn";
    const artisticState = mode === "artistic" ? { ...s.artisticState, numColors: entry.numColors, detail: entry.detail, activeColors: allColors, selectedZoneId: null, zoneInfoVisible: false, zoneGuideActive: false, showTemperatureMap: false, artisticSplitMode: false, flipHorizontal: false, viewTransform: { ...DEFAULT_VIEW_TRANSFORM } } : s.artisticState;
    const pbnState = mode === "pbn" ? { ...s.pbnState, numColors: entry.numColors, detail: entry.detail, activeColors: allColors, selectedZoneId: null, zoneInfoVisible: false, zoneGuideActive: false, showTemperatureMap: false, artisticSplitMode: false, flipHorizontal: false, viewTransform: { ...DEFAULT_VIEW_TRANSFORM } } : s.pbnState;
    const flatState = buildFlatState(mode, artisticState, pbnState);
    set({
      result: entry.result, originalImageUrl, imageDimensions, imageProfile, correctedImageUrl: null,
      correction: { ...DEFAULT_CORRECTION }, correctionHistory: [{ ...DEFAULT_CORRECTION }], correctionHistoryIndex: 0,
      presetKey: entry.presetKey, activeMode: mode, artisticState, pbnState, ...flatState,
      historyModalOpen: false, statusMsg: "Загружено из истории",
    });
  },
  removeFromHistory: async (id) => {
    set((s) => ({ generationHistory: s.generationHistory.filter((e) => e.id !== id) }));
    try { await deleteHistoryEntry(id); } catch (e) { console.error(e); }
  },
  clearHistory: async () => {
    set({ generationHistory: [], historyCounter: 0 });
    try {
      const { clearAllHistoryEntries } = await import("../../utils/idb");
      await clearAllHistoryEntries();
    } catch (e) {
      console.error(e);
    }
  },
});

export const useAppStore = create<AppState>()(
  persist(
    (...a) => ({
      ...createUISlice(...a),
      ...createEngineSlice(...a),
      ...createCorrectionSlice(...a),
      ...createHistorySlice(...a),
    }),
    {
      name: "melura_generator_state",
      partialize: (state) => ({
        isDark: state.isDark,
        correction: state.correction,
        correctionHistory: state.correctionHistory,
        correctionHistoryIndex: state.correctionHistoryIndex,
        presetKey: state.presetKey,
        activeMode: state.activeMode,
        artisticState: {
          ...state.artisticState,
          activeColors: Array.from(state.artisticState.activeColors),
        },
        pbnState: {
          ...state.pbnState,
          activeColors: Array.from(state.pbnState.activeColors),
        },
      }),
      merge: (persistedState: any, currentState: AppState) => {
        const artisticState: ArtisticModeState = persistedState?.artisticState
          ? {
              ...DEFAULT_ARTISTIC_STATE,
              ...persistedState.artisticState,
              activeColors: new Set<number>(persistedState.artisticState.activeColors || []),
              viewTransform: { ...DEFAULT_VIEW_TRANSFORM, ...(persistedState.artisticState.viewTransform || {}) },
            }
          : { ...DEFAULT_ARTISTIC_STATE, activeColors: new Set<number>(), viewTransform: { ...DEFAULT_VIEW_TRANSFORM } };

        const pbnState: PbnModeState = persistedState?.pbnState
          ? {
              ...DEFAULT_PBN_STATE,
              ...persistedState.pbnState,
              activeColors: new Set<number>(persistedState.pbnState.activeColors || []),
              viewTransform: { ...DEFAULT_VIEW_TRANSFORM, ...(persistedState.pbnState.viewTransform || {}) },
            }
          : { ...DEFAULT_PBN_STATE, activeColors: new Set<number>(), viewTransform: { ...DEFAULT_VIEW_TRANSFORM } };

        const activeMode: "artistic" | "pbn" =
          persistedState?.activeMode ||
          (persistedState?.presetKey === "artistic" ? "artistic" : "pbn");

        const flatState = buildFlatState(activeMode, artisticState, pbnState);

        return {
          ...currentState,
          ...persistedState,
          presetKey: persistedState?.presetKey ?? currentState.presetKey,
          activeMode,
          artisticState,
          pbnState,
          ...flatState,
        };
      },
    }
  )
);