import type { RGB, PaintProfile } from '../config';
import { formatParts } from '../config';

export function RecipeRow({ name, parts, percent, rgb, profile }: {
  name: string; parts: number; percent: number; rgb: RGB; profile: PaintProfile;
}) {
  return (
    <div className="relative flex items-center gap-4 px-4 py-4 overflow-hidden group border-b border-slate-50 dark:border-slate-800 last:border-b-0">
      <div 
        className="absolute left-0 top-0 bottom-0 opacity-[0.08] dark:opacity-[0.15] transition-all duration-1000 ease-out origin-left"
        style={{ width: `${percent}%`, backgroundColor: `rgb(${rgb})` }}
      />
      
      <div className="relative z-10 w-9 h-9 rounded-xl shadow-md border-2 border-white dark:border-slate-800 shrink-0 overflow-hidden" style={{ backgroundColor: `rgb(${rgb})` }}>
         <div className="absolute inset-0 bg-gradient-to-tr from-black/10 to-white/10" />
      </div>

      <div className="relative z-10 flex-1 min-w-0">
        <div className="text-xs font-black text-slate-800 dark:text-slate-100 truncate uppercase tracking-tighter leading-tight mb-0.5">{name}</div>
        <div className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">{percent.toFixed(1)}% состава</div>
      </div>

      <div className="relative z-10 text-right">
        <div className="text-sm font-black font-mono text-indigo-600 dark:text-indigo-400 leading-none mb-1">{parts}</div>
        <div className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{profile.unitAbbrev}</div>
      </div>
    </div>
  );
}
