// src/components/dialogs/CalibrationDialog.tsx
import { useState, useCallback, useMemo, useRef } from 'react';
import { ColorComponent } from '../../config';
import {
  loadImageFromFile,
  imageToCanvas,
  calculateWhiteBalance,
  sampleColorFromPhoto,
  screenToCanvasCoords,
  quickColorDifference,
  exportCalibration,
  downloadCalibrationFile,
  getOptimalSampleRadius,
  getDisplayRadius,
  type WhiteBalanceCorrection,
  type CalibrationEntry,
  type SampleResult,
} from '../../calibration';
import { useIsMobile } from '../../hooks/useIsMobile';
import { ColorInfo } from '../../types';
import { ModalWide } from '../ui/Modal';
import { ColorCircle } from '../ui/ColorCircle';
import { cn } from '../../utils/cn';
import type { RGB } from '../../engine';

type CalibrationStep = 'intro' | 'photo' | 'white-balance' | 'sampling' | 'review';

export function CalibrationDialog({ colorInfos, selectedNames, onApply, onClose, addToast }: {
  colorInfos: ColorInfo[];
  selectedNames: Set<string>;
  onApply: (entries: CalibrationEntry[]) => void;
  onClose: () => void;
  addToast: (m: string, t: 'success' | 'info' | 'error') => void;
}) {
  const isMobile = useIsMobile();
  const [step, setStep] = useState<CalibrationStep>('intro');
  const [imageEl, setImageEl] = useState<HTMLImageElement | null>(null);

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const ctxRef = useRef<CanvasRenderingContext2D | null>(null);
  const imgDisplayRef = useRef<HTMLDivElement>(null);

  const [canvasSize, setCanvasSize] = useState({ w: 0, h: 0 });
  const [sampleRadius, setSampleRadius] = useState(15);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const [whiteBalance, setWhiteBalance] = useState<WhiteBalanceCorrection>({ r: 1, g: 1, b: 1 });
  const [wbSample, setWbSample] = useState<RGB | null>(null);
  const [wbPoint, setWbPoint] = useState<{ x: number; y: number } | null>(null);

  const [colorsToCalibrate, setColorsToCalibrate] = useState<ColorComponent[]>([]);
  const [currentColorIndex, setCurrentColorIndex] = useState(0);

  const [entries, setEntries] = useState<CalibrationEntry[]>([]);
  const [currentSample, setCurrentSample] = useState<SampleResult | null>(null);
  const [samplePoints, setSamplePoints] = useState<Map<string, { x: number; y: number; screenX: number; screenY: number }>>(new Map());

  const availableColors = useMemo(() => {
    return colorInfos
      .filter(ci => selectedNames.has(ci.color.name))
      .map(ci => ci.color);
  }, [colorInfos, selectedNames]);

  const handleFileSelect = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const img = await loadImageFromFile(file);
      setImageEl(img);

      const { canvas, ctx } = imageToCanvas(img);
      canvasRef.current = canvas;
      ctxRef.current = ctx;
      setCanvasSize({ w: canvas.width, h: canvas.height });
      setSampleRadius(getOptimalSampleRadius(canvas.width, canvas.height));

      setPreviewUrl(canvas.toDataURL('image/jpeg', 0.8));
      setStep('white-balance');
    } catch (err) {
      addToast('Не удалось загрузить изображение', 'error');
    }
  }, [addToast]);

  const handleImageClick = useCallback((e: React.MouseEvent<HTMLDivElement> | React.TouchEvent<HTMLDivElement>) => {
    if (!ctxRef.current || !imgDisplayRef.current) return;
    const rect = imgDisplayRef.current.getBoundingClientRect();

    let clientX: number, clientY: number;
    if ('touches' in e) {
      if (!e.touches[0]) return;
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    const coords = screenToCanvasCoords(clientX, clientY, rect, canvasSize.w, canvasSize.h);

    if (step === 'white-balance') {
      const wb = calculateWhiteBalance(ctxRef.current, coords.x, coords.y, sampleRadius);
      setWhiteBalance(wb);
      const raw = sampleColorFromPhoto(ctxRef.current, coords.x, coords.y, { r: 1, g: 1, b: 1 }, sampleRadius);
      setWbSample(raw.rawRgb);
      setWbPoint(coords);
    } else if (step === 'sampling' && colorsToCalibrate[currentColorIndex]) {
      const sample = sampleColorFromPhoto(ctxRef.current, coords.x, coords.y, whiteBalance, sampleRadius);
      setCurrentSample(sample);

      setSamplePoints(prev => {
        const next = new Map(prev);
        next.set(colorsToCalibrate[currentColorIndex].name, {
          x: coords.x, y: coords.y,
          screenX: clientX - rect.left, screenY: clientY - rect.top,
        });
        return next;
      });
    }
  }, [step, canvasSize, sampleRadius, whiteBalance, colorsToCalibrate, currentColorIndex]);

  const confirmCurrentColor = useCallback(() => {
    if (!currentSample || !colorsToCalibrate[currentColorIndex]) return;

    const color = colorsToCalibrate[currentColorIndex];
    const point = samplePoints.get(color.name);

    setEntries(prev => {
      const filtered = prev.filter(e => e.name !== color.name);
      return [...filtered, {
        name: color.name,
        originalRgb: color.rgb,
        calibratedRgb: currentSample.correctedRgb,
        samplePoint: point ? { x: point.x, y: point.y } : undefined,
      }];
    });

    if (currentColorIndex < colorsToCalibrate.length - 1) {
      setCurrentColorIndex(prev => prev + 1);
      setCurrentSample(null);
    } else {
      setStep('review');
    }
  }, [currentSample, colorsToCalibrate, currentColorIndex, samplePoints]);

  const skipCurrentColor = useCallback(() => {
    if (currentColorIndex < colorsToCalibrate.length - 1) {
      setCurrentColorIndex(prev => prev + 1);
      setCurrentSample(null);
    } else {
      setStep('review');
    }
  }, [currentColorIndex, colorsToCalibrate.length]);

  const goToPreviousColor = useCallback(() => {
    if (currentColorIndex > 0) {
      setCurrentColorIndex(prev => prev - 1);
      setCurrentSample(null);
    }
  }, [currentColorIndex]);

  const removeEntry = useCallback((name: string) => {
    setEntries(prev => prev.filter(e => e.name !== name));
  }, []);

  const handleApply = useCallback(() => {
    if (entries.length === 0) {
      addToast('Нет откалиброванных цветов', 'error');
      return;
    }
    onApply(entries);
    addToast(`Откалибровано ${entries.length} цветов!`, 'success');
    onClose();
  }, [entries, onApply, onClose, addToast]);

  const handleExport = useCallback(() => {
    if (entries.length === 0) return;
    const data = exportCalibration(entries);
    downloadCalibrationFile(data);
    addToast('Файл калибровки сохранён', 'success');
  }, [entries, addToast]);

  const [introSelected, setIntroSelected] = useState<Set<string>>(() => new Set(availableColors.map(c => c.name)));

  const toggleIntroColor = useCallback((name: string) => {
    setIntroSelected(prev => {
      const next = new Set(prev);
      if (next.has(name)) next.delete(name); else next.add(name);
      return next;
    });
  }, []);

  const startCalibration = useCallback(() => {
    const selected = availableColors.filter(c => introSelected.has(c.name));
    if (selected.length === 0) {
      addToast('Выберите хотя бы один цвет', 'error');
      return;
    }
    setColorsToCalibrate(selected);
    setStep('photo');
  }, [availableColors, introSelected, addToast]);

  const currentColor = colorsToCalibrate[currentColorIndex] || null;

  const displayStyle = useMemo(() => {
    if (!canvasSize.w || !canvasSize.h) return {};
    const maxW = window.innerWidth > 640 ? 460 : window.innerWidth - 48;
    const maxH = window.innerHeight * 0.4;
    const scale = Math.min(maxW / canvasSize.w, maxH / canvasSize.h, 1);
    return {
      width: Math.round(canvasSize.w * scale),
      height: Math.round(canvasSize.h * scale),
    };
  }, [canvasSize]);

  return (
    <ModalWide onClose={onClose} zClass="z-[60]">
      <div className="px-5 pt-4 sm:pt-5 pb-4 border-b border-slate-200/50 dark:border-slate-800/50 flex flex-col shrink-0">
        <div className="flex items-center justify-between mb-1">
          <div className="flex items-center gap-2.5">
            <span className="text-indigo-500 bg-indigo-50 dark:bg-indigo-500/10 p-1.5 rounded-lg shrink-0">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M14.5 4h-5L7 7H4a2 2 0 0 0-2 2v9a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2V9a2 2 0 0 0-2-2h-3l-2.5-3z"/>
                <circle cx="12" cy="13" r="3"/>
              </svg>
            </span>
            <h2 className="text-base sm:text-lg font-bold text-slate-900 dark:text-white truncate">
              {step === 'intro' && 'Калибровка палитры'}
              {step === 'photo' && 'Загрузка фото'}
              {step === 'white-balance' && 'Баланс белого'}
              {step === 'sampling' && `Цвет ${currentColorIndex + 1}/${colorsToCalibrate.length}`}
              {step === 'review' && 'Результаты'}
            </h2>
          </div>
          <button onClick={onClose} className="w-10 h-10 -mr-2 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors shrink-0" aria-label="Закрыть">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M18 6L6 18M6 6l12 12" />
            </svg>
          </button>
        </div>
        <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 ml-9">
          {step === 'intro' && 'Подготовка красок'}
          {step === 'photo' && 'Источник данных'}
          {step === 'white-balance' && 'Настройка освещения'}
          {step === 'sampling' && 'Выбор мазков на фото'}
          {step === 'review' && 'Проверка изменений'}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-5 space-y-6 pb-24 custom-scrollbar">
        {step === 'intro' && (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="bg-indigo-50/50 dark:bg-indigo-500/5 border border-indigo-100 dark:border-indigo-500/20 rounded-2xl p-4">
                <h3 className="font-bold text-xs text-indigo-700 dark:text-indigo-300 uppercase tracking-wider mb-3 flex items-center gap-2">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>
                  Инструкция
                </h3>
                <ul className="text-xs text-indigo-800/80 dark:text-indigo-300/70 space-y-2 font-medium">
                  <li className="flex gap-2"><span>1.</span> Нанесите мазки красок на белую бумагу</li>
                  <li className="flex gap-2"><span>2.</span> Сфотографируйте при дневном свете</li>
                  <li className="flex gap-2"><span>3.</span> Убедитесь, что бумага видна на фото</li>
                </ul>
              </div>

              <div className="bg-slate-50 dark:bg-white/5 border border-slate-100 dark:border-white/5 rounded-2xl p-4 flex flex-col justify-center items-center text-center">
                 <div className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Выбрано для калибровки</div>
                 <div className="text-2xl font-black text-indigo-600 dark:text-indigo-400 tabular-nums">
                   {introSelected.size} <span className="text-slate-300 dark:text-slate-700 mx-1">/</span> {availableColors.length}
                 </div>
                 <button
                    onClick={() => setIntroSelected(introSelected.size === availableColors.length ? new Set() : new Set(availableColors.map(c => c.name)))}
                    className="mt-2 text-xs font-bold uppercase tracking-wider text-indigo-500 hover:text-indigo-400 py-1 px-3 rounded-full bg-indigo-500/10 transition-colors">
                    {introSelected.size === availableColors.length ? 'Снять все' : 'Выбрать все'}
                  </button>
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex items-center gap-2">
                <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
                <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">
                  Список красок
                </h3>
                <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
              </div>
              
              <div className="grid grid-cols-1 xs:grid-cols-2 sm:grid-cols-3 gap-2 max-h-[40dvh] overflow-y-auto px-0.5 pr-1 custom-scrollbar">
                {availableColors.map(c => (
                  <label key={c.name}
                    className={cn(
                      "flex items-center gap-3 px-3 py-3 rounded-2xl border-2 cursor-pointer transition-all active:scale-[0.97]",
                      introSelected.has(c.name)
                        ? "border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 shadow-sm"
                        : "border-slate-100 dark:border-slate-800 hover:border-slate-200 dark:hover:border-slate-700 bg-white dark:bg-slate-900"
                    )}>
                    <div className="relative flex-shrink-0">
                      <input type="checkbox" checked={introSelected.has(c.name)}
                        onChange={() => toggleIntroColor(c.name)}
                        className="peer sr-only" />
                      <div className="w-5 h-5 rounded-lg border-2 border-slate-200 dark:border-slate-700 peer-checked:bg-indigo-600 peer-checked:border-indigo-600 peer-checked:shadow-lg peer-checked:shadow-indigo-500/30 transition-all duration-300" />
                      <svg className="absolute inset-0 m-auto w-3.5 h-3.5 text-white scale-0 peer-checked:scale-100 transition-transform duration-300 ease-out pointer-events-none" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                    </div>
                    <ColorCircle rgb={c.rgb} size={24} />
                    <span className="text-xs font-bold text-slate-700 dark:text-slate-200 truncate">{c.name}</span>
                  </label>
                ))}
              </div>
            </div>

            <button onClick={startCalibration} disabled={introSelected.size === 0}
              className="w-full py-4 rounded-2xl font-black text-sm uppercase tracking-widest text-white bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:grayscale transition-all shadow-lg shadow-indigo-500/20 active:scale-[0.98]">
              Начать анализ
            </button>
          </>
        )}

        {step === 'photo' && (
          <>
            <p className="text-sm text-slate-600 dark:text-slate-200 text-center mb-2">
              Загрузите фото с мазками красок на белой бумаге.
            </p>
            <div className="space-y-3">
              <label className="flex flex-col items-center justify-center w-full py-10 rounded-2xl border-2 border-dashed border-slate-300 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 hover:border-indigo-400 dark:hover:border-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/10 cursor-pointer transition-all">
                <svg className="w-10 h-10 text-slate-500 mb-3" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                  <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
                  <circle cx="8.5" cy="8.5" r="1.5"/>
                  <polyline points="21 15 16 10 5 21"/>
                </svg>
                <div className="text-sm font-bold text-slate-700 dark:text-slate-300">
                  {isMobile ? 'Выбрать из галереи' : 'Выбрать файл'}
                </div>
                <div className="text-xs font-medium text-slate-500 mt-1">JPG, PNG · до 20 МБ</div>
                <input type="file" accept="image/*" onChange={handleFileSelect} className="hidden" />
              </label>

              {isMobile && (
                <label className="flex flex-col items-center justify-center w-full py-6 rounded-2xl border-2 border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 hover:border-indigo-400 cursor-pointer transition-all shadow-sm">
                  <svg className="w-6 h-6 text-slate-600 mb-2" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M14.5 4h-5L7 7H4a2 2 0 0 0-2 2v9a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2V9a2 2 0 0 0-2-2h-3l-2.5-3z"/>
                    <circle cx="12" cy="13" r="3"/>
                  </svg>
                  <div className="text-sm font-bold text-slate-700 dark:text-slate-300">Сделать снимок</div>
                  <input type="file" accept="image/*" capture="environment" onChange={handleFileSelect} className="hidden" />
                </label>
              )}
            </div>
            <button onClick={() => setStep('intro')} className="w-full py-3 rounded-xl text-sm font-semibold text-slate-600 dark:text-slate-200 border-2 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors mt-2">
              Назад
            </button>
          </>
        )}

        {step === 'white-balance' && canvasRef.current && previewUrl && (
          <>
            <div className="bg-amber-50 dark:bg-amber-900/15 border border-amber-200 dark:border-amber-800/50 rounded-xl px-4 py-3 flex items-start gap-3 shadow-sm">
              <svg className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/>
              </svg>
              <p className="text-xs text-amber-700 dark:text-amber-300 font-medium leading-relaxed">
                Нажмите на <b>чистый белый участок бумаги</b> для коррекции освещения.
              </p>
            </div>

            <div className="flex justify-center">
              <div ref={imgDisplayRef}
                className="relative cursor-crosshair rounded-xl overflow-hidden border-2 border-slate-200 dark:border-slate-700 shadow-inner bg-slate-100 dark:bg-slate-800"
                style={{ ...displayStyle, touchAction: 'none' }}
                onClick={handleImageClick}
                onTouchEnd={handleImageClick as any}>
                
                <img src={previewUrl} alt="Фото для калибровки" className="w-full h-full object-contain pointer-events-none" draggable={false} />
                
                {wbPoint && (
                  <div className="absolute w-8 h-8 border-[3px] border-white rounded-full shadow-[0_0_8px_rgba(0,0,0,0.5)] pointer-events-none -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `${(wbPoint.x / canvasSize.w) * 100}%`, top: `${(wbPoint.y / canvasSize.h) * 100}%` }}>
                    <div className="w-1.5 h-1.5 bg-white rounded-full absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 shadow-sm" />
                  </div>
                )}
              </div>
            </div>

            {wbSample && (
              <div className="flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700/80 rounded-xl shadow-sm">
                <div className="flex items-center gap-3">
                  <div className="text-center flex flex-col items-center gap-1.5">
                    <div className="w-12 h-12 rounded-xl border border-black/10 shadow-inner" style={{ backgroundColor: `rgb(${wbSample})` }} />
                    <div className="text-xs font-bold uppercase text-slate-600">Фото</div>
                  </div>
                  <svg className="w-5 h-5 text-slate-300 dark:text-slate-400" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                  <div className="text-center flex flex-col items-center gap-1.5">
                    <div className="w-12 h-12 rounded-xl border border-slate-200 dark:border-slate-600 bg-white shadow-sm" />
                    <div className="text-xs font-bold uppercase text-slate-600">Цель</div>
                  </div>
                </div>
                
                <div className="h-10 w-px bg-slate-200 dark:bg-slate-700" />
                
                <div className="flex-1 min-w-0 flex flex-col justify-center">
                  <div className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-1">Множители:</div>
                  <div className="text-xs font-mono font-semibold text-slate-600 dark:text-slate-300 grid grid-cols-1 gap-1">
                    <span className="text-red-500">R × {whiteBalance.r.toFixed(2)}</span>
                    <span className="text-green-600 dark:text-green-500">G × {whiteBalance.g.toFixed(2)}</span>
                    <span className="text-blue-500">B × {whiteBalance.b.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            )}

            <div className="flex gap-3 pt-2">
              <button onClick={() => setStep('photo')} className="w-1/3 py-3.5 rounded-xl text-sm font-bold text-slate-600 dark:text-slate-200 border-2 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                Назад
              </button>
              <button onClick={() => { setCurrentColorIndex(0); setCurrentSample(null); setStep('sampling'); }}
                disabled={!wbSample}
                className="flex-1 py-3.5 rounded-xl font-bold text-sm text-white bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 dark:disabled:bg-slate-800 dark:disabled:border-slate-700 dark:disabled:text-slate-600 disabled:border shadow-md active:scale-[0.98] transition-all">
                Продолжить
              </button>
            </div>
          </>
        )}

        {step === 'sampling' && canvasRef.current && currentColor && previewUrl && (
          <>
            <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700/80 rounded-xl shadow-sm">
              <div className="flex items-center gap-3">
                <ColorCircle rgb={currentColor.rgb} size={36} />
                <div className="flex flex-col justify-center">
                  <div className="font-bold text-sm text-slate-900 dark:text-white leading-tight">{currentColor.name}</div>
                  <div className="text-xs font-medium text-slate-600 dark:text-slate-200 mt-0.5">Нажмите на мазок этого цвета</div>
                </div>
              </div>
              <div className="px-3 py-1.5 bg-white dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700 text-xs text-slate-600 dark:text-slate-300 font-bold shadow-sm">
                {currentColorIndex + 1} / {colorsToCalibrate.length}
              </div>
            </div>

            <div className="flex justify-center">
              <div ref={imgDisplayRef}
                className="relative cursor-crosshair rounded-xl overflow-hidden border-2 border-slate-200 dark:border-slate-700 shadow-inner bg-slate-100 dark:bg-slate-800"
                style={{ ...displayStyle, touchAction: 'none' }}
                onClick={handleImageClick}
                onTouchEnd={handleImageClick as any}>
                <img src={previewUrl} alt="Фото для калибровки" className="w-full h-full object-contain pointer-events-none" draggable={false} />
                
                {Array.from(samplePoints.entries()).map(([name, pt]) => {
                  const isActive = name === currentColor.name;
                  return (
                    <div key={name}
                      className={cn(
                        "absolute w-7 h-7 rounded-full border-[2.5px] pointer-events-none -translate-x-1/2 -translate-y-1/2 transition-colors",
                        isActive ? "border-indigo-500 bg-indigo-500/20 shadow-[0_0_8px_rgba(99,102,241,0.5)]" : "border-white/80 bg-white/10 shadow-[0_0_4px_rgba(0,0,0,0.5)]"
                      )}
                      style={{ left: `${(pt.x / canvasSize.w) * 100}%`, top: `${(pt.y / canvasSize.h) * 100}%` }}>
                      {!isActive && <div className="w-1.5 h-1.5 bg-white rounded-full absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 shadow-sm" />}
                    </div>
                  );
                })}
              </div>
            </div>

            {currentSample && (
              <div className="space-y-3 animate-fade-in-up">
                <div className="flex items-center gap-4 p-4 bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                  <div className="text-center flex flex-col items-center gap-1.5">
                    <div className="w-12 h-12 rounded-xl border border-black/10 shadow-inner" style={{ backgroundColor: `rgb(${currentColor.rgb})` }} />
                    <div className="text-xs font-bold uppercase text-slate-500">Было</div>
                  </div>
                  <svg className="w-5 h-5 text-slate-300 dark:text-slate-400" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                  <div className="text-center flex flex-col items-center gap-1.5">
                    <div className="w-12 h-12 rounded-xl border border-black/10 shadow-inner" style={{ backgroundColor: `rgb(${currentSample.correctedRgb})` }} />
                    <div className="text-xs font-bold uppercase text-slate-500">Стало</div>
                  </div>
                  
                  <div className="h-10 w-px bg-slate-100 dark:bg-slate-800 mx-1" />
                  
                  <div className="flex-1 min-w-0 flex flex-col justify-center">
                    <div className="text-xs font-bold text-slate-700 dark:text-slate-300 mb-1">
                      ΔE ≈ {quickColorDifference(currentColor.rgb, currentSample.correctedRgb).toFixed(1)}
                    </div>
                    <div className="font-mono text-xs font-medium text-slate-600 bg-slate-50 dark:bg-slate-800 px-2 py-1 rounded">
                      {currentSample.correctedRgb.join(', ')}
                    </div>
                  </div>
                </div>

                {currentSample.warning && (
                  <div className="flex items-start gap-2.5 px-4 py-3 rounded-xl bg-amber-50 dark:bg-amber-900/15 border border-amber-200 dark:border-amber-800/50 shadow-sm">
                    <svg className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
                    <p className="text-xs font-medium text-amber-700 dark:text-amber-300 leading-relaxed">{currentSample.warning}</p>
                  </div>
                )}
              </div>
            )}

            <div className="flex flex-col gap-3 pt-2">
              <div className="flex gap-3">
                <button onClick={currentColorIndex > 0 ? goToPreviousColor : () => setStep('white-balance')}
                  className="w-14 flex items-center justify-center py-3.5 rounded-xl border-2 border-slate-200 dark:border-slate-700 text-slate-600 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                  <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                </button>
                <button onClick={skipCurrentColor}
                  className="w-1/3 py-3.5 rounded-xl text-sm font-bold text-slate-600 dark:text-slate-200 border-2 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                  Пропустить
                </button>
                <button onClick={confirmCurrentColor} disabled={!currentSample}
                  className="flex-1 py-3.5 rounded-xl font-bold text-sm text-white bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 dark:disabled:bg-slate-800 dark:disabled:border-slate-700 dark:disabled:text-slate-600 disabled:border shadow-md active:scale-[0.98] transition-all">
                  Подтвердить
                </button>
              </div>
              
              <div className="h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 transition-[width] duration-300 ease-out"
                  style={{ width: `${((currentColorIndex) / colorsToCalibrate.length) * 100}%` }} />
              </div>
            </div>
          </>
        )}

        {step === 'review' && (
          <>
            {entries.length === 0 ? (
              <div className="text-center py-12 flex flex-col items-center">
                <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                  <svg className="w-8 h-8 text-slate-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>
                </div>
                <p className="text-sm font-medium text-slate-600 dark:text-slate-200 mb-4">Ни один цвет не был откалиброван.</p>
                <button onClick={() => { setCurrentColorIndex(0); setCurrentSample(null); setStep('sampling'); }}
                  className="px-6 py-2.5 rounded-xl text-sm font-bold text-indigo-600 bg-indigo-50 hover:bg-indigo-100 transition-colors">
                  Вернуться к выбору
                </button>
              </div>
            ) : (
              <div className="space-y-4 animate-fade-in-up">
                <div className="flex items-center justify-between px-2">
                  <span className="text-sm font-bold text-slate-800 dark:text-slate-200">Результаты</span>
                  <span className="text-xs font-semibold px-2 py-1 rounded-lg bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400">
                    Откалибровано: {entries.length} из {colorsToCalibrate.length}
                  </span>
                </div>
                
                <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/50 dark:border-slate-800/50 overflow-hidden shadow-sm">
                  {entries.map(entry => (
                    <div key={entry.name} className="flex items-center gap-3 px-4 py-3 border-b border-slate-100 dark:border-slate-800/80 last:border-b-0">
                      <div className="flex items-center gap-2">
                        <div className="w-8 h-8 rounded-lg border border-black/10 shadow-inner" style={{ backgroundColor: `rgb(${entry.originalRgb})` }} />
                        <svg className="w-4 h-4 text-slate-300 dark:text-slate-400" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                        <div className="w-8 h-8 rounded-lg border border-black/10 shadow-inner" style={{ backgroundColor: `rgb(${entry.calibratedRgb})` }} />
                      </div>
                      <div className="flex-1 min-w-0 pl-1">
                        <div className="text-xs font-bold text-slate-800 dark:text-slate-200 truncate">{entry.name}</div>
                        <div className="text-xs font-medium text-slate-600 mt-0.5 font-mono">
                          ΔE ≈ {quickColorDifference(entry.originalRgb, entry.calibratedRgb).toFixed(1)}
                        </div>
                      </div>
                      <button onClick={() => removeEntry(entry.name)}
                        className="w-8 h-8 rounded-full flex items-center justify-center bg-slate-50 dark:bg-slate-800 text-slate-500 hover:bg-red-50 dark:hover:bg-red-900/20 hover:text-red-500 transition-colors">
                        <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                      </button>
                    </div>
                  ))}
                </div>

                <div className="flex gap-3 pt-2">
                  <button onClick={handleExport}
                    className="flex-1 py-3.5 rounded-xl text-sm font-bold text-slate-600 dark:text-slate-300 border-2 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors flex items-center justify-center gap-2">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>
                    Сохранить
                  </button>
                  <button onClick={handleApply}
                    className="flex-1 py-3.5 rounded-xl font-bold text-sm text-white bg-emerald-600 hover:bg-emerald-700 shadow-md active:scale-[0.98] transition-all">
                    Применить
                  </button>
                </div>
                <button onClick={() => { setCurrentColorIndex(0); setCurrentSample(null); setStep('sampling'); }}
                  className="w-full py-2.5 rounded-xl text-xs font-semibold text-slate-600 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors flex items-center justify-center gap-1.5 mt-1">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                  Вернуться к настройке
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </ModalWide>
  );
}