// src/generator/hooks/useSchemeRenderer.ts
import { useEffect, useRef } from "react";
import { renderSchemeCanvas } from "../utils/imageProcessing";
import type { ProcessingResult } from "../utils/imageProcessing";
import type { RGB } from "../../config";

interface UseSchemeRendererProps {
  result: ProcessingResult | null;
  schemeCanvasRef: React.RefObject<HTMLCanvasElement | null>;
  contourWeight: number;
  numberWeight: number;
  activeColors: Set<number>;
  showNumbers: boolean;
  showContours: boolean;
  isArtistic: boolean;
  artisticStep: number;
  artisticPresetId: string | undefined;
  notanLevels: number;
  notanThreshold: number;
  artIntensity: number;
  customArtPalette: RGB[];
  showTemperatureMap: boolean;
  zoneGuideActive: boolean;
  currentZoneContourId: number;
  detailsPhotoOpacity: number;
  applySplit: () => void;
}

export function useSchemeRenderer({
  result,
  schemeCanvasRef,
  contourWeight,
  numberWeight,
  activeColors,
  showNumbers,
  isArtistic,
  artisticStep,
  artisticPresetId,
  notanLevels,
  notanThreshold,
  artIntensity,
  customArtPalette,
  showTemperatureMap,
  zoneGuideActive,
  currentZoneContourId,
  detailsPhotoOpacity,
  showContours,
  applySplit,
}: UseSchemeRendererProps) {
  const renderTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!result) {
      if (schemeCanvasRef.current) {
        schemeCanvasRef.current.width = 0;
        schemeCanvasRef.current.height = 0;
      }
      applySplit();
      return;
    }

    if (renderTimerRef.current) clearTimeout(renderTimerRef.current);
    renderTimerRef.current = setTimeout(() => {
      const c = schemeCanvasRef.current;
      if (!c) return;
      try {
        renderSchemeCanvas(
          c,
          result,
          contourWeight,
          numberWeight,
          activeColors,
          showNumbers,
          2,
          isArtistic,
          artisticStep,
          artisticPresetId as any,
          notanLevels,
          notanThreshold,
          artIntensity,
          customArtPalette.length >= 2 ? customArtPalette : undefined,
          showTemperatureMap,
          zoneGuideActive,
          currentZoneContourId,
          detailsPhotoOpacity,
          showContours
        );
      } catch (err) {
        console.error("Scheme render error:", err);
      }
      applySplit();
    }, 30);

    return () => {
      if (renderTimerRef.current) clearTimeout(renderTimerRef.current);
    };
  }, [
    result,
    contourWeight,
    numberWeight,
    activeColors,
    showNumbers,
    showContours,
    applySplit,
    isArtistic,
    artisticStep,
    artisticPresetId,
    notanLevels,
    notanThreshold,
    artIntensity,
    customArtPalette,
    showTemperatureMap,
    zoneGuideActive,
    currentZoneContourId,
    detailsPhotoOpacity,
    schemeCanvasRef,
  ]);
}