// src/generator/components/MobileBottomSheet.tsx
import { useEffect, useRef, useState, useCallback } from "react";
import { useAppStore } from "../store";
import { SettingsContent } from "./SettingsPanel";
import { cn } from "../../utils/cn";
import { useBackButton } from "../../hooks/useBackButton";

export function MobileBottomSheet() {
  const isOpen = useAppStore((s) => s.mobileSettingsOpen);
  const isDark = useAppStore((s) => s.isDark);
  const update = useAppStore((s) => s.update);

  const sheetRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  const [dragY, setDragY] = useState(0);

  const touchingRef = useRef(false);
  const startY = useRef(0);
  const startScroll = useRef(0);
  const ignoreDragRef = useRef(false);
  const dragStartedFromHandleRef = useRef(false);

  const close = useCallback(() => {
    setDragY(0);
    update({ mobileSettingsOpen: false });
  }, [update]);

  useBackButton(isOpen, close);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
      setDragY(0);
    }

    return () => {
      document.body.style.overflow = "";
    };
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) return;

    const h = (e: KeyboardEvent) => {
      if (e.key === "Escape") close();
    };

    document.addEventListener("keydown", h);
    return () => document.removeEventListener("keydown", h);
  }, [isOpen, close]);

  useEffect(() => {
    const sheet = sheetRef.current;
    if (!sheet || !isOpen) return;

    const isInteractiveTarget = (target: HTMLElement | null) => {
      if (!target) return false;
      return !!(
        target.closest('input[type="range"]') ||
        target.closest("button") ||
        target.closest("select") ||
        target.closest("input") ||
        target.closest("textarea") ||
        target.closest("label") ||
        target.closest('[role="radiogroup"]') ||
        target.closest('[role="radio"]')
      );
    };

    const handleTouchStart = (e: TouchEvent) => {
      const target = e.target as HTMLElement;

      dragStartedFromHandleRef.current = !!target.closest("[data-handle]");

      if (isInteractiveTarget(target) && !dragStartedFromHandleRef.current) {
        ignoreDragRef.current = true;
        return;
      }

      ignoreDragRef.current = false;

      const scrollContainer = contentRef.current ?? sheet;
      const currentScrollTop = scrollContainer.scrollTop;

      if (!dragStartedFromHandleRef.current && currentScrollTop > 0) return;

      touchingRef.current = true;
      startY.current = e.touches[0].clientY;
      startScroll.current = currentScrollTop;
      setDragY(0);
    };

    const handleTouchMove = (e: TouchEvent) => {
      if (ignoreDragRef.current) return;
      if (!touchingRef.current) return;

      const dy = e.touches[0].clientY - startY.current;
      const scrollContainer = contentRef.current ?? sheet;

      if (dragStartedFromHandleRef.current) {
        if (dy > 0) {
          setDragY(dy);
          e.preventDefault();
        } else {
          setDragY(0);
        }
        return;
      }

      if (scrollContainer.scrollTop <= 0 && dy > 0 && startScroll.current <= 0) {
        setDragY(dy);
        e.preventDefault();
      }
    };

    const handleTouchEnd = () => {
      ignoreDragRef.current = false;
      dragStartedFromHandleRef.current = false;

      if (!touchingRef.current) return;
      touchingRef.current = false;

      setDragY((currentDragY) => {
        if (currentDragY > 100) {
          close();
        }
        return 0;
      });
    };

    sheet.addEventListener("touchstart", handleTouchStart, { passive: true });
    sheet.addEventListener("touchmove", handleTouchMove, { passive: false });
    sheet.addEventListener("touchend", handleTouchEnd, { passive: true });
    sheet.addEventListener("touchcancel", handleTouchEnd, { passive: true });

    return () => {
      sheet.removeEventListener("touchstart", handleTouchStart);
      sheet.removeEventListener("touchmove", handleTouchMove);
      sheet.removeEventListener("touchend", handleTouchEnd);
      sheet.removeEventListener("touchcancel", handleTouchEnd);
    };
  }, [isOpen, close]);

  if (!isOpen) return null;

  const sheetTransform = dragY > 0 ? `translateY(${dragY}px)` : "translateY(0)";
  const opacity = dragY > 0 ? Math.max(0, 1 - dragY / 300) : 1;

  return (
    <div
      className="lg:hidden fixed inset-0 z-50 overflow-hidden"
      role="dialog"
      aria-modal="true"
      aria-label="Настройки"
    >
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-300"
        style={{ opacity }}
        onClick={close}
        aria-hidden="true"
      />

      <div
        ref={sheetRef}
        className={cn(
          "absolute bottom-0 left-0 right-0 rounded-t-[3rem] shadow-[0_-20px_50px_rgba(0,0,0,0.2)] dark:shadow-[0_-20px_50px_rgba(0,0,0,0.5)] overflow-hidden flex flex-col border-t border-white/20 dark:border-white/10 transition-all duration-500 ease-[cubic-bezier(0.32,0.72,0,1)]",
          isDark ? "bg-slate-900/90 backdrop-blur-2xl" : "bg-white/90 backdrop-blur-2xl"
        )}
        style={{
          maxHeight: "85dvh",
          transform: sheetTransform,
        }}
      >
        {/* Ручка и заголовок */}
        <div
          data-handle
          className="shrink-0 pt-4 pb-3 flex flex-col items-center cursor-grab active:cursor-grabbing relative"
        >
          <div className={cn("w-12 h-1.5 rounded-full mb-5 shadow-inner transition-colors", isDark ? "bg-slate-800" : "bg-slate-200")} />

          <div className="flex items-center justify-between w-full px-8 mb-1">
            <div className="flex items-center gap-3">
               <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_8px_rgba(99,102,241,0.5)]" />
               <div>
                 <h2 className={cn("text-base font-black tracking-tight uppercase leading-none", isDark ? "text-white" : "text-slate-900")}>
                   Параметры
                 </h2>
                 <p className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em] mt-1.5">Конфигурация проекта</p>
               </div>
            </div>

            <button
              onClick={close}
              aria-label="Закрыть"
              className={cn("w-10 h-10 rounded-2xl flex items-center justify-center transition-all active:scale-90 shadow-sm border-2 border-transparent", isDark ? "bg-slate-800/50 text-slate-400 hover:text-white" : "bg-slate-100 text-slate-500 hover:bg-slate-200")}
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>

        {/* Контентная часть с прокруткой */}
        <div
          ref={contentRef}
          className="flex-1 overflow-y-auto overscroll-contain px-6 pt-2 pb-24 custom-scrollbar touch-pan-y"
        >
          <SettingsContent />
        </div>
      </div>
    </div>
  );
}