import type { RGB } from '../../config';
import { rgbToHsl, hslToRgb } from '../colorMath';
import { getLuminance, clamp01, lerp } from './mathHelpers';

/**
 * Генерирует цвет для карты цветовой температуры.
 * Тёплые цвета → оранжевый, Холодные → синий, Нейтральные → серый.
 */
export function temperatureMapColor(rgb: RGB): RGB {
  const [h, s, l] = rgbToHsl(rgb);
  const lum = getLuminance(rgb);

  if (s < 0.08) {
    const gray = Math.round(lerp(80, 200, lum / 255));
    return [gray, gray, gray];
  }

  const hueDeg = h;
  let temperature = 0;

  if (hueDeg <= 60 || hueDeg >= 300) {
    temperature = 1.0;
  } else if (hueDeg >= 150 && hueDeg <= 270) {
    temperature = -1.0;
  } else if (hueDeg > 60 && hueDeg < 150) {
    temperature = lerp(1.0, -1.0, (hueDeg - 60) / 90);
  } else if (hueDeg > 270 && hueDeg < 300) {
    temperature = lerp(-1.0, 1.0, (hueDeg - 270) / 30);
  }

  temperature *= Math.min(1, s * 2);

  const lumFactor = 1 - Math.abs(lum / 255 - 0.5) * 1.2;
  const intensity = clamp01(Math.abs(temperature) * lumFactor);
  const outL = lerp(0.25, 0.75, lum / 255);

  if (temperature > 0.05) {
    const warmHue = 25;
    const warmSat = lerp(0.3, 0.9, intensity);
    return hslToRgb(warmHue, warmSat, outL);
  } else if (temperature < -0.05) {
    const coolHue = 220;
    const coolSat = lerp(0.3, 0.9, intensity);
    return hslToRgb(coolHue, coolSat, outL);
  } else {
    const neutralHue = 120;
    const neutralSat = 0.05;
    return hslToRgb(neutralHue, neutralSat, outL);
  }
}