// src/generator/utils/worker/geometry.ts

/**
 * Упрощение ломаной линии алгоритмом Дугласа-Пекера.
 */
export function simplifyDP(pts: [number, number][], eps: number): [number, number][] {
  if (pts.length <= 2) return pts;
  const keep = new Uint8Array(pts.length);
  keep[0] = 1;
  keep[pts.length - 1] = 1;
  const stack: [number, number][] = [[0, pts.length - 1]];

  while (stack.length) {
    const [a, b] = stack.pop()!;
    if (b - a < 2) continue;

    let mx = 0;
    let mi = a;
    const [x1, y1] = pts[a];
    const [x2, y2] = pts[b];
    const ddx = x2 - x1;
    const ddy = y2 - y1;
    const len = Math.sqrt(ddx * ddx + ddy * ddy);

    for (let i = a + 1; i < b; i++) {
      const [px, py] = pts[i];
      const d = len > 0 ? Math.abs(ddy * px - ddx * py + x2 * y1 - y2 * x1) / len : Math.hypot(px - x1, py - y1);
      if (d > mx) { mx = d; mi = i; }
    }

    if (mx > eps) {
      keep[mi] = 1;
      stack.push([a, mi], [mi, b]);
    }
  }
  return pts.filter((_, i) => keep[i]);
}

/**
 * Сглаживание пути с сохранением жестких углов.
 */
export function smoothPathSmart(pts: [number, number][], iterations: number = 2, cornerThreshold: number = 0.8): [number, number][] {
  if (pts.length < 3) return pts;
  let curr = pts;
  for (let k = 0; k < iterations; k++) {
    const next: [number, number][] = [curr[0]];
    const n = curr.length;
    for (let i = 1; i < n - 1; i++) {
      const p0 = curr[i - 1], p1 = curr[i], p2 = curr[i + 1];
      const v1x = p0[0] - p1[0], v1y = p0[1] - p1[1];
      const v2x = p2[0] - p1[0], v2y = p2[1] - p1[1];
      const l1 = Math.sqrt(v1x * v1x + v1y * v1y) || 1, l2 = Math.sqrt(v2x * v2x + v2y * v2y) || 1;
      const cosA = (v1x * v2x + v1y * v2y) / (l1 * l2);
      if (cosA < cornerThreshold) {
        next.push([(p0[0] + p1[0] * 2 + p2[0]) / 4, (p0[1] + p1[1] * 2 + p2[1]) / 4]);
      } else {
        next.push([p1[0], p1[1]]);
      }
    }
    next.push(curr[n - 1]);
    curr = next;
  }
  return curr;
}

/**
 * Трассировка граней в цепочки.
 */
export function buildSmoothChains(edges: [number, number, number, number][], eps: number = 0.1, smoothIterations: number = 4): [number, number][][] {
  const adj = new Map<string, string[]>();
  const originalDegree = new Map<string, number>();

  for (const [x1, y1, x2, y2] of edges) {
    const k1 = `${x1},${y1}`;
    const k2 = `${x2},${y2}`;
    if (!adj.has(k1)) adj.set(k1, []);
    if (!adj.has(k2)) adj.set(k2, []);
    adj.get(k1)!.push(k2);
    adj.get(k2)!.push(k1);
  }

  for (const [k, nbrs] of adj) {
    originalDegree.set(k, nbrs.length);
  }

  const rawChains: [number, number][][] = [];

  for (const [k, nbrs] of adj) {
    if (originalDegree.get(k) !== 2) {
      while (adj.get(k)!.length > 0) {
        const chain: [number, number][] = [];
        let cur = k;
        chain.push(cur.split(',').map(Number) as [number, number]);

        while (true) {
          const curNbrs = adj.get(cur)!;
          if (curNbrs.length === 0) break;
          const next = curNbrs.shift()!;
          
          const nextNbrs = adj.get(next)!;
          const idx = nextNbrs.indexOf(cur);
          if (idx > -1) nextNbrs.splice(idx, 1);

          chain.push(next.split(',').map(Number) as [number, number]);

          if (originalDegree.get(next) !== 2) {
            break;
          }
          if (next === k) {
            break;
          }
          cur = next;
        }
        if (chain.length > 1) rawChains.push(chain);
      }
    }
  }

  for (const [k, nbrs] of adj) {
    while (adj.get(k)!.length > 0) {
      const chain: [number, number][] = [];
      let cur = k;
      const startKey = k;
      chain.push(cur.split(',').map(Number) as [number, number]);

      while (true) {
        const curNbrs = adj.get(cur)!;
        if (curNbrs.length === 0) break;
        const next = curNbrs.shift()!;
        
        const nextNbrs = adj.get(next)!;
        const idx = nextNbrs.indexOf(cur);
        if (idx > -1) nextNbrs.splice(idx, 1);

        chain.push(next.split(',').map(Number) as [number, number]);

        if (next === startKey) {
          break;
        }
        cur = next;
      }
      if (chain.length > 1) rawChains.push(chain);
    }
  }

  return rawChains.map(ch => smoothPathSmart(simplifyDP(ch, eps), smoothIterations));
}

/**
 * Безопасная отрисовка сглаженной линии.
 */
export function drawSmoothChain(ctx: CanvasRenderingContext2D, pts: [number, number][]): void {
  if (pts.length < 2) return;

  // Проверка на "гигантские" линии (баг орбиты)
  for (let i = 0; i < pts.length - 1; i++) {
    const dx = pts[i+1][0] - pts[i][0];
    const dy = pts[i+1][1] - pts[i][1];
    if (dx * dx + dy * dy > 40000) return; // Если прыжок больше 200px, игнорируем
  }

  ctx.beginPath();
  ctx.moveTo(pts[0][0], pts[0][1]);
  
  if (pts.length === 2) {
    ctx.lineTo(pts[1][0], pts[1][1]);
    ctx.stroke();
    return;
  }

  const n = pts.length;
  const t = 0.15;

  for (let i = 0; i < n - 1; i++) {
    const p0 = pts[i === 0 ? 0 : i - 1];
    const p1 = pts[i];
    const p2 = pts[i + 1];
    const p3 = pts[i + 2 >= n ? n - 1 : i + 2];

    const cp1x = p1[0] + (p2[0] - p0[0]) * t;
    const cp1y = p1[1] + (p2[1] - p0[1]) * t;
    const cp2x = p2[0] - (p3[0] - p1[0]) * t;
    const cp2y = p2[1] - (p3[1] - p1[1]) * t;

    ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, p2[0], p2[1]);
  }
  ctx.stroke();
}
