import { cn } from '../utils/cn';
import type { InputMode } from '../types';

export function InputModeSwitch({ mode, onChange }: { mode: InputMode; onChange: (m: InputMode) => void }) {
  return (
    <div className="flex bg-slate-100 dark:bg-slate-800/80 p-1 rounded-2xl border-2 border-slate-50 dark:border-slate-800 shadow-inner relative h-10 w-28 overflow-hidden">
      {/* Анимированная подложка */}
      <div 
        className={cn(
          "absolute inset-y-1 w-[calc(50%-4px)] bg-white dark:bg-slate-700 rounded-xl shadow-premium transition-all duration-300 ease-out z-0",
          mode === 'hex' ? "left-1" : "left-[calc(50%+2px)]"
        )}
      />
      
      <button onClick={() => onChange('hex')}
        className={cn(
          "flex-1 relative z-10 text-xs font-black uppercase tracking-[0.2em] transition-colors duration-300",
          mode === 'hex' ? "text-indigo-600 dark:text-white" : "text-slate-600 dark:text-slate-400"
        )}>
        HEX
      </button>
      <button onClick={() => onChange('rgb')}
        className={cn(
          "flex-1 relative z-10 text-xs font-black uppercase tracking-[0.2em] transition-colors duration-300",
          mode === 'rgb' ? "text-indigo-600 dark:text-white" : "text-slate-600 dark:text-slate-400"
        )}>
        RGB
      </button>
    </div>
  );
}
