import { cn } from '../../utils/cn';
import { getAccuracyInfo } from '../../utils/formatting';

export function StarsRating({ deltaE, compact }: { deltaE: number; compact?: boolean }) {
  let score: number, shadowClass: string;
  
  if (deltaE < 1) { score = 100; shadowClass = 'shadow-[0_0_12px_rgba(16,185,129,0.4)]'; }
  else if (deltaE < 2) { score = 90; shadowClass = 'shadow-[0_0_10px_rgba(52,211,153,0.3)]'; }
  else if (deltaE < 3.5) { score = 75; shadowClass = 'shadow-[0_0_10px_rgba(59,130,246,0.3)]'; }
  else if (deltaE < 6) { score = 55; shadowClass = 'shadow-[0_0_10px_rgba(245,158,11,0.2)]'; }
  else { score = 30; shadowClass = 'shadow-[0_0_10px_rgba(239,68,68,0.2)]'; }

  const accInfo = getAccuracyInfo(deltaE);
  const label = accInfo.label;
  const colorClass = accInfo.bgClass;
  const textColorClass = accInfo.colorClass;

  if (compact) {
    return (
      <div className="w-full">
        <div className="h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner">
          <div 
            className={cn("h-full transition-all duration-1000 ease-out", colorClass, shadowClass)} 
            style={{ width: `${score}%` }} 
          />
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-slate-900 rounded-xl p-3.5 sm:p-4 flex flex-col flex-1 min-w-0 border-2 border-slate-50 dark:border-slate-800 shadow-sm relative overflow-hidden group">
      <div className="absolute top-0 right-0 w-12 h-12 bg-slate-50 dark:bg-slate-800/50 rounded-bl-[1.5rem] pointer-events-none -mr-4 -mt-4" />
      
      <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-600 dark:text-slate-400 mb-2 relative z-10">Точность</div>
      
      <div className="flex flex-col gap-2 relative z-10">
        <div className="h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner">
          <div 
            className={cn("h-full transition-all duration-1000 ease-out", colorClass, shadowClass)} 
            style={{ width: `${score}%` }} 
          />
        </div>
        <div className={cn("text-xs font-black uppercase tracking-tighter", textColorClass)}>
          {label}
        </div>
      </div>
    </div>
  );
}
