// src/utils/formatting.ts
import { formatParts, formatPartsFull, type PaintProfile } from '../config';
import type { HistoryEntry } from '../types';

export function formatSmartDate(ts: number): string {
  const now = new Date();
  const d = new Date(ts);
  
  const time = d.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
  
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const target = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  
  const diffDays = Math.round((today.getTime() - target.getTime()) / 86400000);
  
  if (diffDays === 0) return `Сегодня ${time}`;
  if (diffDays === 1) return `Вчера ${time}`;
  if (diffDays < 7 && diffDays > 0) 
    return `${d.toLocaleDateString('ru-RU', { weekday: 'short' })} ${time}`;
    
  return d.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' }) + ` ${time}`;
}

export function favKey(entry: { hex: string; recipe: { name: string; parts: number }[] }): string {
  return `${entry.hex}|${entry.recipe.map(r => `${r.name}:${r.parts}`).join(',')}`;
}

export function formatRecipeText(entry: HistoryEntry, profile: PaintProfile): string {
  const lines = [
    `Melura — Рецепт`,
    `Цвет: ${entry.hex}`,
    `Краска: ${profile.name}`,
    `ΔE: ${entry.deltaE.toFixed(1)} · ${formatPartsFull(entry.totalDrops, profile)}`,
    ``,
    `Рецепт:`,
  ];

  for (const r of entry.recipe) {
    lines.push(`  ${r.name}: ${formatParts(r.parts, profile)} (${r.percent}%)`);
  }

  lines.push(``, `RGB результат: (${entry.approxRgb[0]}, ${entry.approxRgb[1]}, ${entry.approxRgb[2]})`);
  return lines.join('\n');
  }

  export function getAccuracyInfo(deltaE: number) {
  if (deltaE < 1) return { label: 'Идеально', colorClass: 'text-emerald-500', bgClass: 'bg-emerald-500', badgeClass: 'bg-emerald-50 text-emerald-600 border-emerald-100 dark:bg-emerald-500/10 dark:text-emerald-400 dark:border-emerald-500/20' };
  if (deltaE < 2) return { label: 'Высокая', colorClass: 'text-emerald-400', bgClass: 'bg-emerald-400', badgeClass: 'bg-emerald-50 text-emerald-500 border-emerald-100 dark:bg-emerald-400/10 dark:text-emerald-400 dark:border-emerald-400/20' };
  if (deltaE < 3.5) return { label: 'Хорошая', colorClass: 'text-blue-500', bgClass: 'bg-blue-500', badgeClass: 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-500/10 dark:text-blue-400 dark:border-blue-500/20' };
  if (deltaE < 6) return { label: 'Средняя', colorClass: 'text-amber-500', bgClass: 'bg-amber-500', badgeClass: 'bg-amber-50 text-amber-600 border-amber-100 dark:bg-amber-500/10 dark:text-amber-400 dark:border-amber-500/20' };
  return { label: 'Низкая', colorClass: 'text-red-500', bgClass: 'bg-red-500', badgeClass: 'bg-red-50 text-red-600 border-red-100 dark:bg-red-500/10 dark:text-red-400 dark:border-red-500/20' };
  }