// src/PWAProvider.tsx
import { ReactNode } from 'react';
import { useRegisterSW } from 'virtual:pwa-register/react';

export default function PWAProvider({ children }: { children: ReactNode }) {
  // Запускаем Service Worker в "тихом" режиме.
  // Так как в vite.config.ts стоит 'autoUpdate', он сам скачает новые файлы
  // при следующем заходе на сайт, без дополнительных окон.
  useRegisterSW({
    onRegistered(r: any) {
      console.log('Service Worker успешно зарегистрирован:', r);
    },
    onRegisterError(error: any) {
      console.error('Ошибка регистрации Service Worker:', error);
    },
  });

  return <>{children}</>;
}