// src/components/ToolButton.tsx
export function ToolButton({ icon, label, onClick, hidden, badge }: {
  icon: React.ReactNode;
  label: string; 
  onClick: () => void; 
  hidden?: boolean; 
  badge?: number;
}) {
  if (hidden) return null;
  return (
    <button onClick={onClick}
      className="w-full flex items-center gap-3 py-3 px-4 rounded-2xl text-xs font-bold text-left border-2 border-slate-50 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:border-indigo-500/30 transition-all shadow-sm active:scale-95 group min-w-0 uppercase tracking-tighter">
      <span className="text-base w-5 flex items-center justify-center shrink-0 transition-transform">{icon}</span>
      <span className="text-left flex-1 min-w-0 truncate">{label}</span>
      {badge !== undefined && badge > 0 && (
        <span className="px-2 py-0.5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-200 text-xs rounded-full font-bold shadow-inner">{badge}</span>
      )}
    </button>
  );
}