import type { RGB } from '../../config';
import { getLuminance } from './mathHelpers';

/**
 * Палитры для каждого количества уровней Нотана.
 * Цвета подобраны для хорошей читаемости на экране и при печати.
 */
export const NOTAN_PALETTES: Record<number, RGB[]> = {
  2: [
    [30, 41, 59],   // Тёмный (slate-800)
    [248, 250, 252], // Светлый (slate-50)
  ],
  3: [
    [15, 23, 42],    // Тёмный (slate-900)
    [148, 163, 184], // Средний (slate-400)
    [248, 250, 252], // Светлый (slate-50)
  ],
  4: [
    [15, 23, 42],    // Очень тёмный
    [71, 85, 105],   // Тёмно-средний (slate-600)
    [203, 213, 225], // Светло-средний (slate-300)
    [248, 250, 252], // Светлый
  ],
  5: [
    [15, 23, 42],    // 1 — Самый тёмный
    [51, 65, 85],    // 2 — Тёмный (slate-700)
    [148, 163, 184], // 3 — Средний (slate-400)
    [226, 232, 240], // 4 — Светлый (slate-200)
    [248, 250, 252], // 5 — Самый светлый
  ],
};

/**
 * Многоуровневая карта значений (Нотан).
 * Разбивает изображение на N тональных уровней.
 */
export function multiLevelNotan(rgb: RGB, levels: number, threshold: number = 128): RGB {
  const lum = getLuminance(rgb);
  const clampedLevels = Math.max(2, Math.min(5, levels));
  const palette = NOTAN_PALETTES[clampedLevels];

  if (clampedLevels === 2) {
    return lum > threshold ? palette[1] : palette[0];
  }

  const step = 256 / clampedLevels;
  const bucketIndex = Math.min(clampedLevels - 1, Math.floor(lum / step));
  return palette[bucketIndex];
}