import type { RGB, PaintProfile } from '../config';
import { rgbToLab } from '../utils/colorMath';

export function generateWarnings(
  targetRgb: RGB,
  bestDelta: number,
  profile: PaintProfile,
  usedColors: number
): string[] {
  const warnings: string[] = [];

  if (bestDelta > 15) {
    warnings.push('Этот цвет трудно получить из имеющейся палитры. Попробуйте добавить дополнительные цвета.');
  } else if (bestDelta > 8) {
    warnings.push('Приблизительный результат. Для точности расширьте палитру.');
  }

  if (usedColors > profile.maxColorsInMix) {
    warnings.push(`Рекомендуется не более ${profile.maxColorsInMix} цветов для ${profile.name.toLowerCase()}. Больше цветов — менее чистый результат.`);
  }

  const lab = rgbToLab(targetRgb);
  const chroma = Math.sqrt(lab[1] * lab[1] + lab[2] * lab[2]);

  if (chroma > 90) {
    warnings.push('Высокая насыщенность: результат в реальности может быть менее ярким.');
  }

  const max = Math.max(targetRgb[0], targetRgb[1], targetRgb[2]);
  const min = Math.min(targetRgb[0], targetRgb[1], targetRgb[2]);
  
  if (max > 240 && min < 30 && max - min > 200) {
    warnings.push('Чистый спектральный цвет: пигментные краски не могут точно воспроизвести его.');
  }

  if (profile.id === 'watercolor' && lab[0] < 25) {
    warnings.push('Очень тёмные цвета сложно получить акварелью из-за её прозрачности.');
  }

  if (profile.id === 'gouache') {
    warnings.push('Гуашь светлеет при высыхании (~5-10%). Сделайте смесь чуть темнее.');
  }

  return warnings;
}