import { useEffect, useRef } from 'react';

let isProgrammaticBack = false;

export function programmaticBack() {
  isProgrammaticBack = true;
  window.history.back();
  setTimeout(() => { isProgrammaticBack = false; }, 50);
}

export function useBackButton(isOpen: boolean, close: () => void) {
  const closeRef = useRef(close);
  closeRef.current = close;

  useEffect(() => {
    if (!isOpen) return;

    let statePushed = false;

    // Защита от накопления истории браузера (что может вызвать утечку памяти в тестах)
    const timer = setTimeout(() => {
      window.history.pushState({ modalOpen: true }, '');
      statePushed = true;
    }, 100);

    const handlePopState = () => {
      if (isProgrammaticBack) {
        isProgrammaticBack = false;
        return;
      }
      closeRef.current();
    };

    window.addEventListener('popstate', handlePopState);

    return () => {
      clearTimeout(timer);
      window.removeEventListener('popstate', handlePopState);
      if (statePushed && window.history.state?.modalOpen) {
        programmaticBack();
      }
    };
  }, [isOpen]);
}
