import type { RGB } from '../config';
import { copyToClipboard } from '../utils/clipboard';

export function CopyableHex({ hex, onCopy }: { hex: string; onCopy: (m: string) => void }) {
  return (
    <button
      onClick={async () => { const ok = await copyToClipboard(hex); onCopy(ok ? `${hex} скопирован` : 'Не удалось скопировать'); }}
      className="font-bold text-xs sm:text-sm text-slate-800 dark:text-slate-200 font-mono truncate max-w-full hover:text-blue-600 dark:hover:text-blue-400 active:scale-95 transition-all">
      {hex}
    </button>
  );
}

export function ColorBlock({ title, hex, rgb, onCopy }: { title: string; hex?: string; rgb?: RGB; onCopy: (m: string) => void }) {
  return (
    <div className="bg-white dark:bg-slate-900 rounded-2xl p-4 sm:p-5 flex-1 flex flex-col items-center gap-3 border-2 border-slate-50 dark:border-slate-800 shadow-sm relative overflow-hidden group">
      <div className="absolute top-0 left-0 w-full h-1 bg-slate-100 dark:bg-slate-800" />
      
      <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-600 dark:text-slate-400 mb-1">{title}</div>
      
      <div className="relative group/color">
        <div className="w-16 h-16 sm:w-20 sm:h-20 rounded-2xl shadow-premium border-4 border-white dark:border-slate-800 transition-transform duration-500 relative overflow-hidden"
          style={{ backgroundColor: rgb ? `rgb(${rgb})` : 'transparent' }}>
          <div className="absolute inset-0 bg-gradient-to-tr from-black/15 to-white/10" />
          {!rgb && <div className="absolute inset-0 border-4 border-dashed border-slate-300 dark:border-slate-700 rounded-2xl" />}
        </div>
      </div>

      {hex ? (
        <div className="space-y-1 text-center">
          <CopyableHex hex={hex} onCopy={onCopy} />
          <div className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">{rgb?.join(', ')}</div>
        </div>
      ) : (
        <span className="font-black text-xs text-slate-400 dark:text-slate-500 uppercase tracking-widest">—</span>
      )}
    </div>
  );
}
