// src/components/dialogs/BatchDialog.tsx
import { useState, useRef, useMemo } from 'react';
import {
  PAINT_PROFILES, formatParts,
  type ColorComponent, type EngineSettings,
} from '../../config';
import { calculateDrops, rgbToHex, type RGB, type CalculationResult } from '../../engine';
import { cn } from '../../utils/cn';
import { copyToClipboard } from '../../utils/clipboard';
import { smartParseColor } from '../../utils/colorParsing';
import { getAccuracyInfo } from '../../utils/formatting';
import type { HistoryEntry } from '../../types';
import { ModalWide } from '../ui/Modal';

export function BatchDialog({ onClose, calcColors, engineSettings, addToast, onAddHistory, onViewRecipe }: {
  onClose: () => void; calcColors: () => ColorComponent[]; engineSettings: EngineSettings;
  addToast: (m: string, t: 'success' | 'info' | 'error') => void;
  onAddHistory: (entries: HistoryEntry[]) => void; onViewRecipe: (e: HistoryEntry) => void;
}) {
  const profile = PAINT_PROFILES[engineSettings.paintType];
  const [input, setInput] = useState('');
  const [entries, setEntries] = useState<{ id: string; input: string; parsed: { rgb: RGB; hex: string } | null; result?: CalculationResult; status: 'pending' | 'calculating' | 'done' | 'error' }[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const cancelRef = useRef(false);

  const parseInput = () => {
    const lines = input.split('\n').map(l => l.trim()).filter(Boolean);
    setEntries(lines.map((line, idx) => ({
      id: `${Date.now()}-${idx}`,
      input: line,
      parsed: smartParseColor(line),
      status: 'pending' as const
    })));
  };

  const runBatch = async () => {
    const valid = entries.filter(e => e.parsed);
    if (valid.length === 0) { addToast('Нет корректных цветов', 'error'); return; }
    cancelRef.current = false;
    setIsRunning(true);
    const comps = calcColors();
    setProgress({ current: 0, total: valid.length });
    const newEntries = [...entries];
    const historyEntries: HistoryEntry[] = [];
    let doneCount = 0;
    for (let i = 0; i < newEntries.length; i++) {
      if (cancelRef.current) break;
      const e = newEntries[i];
      if (!e.parsed) continue;
      newEntries[i] = { ...e, status: 'calculating' };
      setEntries([...newEntries]);
      try {
        const res = await calculateDrops(e.parsed.rgb, comps, engineSettings, () => { });
        newEntries[i] = { ...e, result: res, status: 'done' };
        const best = res.variants[0];
        if (best) {
          historyEntries.push({
            id: Date.now() + i, hex: res.targetHex, rgb: res.targetRgb,
            approxRgb: best.approxRgb, deltaE: best.deltaE,
            totalDrops: best.totalDrops, timestamp: Date.now(),
            variantLabel: best.label, paintType: engineSettings.paintType,
            recipe: best.recipe,
          });
        }
        doneCount++;
      } catch { newEntries[i] = { ...e, status: 'error' }; }
      setProgress({ current: doneCount, total: valid.length });
      setEntries([...newEntries]);
    }
    if (historyEntries.length > 0) onAddHistory(historyEntries);
    setIsRunning(false);
    if (cancelRef.current) addToast(`Отменено. Рассчитано ${doneCount} рецептов.`, 'info');
    else addToast(`Рассчитано ${doneCount} рецептов!`, 'success');
  };

  const cancelBatch = () => { cancelRef.current = true; };

  const exportAll = async () => {
    const done = entries.filter(e => e.status === 'done' && e.result);
    if (done.length === 0) return;
    const lines: string[] = [`Melura — Пакетный расчёт (${profile.name})`, ''];
    for (const e of done) {
      const r = e.result!; const best = r.variants[0];
      if (!best) continue;
      lines.push(`═══ ${r.targetHex} (ΔE ${best.deltaE.toFixed(1)}) ═══`);
      best.recipe.forEach(item => { lines.push(`  ${item.name}: ${formatParts(item.parts, profile)} (${item.percent}%)`); });
      lines.push('');
    }
    const ok = await copyToClipboard(lines.join('\n'));
    addToast(ok ? 'Все рецепты скопированы!' : 'Не удалось скопировать', ok ? 'success' : 'error');
  };

  const viewBatchRecipe = (e: typeof entries[0]) => {
    if (!e.result || !e.parsed) return;
    const res = e.result; const best = res.variants[0];
    if (!best) return;
    onViewRecipe({
      id: Date.now(), hex: res.targetHex, rgb: res.targetRgb,
      approxRgb: best.approxRgb, deltaE: best.deltaE,
      totalDrops: best.totalDrops, timestamp: Date.now(),
      variantLabel: best.label, paintType: engineSettings.paintType,
      recipe: best.recipe,
    });
  };

  const validCount = entries.filter(e => e.parsed).length;
  const doneCount = entries.filter(e => e.status === 'done').length;

  return (
    <ModalWide onClose={onClose} zClass="z-[70]">
      <div className="px-5 pt-4 sm:pt-5 pb-4 border-b border-slate-200/50 dark:border-slate-800/50 flex flex-col shrink-0">
        <div className="flex items-center justify-between mb-1">
          <div className="flex items-center gap-2.5">
            <span className="text-indigo-500 bg-indigo-50 dark:bg-indigo-500/10 p-1.5 rounded-lg shrink-0">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M3 3v18h18" /><path d="m19 9-5 5-4-4-3 3" />
              </svg>
            </span>
            <h2 className="text-base sm:text-lg font-bold text-slate-900 dark:text-white truncate">Пакетный расчёт</h2>
          </div>
          <div className="flex items-center gap-1">
            {doneCount > 0 && (
              <button onClick={exportAll} className="w-10 h-10 rounded-full flex items-center justify-center text-indigo-600 bg-indigo-50 dark:bg-indigo-900/20 hover:bg-indigo-100 transition-all border border-indigo-100 dark:border-indigo-900/30" title="Копировать всё">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
              </button>
            )}
            <button onClick={onClose} className="w-10 h-10 -mr-2 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" aria-label="Закрыть">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
        <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 ml-9">
          Обработка списка цветов ({profile.name})
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-5 space-y-6 custom-scrollbar">
        {entries.length === 0 ? (
          <div className="space-y-4 animate-fade-in">
            <div className="bg-slate-50 dark:bg-indigo-500/5 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl p-8 text-center">
              <div className="w-16 h-16 bg-white dark:bg-slate-800 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-sm border border-slate-100 dark:border-slate-700">
                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="text-indigo-500"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>
              </div>
              <p className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-[0.15em] leading-relaxed">
                Введите HEX, RGB или названия<br/>по одному на каждой строке
              </p>
            </div>
            
            <textarea value={input} onChange={e => setInput(e.target.value)}
              placeholder={"#FF5733\n255, 128, 64\nsky blue\nrgb(100, 200, 50)"}
              rows={8} className="w-full px-5 py-5 rounded-2xl border-2 border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-900 dark:text-white text-sm font-mono font-bold focus:outline-none focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/10 shadow-premium transition-all resize-none" />
            
            <button onClick={parseInput} disabled={!input.trim()}
              className="w-full py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] text-white bg-indigo-600 hover:bg-indigo-700 disabled:opacity-30 transition-all shadow-lg shadow-indigo-600/20 active:scale-[0.98]">
              Распознать список
            </button>
          </div>
        ) : (
          <div className="space-y-5 animate-fade-in">
            <div className="flex items-center justify-between px-1">
              <div className="flex items-center gap-2">
                 <span className="text-xs font-black uppercase tracking-widest text-slate-400">Найдено:</span>
                 <span className="px-2 py-0.5 rounded-md bg-indigo-50 dark:bg-indigo-500/10 text-xs font-black text-indigo-600 dark:text-indigo-400 tabular-nums">{validCount} / {entries.length}</span>
              </div>
              <button onClick={() => { setEntries([]); setInput(''); }} className="text-xs font-black uppercase tracking-widest text-slate-400 hover:text-indigo-500 flex items-center gap-1.5 transition-colors">
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="m15 18-6-6 6-6"/></svg>
                Назад
              </button>
            </div>

            {isRunning && (
              <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm space-y-3">
                <div className="flex justify-between items-end">
                   <div className="flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" />
                      <span className="text-xs font-black uppercase tracking-widest text-indigo-600 dark:text-indigo-400">Идет расчёт...</span>
                   </div>
                   <div className="text-xs font-black font-mono text-indigo-500">{Math.round((progress.current / progress.total) * 100)}%</div>
                </div>
                <div className="h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner">
                  <div className="h-full bg-gradient-to-r from-indigo-500 to-blue-500 transition-[width] duration-300 ease-out" style={{ width: `${progress.total > 0 ? (progress.current / progress.total) * 100 : 0}%` }} />
                </div>
              </div>
            )}

            <div className="space-y-3">
              {entries.map((e) => {
                const best = e.result?.variants[0];
                const dE = best?.deltaE ?? e.result?.deltaE;
                return (
                  <button key={e.id} onClick={() => e.status === 'done' && viewBatchRecipe(e)} disabled={e.status !== 'done'}
                    className={cn("w-full group relative flex items-center gap-4 p-4 rounded-2xl border-2 transition-all text-left overflow-hidden",
                      !e.parsed ? "border-red-50 dark:border-red-950/20 bg-red-50/30 dark:bg-red-950/10 opacity-60" :
                      e.status === 'done' ? "border-white dark:border-slate-800 bg-white dark:bg-slate-900 hover:border-indigo-400 active:scale-[0.98] shadow-sm" :
                      "border-indigo-100 dark:border-indigo-900/30 bg-indigo-50/30 dark:bg-indigo-900/10")}>
                    
                    {e.parsed ? (
                       <div className="flex -space-x-2 shrink-0">
                          <div className="w-12 h-12 rounded-xl border-2 border-white dark:border-slate-800 shadow-sm relative z-10" style={{ backgroundColor: e.parsed.hex }} />
                          {e.status === 'done' && e.result && (
                             <div className="w-12 h-12 rounded-xl border-2 border-white dark:border-slate-800 shadow-sm relative z-0" style={{ backgroundColor: rgbToHex(best?.approxRgb || e.result.approxRgb) }} />
                          )}
                       </div>
                    ) : (
                       <div className="w-12 h-12 rounded-xl border-2 border-dashed border-red-200 dark:border-red-900/50 flex items-center justify-center text-red-300">✕</div>
                    )}

                    <div className="flex-1 min-w-0">
                      <div className="text-xs font-black font-mono text-slate-800 dark:text-slate-100 truncate uppercase tracking-tighter leading-none mb-1.5">{e.input}</div>
                      {!e.parsed ? (
                        <div className="text-xs font-black text-red-500 uppercase tracking-widest">Не распознан</div>
                      ) : e.status === 'done' && dE !== undefined ? (
                        <div className="flex items-center gap-2">
                           <span className={cn("px-1.5 py-0.5 rounded-md text-xs font-black tabular-nums border", 
                             getAccuracyInfo(dE).badgeClass)}>
                             ΔE {dE.toFixed(1)}
                           </span>
                           <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">Нажмите для рецепта</span>
                        </div>
                      ) : e.status === 'calculating' ? (
                        <div className="text-xs font-black text-indigo-500 uppercase tracking-widest animate-pulse">Идет анализ...</div>
                      ) : (
                        <div className="text-xs font-black text-slate-400 uppercase tracking-widest">В очереди</div>
                      )}
                    </div>

                    {e.status === 'done' && (
                       <div className="text-slate-300 group-hover:text-indigo-400 transition-colors shrink-0">
                          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="m9 18 6-6-6-6"/></svg>
                       </div>
                    )}
                  </button>
                );
              })}
            </div>

            {!isRunning && doneCount === 0 && validCount > 0 && (
              <button onClick={runBatch} className="w-full py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] text-white bg-indigo-600 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20 active:scale-[0.98] flex items-center justify-center gap-3">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M10 2v7.31"/><path d="M14 9.3V1.99"/><path d="M8.5 2h7"/><path d="M14 9.3a6.5 6.5 0 1 1-4 0"/><path d="M5.52 16h12.96"/></svg>
                Запустить расчёт
              </button>
            )}

            {isRunning && (
              <button onClick={cancelBatch} className="w-full py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] text-red-500 bg-red-50 dark:bg-red-950/30 border-2 border-red-100 dark:border-red-900/30 transition-all active:scale-[0.98]">
                Остановить
              </button>
            )}
          </div>
        )}
      </div>
    </ModalWide>
  );
}
