// src/generator/components/CropModal.tsx
import { useEffect, useRef, useState, useCallback } from "react";
import { useAppStore } from "../store";
import { useBackButton } from "../../hooks/useBackButton";
import { cn } from "../../utils/cn";
import { profileImageQuick } from "../utils/imageProcessing/profiler";

export function CropModal() {
  const isDark = useAppStore((s) => s.isDark);
  const isOpen = useAppStore((s) => s.cropModalOpen);

  const originalImageUrl = useAppStore((s) => s.originalImageUrl);
  const imageDimensions = useAppStore((s) => s.imageDimensions);

  const update = useAppStore((s) => s.update);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [crop, setCrop] = useState({ x: 0, y: 0, w: 100, h: 100 });
  const [scale, setScale] = useState(1);

  const dragRef = useRef<{
    type: string;
    sx: number;
    sy: number;
    cx: number;
    cy: number;
    cw: number;
    ch: number;
  } | null>(null);

  useEffect(() => {
    if (!isOpen || !originalImageUrl || !imageDimensions || !canvasRef.current || !containerRef.current) {
      return;
    }

    const { w: imgW, h: imgH } = imageDimensions;

    const img = new Image();
    img.src = originalImageUrl;
    img.onload = () => {
      const c = canvasRef.current;
      if (!c) return;

      const ctx = c.getContext("2d");
      if (!ctx) return;

      c.width = imgW;
      c.height = imgH;
      ctx.drawImage(img, 0, 0);

      const cont = containerRef.current;
      if (!cont) return;

      const maxW = cont.clientWidth - 32;
      const maxH = cont.clientHeight - 160;
      const s = Math.min(1, maxW / imgW, maxH / imgH);

      setScale(s);
      setCrop({ x: 0, y: 0, w: imgW, h: imgH });
    };
  }, [isOpen, originalImageUrl, imageDimensions]);

  const close = useCallback(() => update({ cropModalOpen: false }), [update]);

  useBackButton(isOpen, close);

  const applyCrop = useCallback(() => {
    if (!originalImageUrl || !imageDimensions) return;

    const { x, y, w, h } = crop;
    const rx = Math.max(0, Math.round(x));
    const ry = Math.max(0, Math.round(y));
    const rw = Math.min(imageDimensions.w - rx, Math.round(w));
    const rh = Math.min(imageDimensions.h - ry, Math.round(h));

    if (rw < 10 || rh < 10) return;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = originalImageUrl;

    img.onload = () => {
      const c = document.createElement("canvas");
      c.width = rw;
      c.height = rh;
      const ctx = c.getContext("2d")!;
      ctx.drawImage(img, rx, ry, rw, rh, 0, 0, rw, rh);
      
      const imageData = ctx.getImageData(0, 0, rw, rh);
      const profile = profileImageQuick(imageData.data, rw, rh);

      c.toBlob((blob) => {
        if (!blob) return;

        const newUrl = URL.createObjectURL(blob);
        const s = useAppStore.getState();

        if (s.originalImageUrl && s.originalImageUrl.startsWith("blob:")) {
          URL.revokeObjectURL(s.originalImageUrl);
        }
        if (s.correctedImageUrl && s.correctedImageUrl.startsWith("blob:")) {
          URL.revokeObjectURL(s.correctedImageUrl);
        }

        update({
          originalImageUrl: newUrl,
          imageDimensions: { w: rw, h: rh },
          imageProfile: profile,
          correctedImageUrl: null,
          result: null,
          cropModalOpen: false,
          statusMsg: `Обрезано: ${rw}×${rh}`,

          // важное: сбрасываем только текущее отображение,
          // а режимы сохраняют свои собственные настройки отдельно
          viewTransform: { x: 0, y: 0, z: 1, splitPos: 0.5 },

          mobilePaletteExpanded: false,
          zoneGuideActive: false,
          showTemperatureMap: false,
          artisticSplitMode: false,
          selectedZoneId: null,
          zoneInfoVisible: false,
          flipHorizontal: false,
        });
      }, "image/webp", 0.95);
    };
  }, [originalImageUrl, imageDimensions, crop, update]);

  const onPointerDown = useCallback((e: React.PointerEvent, type: string) => {
    e.preventDefault();
    e.stopPropagation();
    (e.target as HTMLElement).setPointerCapture(e.pointerId);

    dragRef.current = {
      type,
      sx: e.clientX,
      sy: e.clientY,
      cx: crop.x,
      cy: crop.y,
      cw: crop.w,
      ch: crop.h,
    };
  }, [crop]);

  const onPointerMove = useCallback((e: React.PointerEvent) => {
    if (!dragRef.current || !imageDimensions) return;

    const d = dragRef.current;
    const dx = (e.clientX - d.sx) / scale;
    const dy = (e.clientY - d.sy) / scale;

    setCrop((prev) => {
      let { x, y, w, h } = prev;
      const minS = 20;

      switch (d.type) {
        case "move":
          x = Math.max(0, Math.min(imageDimensions.w - d.cw, d.cx + dx));
          y = Math.max(0, Math.min(imageDimensions.h - d.ch, d.cy + dy));
          w = d.cw;
          h = d.ch;
          break;

        case "tl":
          x = Math.min(d.cx + d.cw - minS, d.cx + dx);
          y = Math.min(d.cy + d.ch - minS, d.cy + dy);
          w = d.cx + d.cw - x;
          h = d.cy + d.ch - y;
          break;

        case "tr":
          y = Math.min(d.cy + d.ch - minS, d.cy + dy);
          w = Math.max(minS, d.cw + dx);
          h = d.cy + d.ch - y;
          x = d.cx;
          break;

        case "bl":
          x = Math.min(d.cx + d.cw - minS, d.cx + dx);
          w = d.cx + d.cw - x;
          h = Math.max(minS, d.ch + dy);
          y = d.cy;
          break;

        case "br":
          w = Math.max(minS, d.cw + dx);
          h = Math.max(minS, d.ch + dy);
          x = d.cx;
          y = d.cy;
          break;
      }

      x = Math.max(0, x);
      y = Math.max(0, y);
      w = Math.min(imageDimensions.w - x, w);
      h = Math.min(imageDimensions.h - y, h);

      return { x, y, w, h };
    });
  }, [scale, imageDimensions]);

  const onPointerUp = useCallback(() => {
    dragRef.current = null;
  }, []);

  if (!isOpen || !originalImageUrl || !imageDimensions) return null;

  const cStyle = {
    left: crop.x * scale,
    top: crop.y * scale,
    width: crop.w * scale,
    height: crop.h * scale,
  };

  const handleCls =
    "absolute w-5 h-5 sm:w-4 sm:h-4 rounded-full bg-white border-2 border-indigo-500 shadow-lg z-10 cursor-pointer touch-none";

  return (
    <div
      className="fixed inset-0 z-[110] flex items-center justify-center p-4 sm:p-6 pt-[max(1rem,env(safe-area-inset-top))] touch-none"
      role="dialog"
      aria-modal="true"
      aria-label="Обрезка изображения"
    >
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={close} />

      <div
        ref={containerRef}
        className={cn(
          "relative z-10 w-full h-full max-w-4xl max-h-[90dvh] rounded-2xl shadow-premium flex flex-col overflow-hidden animate-fade-in-up",
          isDark ? "bg-slate-900 border border-white/10" : "bg-white border border-black/5"
        )}
      >
        <div className={cn("flex flex-col px-6 pt-5 pb-4 border-b shrink-0", isDark ? "border-white/10" : "border-black/5")}>
          <div className="flex items-center justify-between mb-1">
            <div className="flex items-center gap-2.5">
               <div className={cn("p-1.5 rounded-xl", isDark ? "bg-slate-800 text-indigo-400" : "bg-indigo-50 text-indigo-600")}>
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M6.13 1L6 16a2 2 0 0 0 2 2h15" /><path d="M1 6.13L16 6a2 2 0 0 1 2 2v15" />
                  </svg>
               </div>
               <h2 className={cn("text-base sm:text-lg font-bold", isDark ? "text-white" : "text-slate-900")}>
                 Обрезка фото
               </h2>
            </div>
            
            <div className="flex items-center gap-2">
              <button onClick={close} className={cn(
                "px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all active:scale-95",
                isDark ? "bg-slate-800 text-slate-400 hover:text-white" : "bg-slate-100 text-slate-500 hover:bg-slate-200"
              )} aria-label="Закрыть">
                Отмена
              </button>
              <button onClick={applyCrop} className="px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest bg-indigo-600 text-white shadow-lg shadow-indigo-600/25 hover:bg-indigo-700 transition-all active:scale-95">
                Готово
              </button>
            </div>
          </div>
          <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 dark:text-slate-400 ml-10">
             Выберите область для анализа цвета
          </div>
        </div>

        <div
          className="flex-1 flex items-center justify-center p-6 sm:p-10 overflow-hidden bg-slate-50/30 dark:bg-black/20"
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          onPointerCancel={onPointerUp}
        >
          <div className="relative shadow-2xl transition-transform duration-300" style={{ width: imageDimensions.w * scale, height: imageDimensions.h * scale }}>
            <canvas
              ref={canvasRef}
              className="block rounded-lg"
              style={{ width: imageDimensions.w * scale, height: imageDimensions.h * scale }}
            />

            {/* Затемнение */}
            <div className="absolute inset-0 bg-black/60 pointer-events-none rounded-lg" />
            <div
              className="absolute pointer-events-none rounded-lg"
              style={{
                ...cStyle,
                backgroundColor: "transparent",
                boxShadow: "0 0 0 9999px rgba(0,0,0,0.4)",
                zIndex: 5,
              }}
            />

            {/* Рамка crop */}
            <div
              className="absolute border-2 border-white cursor-move touch-none shadow-[0_0_20px_rgba(0,0,0,0.3)]"
              style={{ ...cStyle, zIndex: 6 }}
              onPointerDown={(e) => onPointerDown(e, "move")}
            >
              <div className="absolute inset-0 pointer-events-none">
                <div className="absolute left-1/3 top-0 bottom-0 w-px bg-white/40" />
                <div className="absolute left-2/3 top-0 bottom-0 w-px bg-white/40" />
                <div className="absolute top-1/3 left-0 right-0 h-px bg-white/40" />
                <div className="absolute top-2/3 left-0 right-0 h-px bg-white/40" />
              </div>

              <div className="absolute -top-10 left-1/2 -translate-x-1/2 px-3 py-1 rounded-full bg-black/80 backdrop-blur-md text-white text-xs font-black tracking-widest whitespace-nowrap shadow-xl border border-white/10">
                {Math.round(crop.w)} × {Math.round(crop.h)}
              </div>
            </div>

            {/* Угловые маркеры */}
            <div className={cn(handleCls, "w-6 h-6 border-4 border-indigo-600 bg-white")} style={{ left: crop.x * scale - 12, top: crop.y * scale - 12, zIndex: 10 }} onPointerDown={(e) => onPointerDown(e, "tl")} />
            <div className={cn(handleCls, "w-6 h-6 border-4 border-indigo-600 bg-white")} style={{ left: (crop.x + crop.w) * scale - 12, top: crop.y * scale - 12, zIndex: 10 }} onPointerDown={(e) => onPointerDown(e, "tr")} />
            <div className={cn(handleCls, "w-6 h-6 border-4 border-indigo-600 bg-white")} style={{ left: crop.x * scale - 12, top: (crop.y + crop.h) * scale - 12, zIndex: 10 }} onPointerDown={(e) => onPointerDown(e, "bl")} />
            <div className={cn(handleCls, "w-6 h-6 border-4 border-indigo-600 bg-white")} style={{ left: (crop.x + crop.w) * scale - 12, top: (crop.y + crop.h) * scale - 12, zIndex: 10 }} onPointerDown={(e) => onPointerDown(e, "br")} />
          </div>
        </div>
      </div>
    </div>
  );
}