import { useState } from 'react';
import { cn } from '../../utils/cn';
import type { ColorInfo } from '../../types';
import { useIsMobile } from '../../hooks/useIsMobile';
import { Modal } from '../ui/Modal';
import { ColorCircle } from '../ui/ColorCircle';

export function PaletteDialog({ colorInfos, selectedNames, onToggleColor, onToggleAll, onFullReset, onClose, onEdit, onAdd, onDelete, onRestoreBuiltIn }: {
  colorInfos: ColorInfo[]; selectedNames: Set<string>; onToggleColor: (n: string) => void;
  onToggleAll: (s: boolean) => void; onFullReset: () => void; onClose: () => void;
  onEdit: (i: ColorInfo) => void; onAdd: () => void; onDelete: (i: ColorInfo) => void;
  onRestoreBuiltIn: (k: string) => void;
}) {
  const [search, setSearch] = useState('');
  const norm = (t: string) => t.toLowerCase().replace(/ё/g, 'е');
  const filtered = colorInfos.filter(ci => norm(ci.color.name).includes(norm(search)));
  const allSelected = colorInfos.length > 0 && colorInfos.every(ci => selectedNames.has(ci.color.name));
  const someSelected = colorInfos.some(ci => selectedNames.has(ci.color.name));
  const noneSelected = selectedNames.size === 0;

  return (
    <Modal onClose={onClose} zClass="z-[70]">
      <div className="px-5 pt-4 sm:pt-5 pb-4 border-b border-slate-200/50 dark:border-slate-800/50 flex flex-col shrink-0">
        <div className="flex items-center justify-between mb-1">
          <div className="flex items-center gap-2.5">
            <span className="text-indigo-500 bg-indigo-50 dark:bg-indigo-500/10 p-1.5 rounded-lg shrink-0">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="13.5" cy="6.5" r=".5" fill="currentColor" /><circle cx="17.5" cy="10.5" r=".5" fill="currentColor" /><circle cx="8.5" cy="7.5" r=".5" fill="currentColor" /><circle cx="6.5" cy="12.5" r=".5" fill="currentColor" /><path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10c.926 0 1.648-.746 1.648-1.688 0-.437-.18-.835-.437-1.125-.29-.289-.438-.652-.438-1.125a1.64 1.64 0 0 1 1.668-1.668h1.996c3.051 0 5.555-2.503 5.555-5.554C21.965 6.012 17.461 2 12 2z" />
              </svg>
            </span>
            <h2 className="text-base sm:text-lg font-bold text-slate-900 dark:text-white truncate">Палитра красок</h2>
          </div>
          <div className="flex items-center gap-1">
            <button onClick={onAdd} className="w-10 h-10 rounded-full flex items-center justify-center text-indigo-600 bg-indigo-50 dark:bg-indigo-500/10 hover:bg-indigo-100 transition-all border border-indigo-100 dark:border-indigo-900/30" title="Добавить цвет" aria-label="Добавить новый цвет">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></svg>
            </button>
            <button onClick={onClose} className="w-10 h-10 -mr-2 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" aria-label="Закрыть палитру">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
        <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 dark:text-slate-400 ml-9 mb-4">
          Управление вашим набором цветов
        </div>

        <div className="relative group">
          <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
             <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
          </div>
          <input type="text" value={search} onChange={e => setSearch(e.target.value)} placeholder="Найти краску..."
            className="w-full pl-11 pr-4 py-3 rounded-2xl border-2 border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-900 dark:text-white text-sm font-bold focus:outline-none focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/10 transition-all" />
        </div>
      </div>

      <div className="flex items-center justify-between px-5 py-2.5 bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800">
        <button 
          onClick={() => onToggleAll(!allSelected)}
          className="flex items-center gap-3 cursor-pointer group"
        >
          <div className="relative flex-shrink-0">
            <div className={cn(
              "w-5 h-5 rounded-md border-2 transition-all flex items-center justify-center",
              allSelected ? "bg-indigo-600 border-indigo-600 shadow-lg shadow-indigo-500/30" : "border-slate-200 dark:border-slate-700"
            )}>
               {allSelected ? <svg className="w-3.5 h-3.5 text-white animate-fade-in transition-transform duration-300 ease-out" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg> : someSelected && <div className="w-2.5 h-0.5 bg-slate-400 rounded-full" />}
            </div>
          </div>
          <span className="text-xs font-black uppercase tracking-widest text-slate-600 dark:text-slate-400 group-hover:text-indigo-500 transition-colors">Выбрать все</span>
        </button>
        
        <button onClick={onFullReset} className="text-xs font-black uppercase tracking-widest text-slate-500 hover:text-red-500 transition-colors flex items-center gap-1.5">
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" /><path d="M3 3v5h5" /></svg>
          Сброс
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
        {noneSelected && (
          <div className="mb-4 p-3 rounded-2xl bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-800/50 flex items-start gap-3">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-amber-500 shrink-0 mt-0.5"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
            <p className="text-xs font-bold text-amber-700 dark:text-amber-300 leading-relaxed uppercase tracking-tight">Ни одна краска не выбрана. При подборе будут использованы базовые цвета.</p>
          </div>
        )}

        <div className="grid grid-cols-1 xs:grid-cols-2 gap-2 px-0.5">
          {filtered.map(ci => {
            const isSelected = selectedNames.has(ci.color.name);
            return (
              <div key={ci.builtInKey || ci.color.name} 
                onClick={() => onToggleColor(ci.color.name)}
                className={cn(
                  "group relative flex items-center gap-3 p-3 rounded-2xl border-2 transition-all cursor-pointer active:scale-[0.97]",
                  isSelected
                    ? "border-indigo-600 bg-white dark:bg-slate-900 shadow-sm"
                    : "border-slate-50 dark:border-slate-800/50 bg-white dark:bg-slate-900 hover:border-slate-200 dark:hover:border-slate-700 shadow-none"
                )}>
                
                <div className="relative z-10 w-10 h-10 rounded-xl border-2 border-white dark:border-slate-800 shadow-sm shrink-0 overflow-hidden" style={{ backgroundColor: `rgb(${ci.color.rgb})` }}>
                   <div className="absolute inset-0 bg-gradient-to-tr from-black/10 to-white/10" />
                   {isSelected && (
                     <div className="absolute inset-0 flex items-center justify-center bg-black/10 animate-fade-in">
                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="5"><polyline points="20 6 9 17 4 12"/></svg>
                     </div>
                   )}
                </div>

                <div className="relative z-10 flex-1 min-w-0">
                  <div className="text-xs font-black text-slate-800 dark:text-slate-200 truncate uppercase tracking-tighter leading-tight">{ci.color.name}</div>
                  <div className="flex items-center gap-1.5 mt-1">
                     {ci.isCustom && <span className="text-xs font-black bg-blue-100 dark:bg-blue-500/20 text-blue-600 dark:text-blue-400 px-1.5 py-0.5 rounded uppercase tracking-tighter">Свой</span>}
                     {ci.isOverridden && <span className="text-xs font-black bg-amber-100 dark:bg-amber-500/20 text-amber-600 dark:text-amber-400 px-1.5 py-0.5 rounded uppercase tracking-tighter">Правка</span>}
                  </div>
                </div>

                <div className="relative z-20 flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity" onClick={e => e.stopPropagation()}>
                  {ci.isOverridden && ci.builtInKey && (
                    <button onClick={() => onRestoreBuiltIn(ci.builtInKey!)} className="w-8 h-8 rounded-lg flex items-center justify-center hover:bg-amber-100 dark:hover:bg-amber-950 text-amber-500 transition-colors" title="Сбросить изменения" aria-label="Сбросить изменения">
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" /><path d="M3 3v5h5" /></svg>
                    </button>
                  )}
                  <button onClick={() => onEdit(ci)} className="w-8 h-8 rounded-lg flex items-center justify-center hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-500 dark:text-slate-400 transition-colors" title="Редактировать" aria-label="Редактировать">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" /><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" /></svg>
                  </button>
                  <button onClick={() => onDelete(ci)} className="w-8 h-8 rounded-lg flex items-center justify-center hover:bg-red-50 dark:hover:bg-red-950 text-red-500 dark:text-red-400 transition-colors" title="Удалить" aria-label="Удалить">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 6h18" /><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                  </button>
                </div>
              </div>
            );
          })}
        </div>
        {filtered.length === 0 && (
          <div className="py-20 text-center opacity-30">
             <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" className="mx-auto mb-3"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
             <p className="text-sm font-bold uppercase tracking-widest text-slate-600 dark:text-slate-400">Ничего не найдено</p>
          </div>
        )}
      </div>
    </Modal>
  );
}
