// src/generator/components/SmoothSlider.tsx
import { useRef, useCallback, useState, useEffect } from "react";
import { cn } from "../../utils/cn";
import { useAppStore } from "../store";

export function SmoothSlider({
  label,
  storeValue,
  defaultValue,
  min,
  max,
  step,
  onCommit,
  onDragEnd,
  suffix = "",
  showSign = false,
  compact = false,
  disabled = false,
  isDark,
}: {
  label: string;
  storeValue: number;
  defaultValue: number;
  min: number;
  max: number;
  step?: number;
  onCommit: (v: number) => void;
  onDragEnd?: () => void;
  suffix?: string;
  showSign?: boolean;
  compact?: boolean;
  disabled?: boolean;
  isDark?: boolean;
}) {
  const [localValue, setLocalValue] = useState(storeValue);
  const isDragging = useRef(false);
  const isScrolling = useRef(false);
  const startPos = useRef<{ x: number, y: number } | null>(null);
  const commitTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!isDragging.current) {
      setLocalValue(storeValue);
    }
  }, [storeValue]);

  const handleMove = useCallback((clientX: number, rect: DOMRect) => {
    const padding = 10;
    const percent = Math.max(0, Math.min(1, (clientX - rect.left - padding) / (rect.width - padding * 2)));
    const rawValue = percent * (max - min) + min;
    const steppedValue = step ? Math.round(rawValue / step) * step : Math.round(rawValue);
    const finalValue = Math.max(min, Math.min(max, steppedValue));
    
    setLocalValue(finalValue);
    if (commitTimer.current) clearTimeout(commitTimer.current);
    commitTimer.current = setTimeout(() => onCommit(finalValue), 60);
  }, [min, max, step, onCommit]);

  const onTouchStart = (e: React.TouchEvent) => {
    if (disabled) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const startX = e.touches[0].clientX;
    const startY = e.touches[0].clientY;
    let isSliding = false;
    let isScrolling = false;

    const move = (te: TouchEvent) => {
      if (isScrolling) return;
      const currentX = te.touches[0].clientX;
      const currentY = te.touches[0].clientY;
      const dx = Math.abs(currentX - startX);
      const dy = Math.abs(currentY - startY);

      if (!isSliding && !isScrolling) {
        if (dy > dx && dy > 8) { isScrolling = true; return; }
        if (dx > 8 || dx > dy) { 
          isSliding = true; 
          isDragging.current = true;
          useAppStore.getState().update({ isInteracting: true });
        }
      }

      if (isSliding) {
        if (te.cancelable) te.preventDefault();
        te.stopPropagation();
        handleMove(currentX, rect);
      }
    };

    const end = () => {
      if (isSliding) {
        isDragging.current = false;
        useAppStore.getState().update({ isInteracting: false });
        onDragEnd?.();
      }
      document.removeEventListener("touchmove", move);
      document.removeEventListener("touchend", end);
    };

    document.addEventListener("touchmove", move, { passive: false });
    document.addEventListener("touchend", end);
  };

  const onMouseDown = (e: React.MouseEvent<HTMLDivElement>) => {
    if (disabled) return;
    const rect = e.currentTarget.getBoundingClientRect();
    isDragging.current = true;
    useAppStore.getState().update({ isInteracting: true });
    handleMove(e.clientX, rect);

    const move = (me: MouseEvent) => {
      handleMove(me.clientX, rect);
    };

    const up = () => {
      isDragging.current = false;
      useAppStore.getState().update({ isInteracting: false });
      onDragEnd?.();
      document.removeEventListener("mousemove", move);
      document.removeEventListener("mouseup", up);
    };

    document.addEventListener("mousemove", move);
    document.addEventListener("mouseup", up);
  };

  const onKeyDown = (e: React.KeyboardEvent) => {
    if (disabled) return;
    let nextValue = localValue;
    const delta = step ?? 1;
    if (e.key === "ArrowLeft" || e.key === "ArrowDown") nextValue -= delta;
    else if (e.key === "ArrowRight" || e.key === "ArrowUp") nextValue += delta;
    else if (e.key === "Home") nextValue = min;
    else if (e.key === "End") nextValue = max;
    else return;

    e.preventDefault();
    nextValue = Math.max(min, Math.min(max, nextValue));
    setLocalValue(nextValue);
    onCommit(nextValue);
  };

  const handleReset = useCallback(() => {
    if (disabled) return;
    setLocalValue(defaultValue);
    useAppStore.getState().update({ isInteracting: false });
    if (commitTimer.current) clearTimeout(commitTimer.current);
    onCommit(defaultValue);
    onDragEnd?.();
  }, [defaultValue, onCommit, onDragEnd, disabled]);

  const displayValue =
    step && step < 1
      ? (showSign && localValue > 0 ? "+" : "") + localValue.toFixed(1)
      : (showSign && localValue > 0 ? "+" : "") + String(localValue);

  const hasChanged = localValue !== defaultValue;
  const pct = ((localValue - min) / (max - min)) * 100;

  return (
    <div className={cn("space-y-1", compact ? "mb-2" : "mb-3", disabled && "opacity-40 pointer-events-none grayscale transition-opacity duration-300")}>
      <div className="flex justify-between items-center mb-1">
        <label className={`font-bold ${compact ? "text-xs" : "text-sm"} text-slate-800 dark:text-white`}>
          {label}
        </label>
        <div className="flex items-center gap-2">
          <button
            onClick={handleReset}
            title="Сбросить"
            tabIndex={hasChanged && !disabled ? 0 : -1}
            className={cn(
              "p-1 rounded-md transition-all duration-300 flex items-center justify-center shadow-sm border-2 border-transparent",
              hasChanged ? "opacity-100 rotate-0 hover:bg-slate-200 dark:hover:bg-slate-700" : "opacity-0 -rotate-90 pointer-events-none cursor-default",
              "text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-white/10"
            )}
          >
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" />
              <path d="M3 3v5h5" />
            </svg>
          </button>

          <span className={cn(
            "font-black px-2 py-0.5 rounded-md bg-slate-100 dark:bg-white/10 text-right tabular-nums shadow-inner min-w-[3ch] tracking-tight",
            compact ? "text-xs" : "text-xs",
            hasChanged ? "text-indigo-600 dark:text-indigo-400" : "text-slate-800 dark:text-white"
          )}>
            {displayValue}{suffix}
          </span>
        </div>
      </div>
      
      <div 
        className={cn("relative flex items-center cursor-pointer touch-pan-y select-none px-[10px]", compact ? "h-6" : "h-8")}
        onTouchStart={onTouchStart}
        onMouseDown={onMouseDown}
        onKeyDown={onKeyDown}
        tabIndex={disabled ? -1 : 0}
        role="slider"
        aria-label={label}
        aria-valuemin={min}
        aria-valuemax={max}
        aria-valuenow={localValue}
      >
        <div className={cn("w-full rounded-full shadow-inner bg-slate-200 dark:bg-white/20 overflow-hidden", compact ? "h-1.5" : "h-2")}>
          <div 
            className="h-full bg-indigo-500 rounded-full transition-all duration-75" 
            style={{ width: `${pct}%` }}
          />
        </div>
        <div 
          className={cn(
            "absolute top-1/2 -translate-y-1/2 w-5 h-5 bg-white dark:bg-slate-200 rounded-full border-2 border-white dark:border-slate-700 shadow-premium transition-all duration-75",
            isDragging.current && "scale-110"
          )}
          style={{ left: `calc(${pct}% - ${(pct * 20) / 100}px)` }}
        />
      </div>
    </div>
  );
}
