// src/components/dialogs/ColorEditorDialog.tsx
import { useState, useEffect, useRef } from 'react';
import { rgbToHex, type RGB } from '../../engine';
import { hslToRgbArr } from '../../utils/colorParsing';
import type { ColorComponent } from '../../config';
import { ModalWide } from '../ui/Modal';

export function ColorEditorDialog({ existingColor, allColorNames, onSave, onClose, originalName }: {
  existingColor?: ColorComponent | null; allColorNames: string[];
  onSave: (c: ColorComponent) => void; onClose: () => void; originalName?: string;
}) {
  const hexToRgb = (h: string): RGB | null => { 
    let c = h.replace(/^#/, ''); 
    // Жестко требуем 6 символов, так как инпут автоматически дополняет
    if (!/^([0-9A-Fa-f]{6})$/.test(c)) return null; 
    return [parseInt(c.slice(0, 2), 16), parseInt(c.slice(2, 4), 16), parseInt(c.slice(4, 6), 16)]; 
  };

  const hexToHsl = (h: string) => {
    const rgb = hexToRgb(h); if (!rgb) return { h: 0, s: 100, l: 50 };
    const r = rgb[0] / 255, g = rgb[1] / 255, b = rgb[2] / 255, mx = Math.max(r, g, b), mn = Math.min(r, g, b);
    let hh = 0, s = 0; const l = (mx + mn) / 2;
    if (mx !== mn) {
      const d = mx - mn; s = l > 0.5 ? d / (2 - mx - mn) : d / (mx + mn);
      switch (mx) { case r: hh = ((g - b) / d + (g < b ? 6 : 0)) / 6; break; case g: hh = ((b - r) / d + 2) / 6; break; case b: hh = ((r - g) / d + 4) / 6; break; }
    }
    return { h: Math.round(hh * 360), s: Math.round(s * 100), l: Math.round(l * 100) };
  };

  const isE = !!existingColor;
  const [name, setName] = useState(existingColor?.name || '');
  const [hex, setHex] = useState(() => existingColor?.rgb ? rgbToHex(existingColor.rgb) : '#FF0000');
  const [error, setError] = useState('');

  const [hue, setHue] = useState(() => existingColor?.rgb ? hexToHsl(rgbToHex(existingColor.rgb)).h : 0);
  const [sat, setSat] = useState(() => existingColor?.rgb ? hexToHsl(rgbToHex(existingColor.rgb)).s : 100);
  const [lit, setLit] = useState(() => existingColor?.rgb ? hexToHsl(rgbToHex(existingColor.rgb)).l : 50);

  const [ri, setRi] = useState(() => existingColor?.rgb ? `${existingColor.rgb[0]}, ${existingColor.rgb[1]}, ${existingColor.rgb[2]}` : '255, 0, 0');

  const bySlider = useRef(false);

  useEffect(() => {
    if (bySlider.current) { bySlider.current = false; const r = hexToRgb(hex); if (r) setRi(`${r[0]}, ${r[1]}, ${r[2]}`); return; }
    const r = hexToRgb(hex);
    if (r) { setRi(`${r[0]}, ${r[1]}, ${r[2]}`); const h = hexToHsl(hex); setHue(h.h); setSat(h.s); setLit(h.l); }
  }, [hex]);

  const uHsl = (h: number, s: number, l: number) => { bySlider.current = true; setHex(rgbToHex(hslToRgbArr(h, s, l))); };

  const hRgb = (v: string) => { const n = v.replace(/\./g, ','); setRi(n); const m = n.match(/^(\d{1,3}),\s*(\d{1,3}),\s*(\d{1,3})$/); if (m) { setHex(rgbToHex([Math.min(255, +m[1]), Math.min(255, +m[2]), Math.min(255, +m[3])])); setError(''); } };

  const validate = (): string | null => { if (!name.trim()) return 'Введите название'; if (!hexToRgb(hex)) return 'Некорректный HEX'; const sn = originalName || existingColor?.name; const d = allColorNames.find(n => n.toLowerCase() === name.trim().toLowerCase() && n !== sn); if (d) return `«${d}» уже существует`; return null; };
  
  const save = () => { const e = validate(); if (e) { setError(e); return; } onSave({ name: name.trim(), rgb: hexToRgb(hex)! }); };
  
  const hHex = (e: React.ChangeEvent<HTMLInputElement>) => { let v = e.target.value; if (!v.startsWith('#')) v = '#' + v.replace(/#/g, ''); v = '#' + v.slice(1).replace(/[^0-9A-Fa-f]/g, '').toUpperCase().slice(0, 6); setHex(v); setError(''); };

  const hueC = Array.from({ length: 36 }, (_, i) => rgbToHex(hslToRgbArr(i * 10, 100, 50)));

  const mkH = (sv: (v: number) => void, mx: number, bh: (v: number) => [number, number, number]) => ({
    onClick: (e: React.MouseEvent<HTMLDivElement>) => { 
      e.stopPropagation(); 
      const r = e.currentTarget.getBoundingClientRect(); 
      const v = Math.round(Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)) * mx); 
      sv(v); 
      const [h, s, l] = bh(v); 
      uHsl(h, s, l); 
    },
    onMouseDown: (e: React.MouseEvent<HTMLDivElement>) => { 
      e.preventDefault(); 
      e.stopPropagation(); 
      const r = e.currentTarget.getBoundingClientRect(); 
      const m = (me: MouseEvent) => { 
        const v = Math.round(Math.max(0, Math.min(1, (me.clientX - r.left) / r.width)) * mx); 
        sv(v); 
        const [h, s, l] = bh(v); 
        uHsl(h, s, l); 
      }; 
      const u = () => { 
        document.removeEventListener('mousemove', m); 
        document.removeEventListener('mouseup', u); 
      }; 
      document.addEventListener('mousemove', m); 
      document.addEventListener('mouseup', u); 
    },
    onTouchStart: (e: React.TouchEvent<HTMLDivElement>) => { 
      const r = e.currentTarget.getBoundingClientRect(); 
      const startX = e.touches[0].clientX;
      const startY = e.touches[0].clientY;
      let isSliding = false;
      let isScrolling = false;

      const f = (clientX: number) => { 
        const v = Math.round(Math.max(0, Math.min(1, (clientX - r.left) / r.width)) * mx); 
        sv(v); 
        const [h, s, l] = bh(v); 
        uHsl(h, s, l); 
      }; 

      const m = (te: TouchEvent) => { 
        if (isScrolling) return;

        const currentX = te.touches[0].clientX;
        const currentY = te.touches[0].clientY;
        const dx = Math.abs(currentX - startX);
        const dy = Math.abs(currentY - startY);

        if (!isSliding && !isScrolling) {
          if (dy > dx && dy > 10) {
            isScrolling = true;
            return;
          }
          if (dx > 10 || dx > dy) {
            isSliding = true;
          }
        }

        if (isSliding) {
          if (te.cancelable) te.preventDefault();
          te.stopPropagation();
          f(currentX);
        }
      }; 

      const u = (te: TouchEvent) => { 
        if (!isScrolling && !isSliding) {
          // It was a tap
          f(startX);
        }
        document.removeEventListener('touchmove', m); 
        document.removeEventListener('touchend', u); 
      }; 

      document.addEventListener('touchmove', m, { passive: false }); 
      document.addEventListener('touchend', u); 
    },
  });

  return (
    <ModalWide onClose={onClose} zClass="z-[70]">
      <div className="px-5 pt-4 sm:pt-5 pb-4 border-b border-slate-200/50 dark:border-slate-800/50 flex flex-col shrink-0 relative overflow-hidden">
        <div className="flex items-center justify-between mb-1 relative z-10">
          <div className="flex items-center gap-2.5 min-w-0">
            <div className="w-10 h-10 rounded-xl border-2 border-white dark:border-slate-800 shadow-premium shrink-0 transition-colors duration-300" style={{ backgroundColor: hexToRgb(hex) ? hex : 'transparent' }} />
            <div className="min-w-0">
              <h2 className="text-base sm:text-lg font-bold text-slate-900 dark:text-white truncate">
                {isE ? 'Изменение цвета' : 'Новый цвет'}
              </h2>
              <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">
                {hexToRgb(hex) ? hex : 'Палитра красок'}
              </div>
            </div>
          </div>
          
          <div className="flex items-center gap-2 shrink-0">
            <button 
              onClick={save} 
              className="hidden sm:flex px-4 py-2 rounded-xl bg-blue-600 hover:bg-blue-700 active:bg-blue-800 text-white text-sm font-bold shadow-lg shadow-blue-500/20 transition-all active:scale-[0.95]"
            >
              {isE ? 'Сохранить' : 'Добавить'}
            </button>
            <button 
              onClick={onClose} 
              className="w-10 h-10 -mr-2 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
              aria-label="Закрыть"
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>

        {/* Мобильная кнопка сохранения — более удобная и инфографичная */}
        <div className="sm:hidden mt-3">
          <button 
            onClick={save} 
            className="w-full py-3 rounded-2xl bg-blue-600 text-white text-xs font-black uppercase tracking-widest shadow-lg shadow-blue-500/25 flex items-center justify-center gap-2 active:scale-[0.98] transition-all"
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="20 6 9 17 4 12" />
            </svg>
            {isE ? 'Применить изменения' : 'Добавить в палитру'}
          </button>
        </div>
      </div>

      <div className="p-5 space-y-6 overflow-y-auto flex-1 pb-24 custom-scrollbar">
        <div className="space-y-4">
          <div className="flex items-center gap-2 mb-1">
             <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
             <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">Основное</span>
             <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
          </div>
          
          <div>
            <label className="block text-xs font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-2 ml-1">Название краски</label>
            <input type="text" value={name} onChange={e => { setName(e.target.value); setError(''); }} placeholder="Например: Небесный" maxLength={30} className="w-full px-4 py-3.5 rounded-2xl border-2 border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-900 dark:text-white text-sm font-bold focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all" />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-2 ml-1">HEX код</label>
              <input type="text" value={hex} onChange={hHex} maxLength={7} className="w-full px-4 py-3.5 rounded-2xl border-2 border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-900 dark:text-white text-sm font-mono font-bold uppercase tracking-widest focus:outline-none focus:border-blue-500 transition-all" />
            </div>
            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-2 ml-1">RGB значения</label>
              <input type="text" value={ri} onChange={e => hRgb(e.target.value)} placeholder="255, 128, 64" className="w-full px-4 py-3.5 rounded-2xl border-2 border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-900 dark:text-white text-sm font-mono font-bold focus:outline-none focus:border-blue-500 transition-all" />
            </div>
          </div>
        </div>

        {error && (
          <div className="p-3 rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/30 flex items-center gap-3 animate-shake">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-red-500"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
            <p className="text-xs font-bold text-red-600 dark:text-red-400">{error}</p>
          </div>
        )}

        <div className="space-y-6 pt-2">
          <div className="flex items-center gap-2 mb-1">
             <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
             <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">Тонкая настройка</span>
             <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
          </div>

          <div>
            <div className="flex justify-between items-center mb-3 px-1">
              <label className="text-xs font-black uppercase tracking-widest text-slate-500 dark:text-slate-400">Оттенок (Hue)</label>
              <span className="text-xs font-black text-indigo-500 tabular-nums bg-indigo-50 dark:bg-indigo-500/10 px-2 py-0.5 rounded-md">{hue}°</span>
            </div>
            <div className="relative h-11 rounded-2xl overflow-hidden cursor-ew-resize select-none touch-pan-y shadow-inner border border-black/5" {...mkH(setHue, 359, v => [v, sat, lit])}>
              <div className="w-full h-full" style={{ background: `linear-gradient(to right, ${hueC.map((c, i) => `${c} ${(i / hueC.length) * 100}%`).join(', ')}, #FF0000 100%)` }} />
              <div className="absolute top-1/2 -translate-y-1/2 w-2 h-8 bg-white rounded-full shadow-lg ring-2 ring-black/10 transition-transform active:scale-x-150" style={{ left: `calc(${(hue / 359) * 100}% - 4px)` }} />
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-3 px-1">
              <label className="text-xs font-black uppercase tracking-widest text-slate-500 dark:text-slate-400">Насыщенность</label>
              <span className="text-xs font-black text-indigo-500 tabular-nums bg-indigo-50 dark:bg-indigo-500/10 px-2 py-0.5 rounded-md">{sat}%</span>
            </div>
            <div className="relative h-11 rounded-2xl overflow-hidden cursor-ew-resize select-none touch-pan-y shadow-inner border border-black/5" {...mkH(setSat, 100, v => [hue, v, lit])}>
              <div className="w-full h-full" style={{ background: `linear-gradient(to right, hsl(${hue},0%,${lit}%), hsl(${hue},100%,${lit}%))` }} />
              <div className="absolute top-1/2 -translate-y-1/2 w-2 h-8 bg-white rounded-full shadow-lg ring-2 ring-black/10 transition-transform active:scale-x-150" style={{ left: `calc(${sat}% - 4px)` }} />
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-3 px-1">
              <label className="text-xs font-black uppercase tracking-widest text-slate-500 dark:text-slate-400">Яркость (Lightness)</label>
              <span className="text-xs font-black text-indigo-500 tabular-nums bg-indigo-50 dark:bg-indigo-500/10 px-2 py-0.5 rounded-md">{lit}%</span>
            </div>
            <div className="relative h-11 rounded-2xl overflow-hidden cursor-ew-resize select-none touch-pan-y shadow-inner border border-black/5" {...mkH(setLit, 100, v => [hue, sat, v])}>
              <div className="w-full h-full" style={{ background: `linear-gradient(to right, black, hsl(${hue},${sat}%,50%), white)` }} />
              <div className="absolute top-1/2 -translate-y-1/2 w-2 h-8 bg-white rounded-full shadow-lg ring-2 ring-black/10 transition-transform active:scale-x-150" style={{ left: `calc(${lit}% - 4px)` }} />
            </div>
          </div>
        </div>
      </div>
    </ModalWide>
  );
}