// src/generator/GeneratorModal.tsx
import { useAppStore } from "./store";
import { Toolbar } from "./components/ToolBar";
import { PreviewPanel } from "./components/PreviewPanel";
import { PalettePanel } from "./components/PalettePanel";
import { SettingsPanel } from "./components/SettingsPanel";
import { CalculatorPanel } from "./components/CalculatorPanel";
import { CalculatorBottomSheet } from "./components/CalculatorBottomSheet";
import { MobileBottomSheet } from "./components/MobileBottomSheet";
import { CropModal } from "./components/CropModal";
import { UrlModal } from "./components/UrlModal";
import { ExportModal } from "./components/ExportModal";
import { HistoryModal } from "./components/HistoryModal";
import { ErrorBoundary } from "../components/ui/ErrorBoundary";
import { cn } from "../utils/cn";
import { useGeneratorLogic } from "./hooks/useGeneratorLogic";

export default function GeneratorModal({
  isOpen,
  isDark,
}: {
  isOpen: boolean;
  onClose: () => void;
  isDark: boolean;
}) {
  const isProcessing = useAppStore((s) => s.isProcessing);
  const isExporting = useAppStore((s) => s.isExporting);
  const progress = useAppStore((s) => s.progress);
  const hasOriginal = useAppStore((s) => !!s.originalImageUrl);
  const hasResult = useAppStore((s) => !!s.result);
  const presetKey = useAppStore((s) => s.presetKey);
  const update = useAppStore((s) => s.update);
  const colorPickerActive = useAppStore((s) => s.colorPickerActive);
  const pickedColor = useAppStore((s) => s.pickedColor);

  const { loadImage, cancelProcessing } = useGeneratorLogic(isOpen, isDark);

  return (
    <div
      className={cn(
        "flex-1 flex flex-col min-h-0 bg-white dark:bg-slate-900 relative animate-fade-in-up w-full h-full",
        isOpen ? "flex" : "hidden"
      )}
    >
      <ErrorBoundary>
        {(isProcessing || isExporting) && (
          <div
            className="absolute top-0 left-0 right-0 h-1 z-[50] bg-slate-200 dark:bg-slate-800"
            role="progressbar"
            aria-label="Прогресс"
            aria-valuenow={progress}
            aria-valuemin={0}
            aria-valuemax={100}
          >
            <div className="h-full bg-indigo-500 transition-all duration-300 rounded-r-full" style={{ width: `${progress}%` }} />
          </div>
        )}

        <Toolbar
          onLoadImage={loadImage}
          onCancel={cancelProcessing}
          onExport={() => update({ exportModalOpen: true })}
          hasResult={hasResult}
        />

        <div className="flex-1 flex min-h-0 relative w-full overflow-hidden">
          <div className="flex-1 flex flex-col min-w-0 min-h-0 w-full relative">
            <PreviewPanel onLoadImage={loadImage} />
            {hasResult && presetKey !== "artistic" && <PalettePanel />}
          </div>
          {colorPickerActive ? (
            <CalculatorPanel pickedColor={pickedColor} onClose={() => update({ colorPickerActive: false, pickedColor: null, colorPickerPanelOpen: false })} />
          ) : (
            (hasOriginal || hasResult) && <SettingsPanel />
          )}
        </div>

        <MobileBottomSheet />
        <CalculatorBottomSheet />
        <CropModal />
        <UrlModal onLoadImage={loadImage} />
        <ExportModal />
        <HistoryModal />
      </ErrorBoundary>
    </div>
  );
}
