import React, { useState } from "react";
import { useAppStore } from "../store";
import { SmoothSlider } from "./SmoothSlider";
import { ArtisticPresetSelector } from "./ArtisticPresetSelector";
import { cn } from "../../utils/cn";
import { SectionTitle, Divider } from "../../components/ui/SectionTitle";
import { calculateAutoParams, type AutoParamsResult } from "../utils/autoParams";

export function SettingsPanel() {
  const isDark = useAppStore((s) => s.isDark);

  return (
    <aside
      className={cn(
        "w-80 xl:w-96 flex-shrink-0 border-l overflow-y-auto p-4 lg:block hidden custom-scrollbar pb-24 glass-panel dark:glass-panel border-white/20 dark:border-white/10 z-10 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] dark:shadow-[-10px_0_30px_rgba(0,0,0,0.3)]",
      )}
      aria-label="Панель настроек"
    >
      <SettingsContent />
    </aside>
  );
}

function Section({ title, children, isDark, action }: { title: string; children: React.ReactNode; isDark: boolean; action?: React.ReactNode }) {
  return (
    <section className="space-y-4">
      {action ? (
        <div className="flex items-center justify-between">
          <SectionTitle>{title}</SectionTitle>
          {action}
        </div>
      ) : (
        <SectionTitle>{title}</SectionTitle>
      )}
      <div className="space-y-4">
        {children}
      </div>
    </section>
  );
}

function HighlightSection({ title, children, isDark }: { title: string; children: React.ReactNode; isDark: boolean }) {
  return (
    <div className={cn("flex flex-col gap-4 p-5 rounded-2xl border backdrop-blur-sm", isDark ? "bg-indigo-500/5 border-indigo-500/20" : "bg-indigo-50/80 border-indigo-200/80")}>
      <h3 className="text-xs font-bold uppercase tracking-widest text-indigo-700 dark:text-indigo-200">
        {title}
      </h3>
      <div className="space-y-5">
        {children}
      </div>
    </div>
  );
}

export function SettingsContent({ hideCorrection = false }: { hideCorrection?: boolean }) {
  const isDark = useAppStore((s) => s.isDark);

  const presetKey = useAppStore((s) => s.presetKey);
  const showNumbers = useAppStore((s) => s.showNumbers);
  const showContours = useAppStore((s) => s.showContours);
  const activeColors = useAppStore((s) => s.activeColors);
  const numColors = useAppStore((s) => s.numColors);
  const detail = useAppStore((s) => s.detail);
  const contourWeight = useAppStore((s) => s.contourWeight);
  const pbnContourWeight = useAppStore((s) => s.pbnContourWeight);
  const numberWeight = useAppStore((s) => s.numberWeight);
  const hasResult = useAppStore((s) => !!s.result);
  const hasImage = useAppStore((s) => !!s.originalImageUrl);
  const correction = useAppStore((s) => s.correction);
  const imageProfile = useAppStore((s) => s.imageProfile);

  const update = useAppStore((s) => s.update);
  const switchMode = useAppStore((s) => s.switchMode);
  const toggleAllColors = useAppStore((s) => s.toggleAllColors);
  const updateCorrection = useAppStore((s) => s.updateCorrection);
  const resetCorrection = useAppStore((s) => s.resetCorrection);
  const pushHistory = useAppStore((s) => s.pushCorrectionHistory);

  const notanLevels = useAppStore((s) => s.notanLevels);
  const notanThreshold = useAppStore((s) => s.notanThreshold);
  const setNotanLevels = useAppStore((s) => s.setNotanLevels);
  const setNotanThreshold = useAppStore((s) => s.setNotanThreshold);

  const artIntensity = useAppStore((s) => s.artIntensity);
  const setArtIntensity = useAppStore((s) => s.setArtIntensity);

  const detailsPhotoOpacity = useAppStore((s) => s.detailsPhotoOpacity);
  const setDetailsPhotoOpacity = useAppStore((s) => s.setDetailsPhotoOpacity);

  const artisticStep = useAppStore((s) => s.artisticStep);
  const artisticNumColors = useAppStore((s) => s.artisticNumColors);
  const artisticDetail = useAppStore((s) => s.artisticDetail);
  const setArtisticNumColors = useAppStore((s) => s.setArtisticNumColors);
  const setArtisticDetail = useAppStore((s) => s.setArtisticDetail);

  const artisticPresetId = useAppStore((s) => s.artisticPresetId);

  const currentMode = presetKey === "artistic" ? "art" : "pbn";

  const handleModeChange = (mode: "art" | "pbn") => {
    switchMode(mode === "art" ? "artistic" : "pbn");
  };

  return (
    <div className="flex flex-col gap-8">
      {/* 1. ГЛАВНЫЙ ПЕРЕКЛЮЧАТЕЛЬ РЕЖИМА */}
      <Section title="Тип проекта" isDark={isDark}>
        <div className={cn("flex p-1.5 rounded-2xl", isDark ? "bg-slate-800/50" : "bg-slate-100")}>
          <ModeButton
            active={currentMode === "art"}
            onClick={() => handleModeChange("art")}
            label="Живопись"
            isDark={isDark}
            icon={
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 19l7-7 3 3-7 7-3-3z" />
                <path d="m18 13-1.5-7.5L2 2l3.5 14.5L13 18l5-5z" />
              </svg>
            }
          />
          <ModeButton
            active={currentMode === "pbn"}
            onClick={() => handleModeChange("pbn")}
            label="По номерам"
            isDark={isDark}
            icon={
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M4 7h4M4 17h4M4 12h3" />
                <path d="M14 7h2v4M14 17h4M14 13h2v4" />
              </svg>
            }
          />
        </div>
      </Section>

      <div className="h-px w-full bg-slate-100 dark:bg-slate-800" />

      {/* 2. НАСТРОЙКИ: ЖИВОПИСЬ */}
      {currentMode === "art" && (
        <div className="flex flex-col gap-6 animate-fade-in-up">
          <Section title="Стилизация" isDark={isDark}>
             <ArtisticPresetSelector isDark={isDark} />
          </Section>

          <Divider />

          <Section title="Сложность" isDark={isDark}>
            {imageProfile && (
              <AutoParamsSelector
                profile={imageProfile}
                isDark={isDark}
                onSelect={(colors, det) => {
                  setArtisticNumColors(colors);
                  setArtisticDetail(det);
                }}
              />
            )}
            <SmoothSlider
              label="Количество цветов"
              storeValue={artisticNumColors}
              defaultValue={6}
              min={4}
              max={50}
              onCommit={setArtisticNumColors}
              isDark={isDark}
            />
            <SmoothSlider
              label="Детализация форм"
              storeValue={artisticDetail}
              defaultValue={1}
              min={1}
              max={10}
              onCommit={setArtisticDetail}
              isDark={isDark}
            />
          </Section>

          {hasResult && artisticStep === 1 && (
            <>
              <Divider />
              <HighlightSection title="Подмалёвок (Тени)" isDark={isDark}>
                <SmoothSlider
                  label="Уровни детализации"
                  storeValue={notanLevels}
                  defaultValue={2}
                  min={2}
                  max={5}
                  onCommit={setNotanLevels}
                  isDark={isDark}
                />
                <SmoothSlider
                  label="Баланс ч/б"
                  storeValue={notanThreshold}
                  defaultValue={128}
                  min={40}
                  max={220}
                  onCommit={setNotanThreshold}
                  isDark={isDark}
                  disabled={notanLevels !== 2}
                />
              </HighlightSection>
            </>
          )}

          {hasResult && artisticStep === 2 && artisticPresetId !== "original" && (
            <>
              <Divider />
              <HighlightSection title="Настройка цвета" isDark={isDark}>
                <SmoothSlider
                  label="Интенсивность"
                  storeValue={artIntensity}
                  defaultValue={100}
                  min={0}
                  max={100}
                  onCommit={setArtIntensity}
                  isDark={isDark}
                  suffix="%"
                />
              </HighlightSection>
            </>
          )}

          {hasResult && (artisticStep === 0 || artisticStep === 3) && (
            <>
              <Divider />
              <Section title="Вспомогательное" isDark={isDark}>
                <SmoothSlider
                  label={artisticStep === 3 ? "Прозрачность фото" : "Прозрачность эскиза"}
                  storeValue={detailsPhotoOpacity}
                  defaultValue={60}
                  min={0}
                  max={100}
                  onCommit={setDetailsPhotoOpacity}
                  isDark={isDark}
                  suffix="%"
                />
              </Section>
            </>
          )}
        </div>
      )}

      {/* 3. НАСТРОЙКИ: ПО НОМЕРАМ */}
      {currentMode === "pbn" && (
        <div className="flex flex-col gap-6 animate-fade-in-up">
          <Section title="Векторизация" isDark={isDark}>
            {imageProfile && (
              <AutoParamsSelector
                profile={imageProfile}
                isDark={isDark}
                onSelect={(colors, det) => {
                  update({ numColors: colors, detail: det });
                }}
              />
            )}
            <SmoothSlider
              label="Количество цветов"
              storeValue={numColors}
              defaultValue={20}
              min={4}
              max={50}
              onCommit={(v) => update({ numColors: v })}
              isDark={isDark}
            />
            <SmoothSlider
              label="Детализация форм"
              storeValue={detail}
              defaultValue={5}
              min={1}
              max={10}
              onCommit={(v) => update({ detail: v })}
              isDark={isDark}
            />
          </Section>

          {hasResult && (
            <>
              <Divider />
              <Section title="Вид холста" isDark={isDark}>
              <SmoothSlider
                label="Толщина контуров"
                storeValue={pbnContourWeight}
                defaultValue={25}
                min={0}
                max={100}
                onCommit={(v) => update({ contourWeight: v, pbnContourWeight: v })}
                isDark={isDark}
                suffix="%"
              />
              <SmoothSlider
                label="Яркость номеров"
                storeValue={numberWeight}
                defaultValue={25}
                min={0}
                max={100}
                onCommit={(v) => update({ numberWeight: v })}
                isDark={isDark}
                suffix="%"
              />
              
              <div className="pt-4 space-y-3">
                <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-600 dark:text-slate-400 pl-1 mb-2">Отображение</h3>
                <div className="space-y-2">
                  <SwitchRow
                    label="Контуры зон"
                    checked={showContours}
                    onChange={(v) => update({ showContours: v })}
                    isDark={isDark}
                  />
                  <SwitchRow
                    label="Заливка цветом"
                    checked={activeColors.size > 0}
                    onChange={() => toggleAllColors()}
                    isDark={isDark}
                  />
                  <SwitchRow
                    label="Номера красок"
                    checked={showNumbers}
                    onChange={(v) => update({ showNumbers: v })}
                    isDark={isDark}
                  />
                </div>
              </div>
            </Section>
            </>
          )}
        </div>
      )}

      {/* 4. ГЛОБАЛЬНАЯ КОРРЕКЦИЯ ФОТО */}
      {hasImage && !hideCorrection && (
        <>
          <Divider />
          <Section 
            title="Светокоррекция" 
            isDark={isDark}
            action={
              <button 
                onClick={resetCorrection}
                className="text-xs font-black uppercase tracking-widest text-indigo-500 hover:text-indigo-400 transition-colors px-2 py-1"
              >
                Сбросить
              </button>
            }
          >
            <SmoothSlider
              label="Яркость"
              storeValue={correction.brightness}
              defaultValue={0}
              min={-100}
              max={100}
              onCommit={(v) => updateCorrection({ brightness: v })}
              onDragEnd={pushHistory}
              showSign
            />
            <SmoothSlider
              label="Контраст"
              storeValue={correction.contrast}
              defaultValue={0}
              min={-100}
              max={100}
              onCommit={(v) => updateCorrection({ contrast: v })}
              onDragEnd={pushHistory}
              showSign
            />
            <SmoothSlider
              label="Насыщенность"
              storeValue={correction.saturation}
              defaultValue={0}
              min={-100}
              max={100}
              onCommit={(v) => updateCorrection({ saturation: v })}
              onDragEnd={pushHistory}
              showSign
            />
          </Section>
        </>
      )}
    </div>
  );
}

function SwitchRow({
  label,
  checked,
  onChange,
  isDark,
}: {
  label: string;
  checked: boolean;
  onChange: (v: boolean) => void;
  isDark: boolean;
}) {
  return (
    <label className="flex items-center justify-between p-4 rounded-2xl bg-slate-50/80 dark:bg-slate-800/40 border-2 border-slate-100 dark:border-slate-800/50 cursor-pointer group hover:border-indigo-500/30 transition-all min-h-[56px] active:scale-[0.98]">
      <span className={cn(
        "text-xs font-black uppercase tracking-wider transition-colors", 
        checked ? "text-indigo-500" : "text-slate-600 dark:text-slate-300"
      )}>
        {label}
      </span>
      <div className="relative flex items-center shrink-0">
        <input
          type="checkbox"
          checked={checked}
          onChange={(e) => onChange(e.target.checked)}
          className="peer sr-only"
        />
        <div className="w-12 h-7 bg-slate-200 dark:bg-slate-700 rounded-full peer peer-checked:bg-indigo-600 transition-colors shadow-inner" />
        <div className="absolute left-1 top-1 w-5 h-5 bg-white rounded-full transition-transform peer-checked:translate-x-5 shadow-sm" />
      </div>
    </label>
  );
}

function ModeButton({
  active,
  onClick,
  label,
  icon,
  isDark,
}: {
  active: boolean;
  onClick: () => void;
  label: string;
  icon: React.ReactNode;
  isDark: boolean;
}) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-xs font-black uppercase tracking-[0.15em] transition-all outline-none",
        active
          ? "bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-[0_2px_10px_rgba(0,0,0,0.08)] dark:shadow-[0_2px_10px_rgba(0,0,0,0.3)] scale-100"
          : "text-slate-500 hover:text-slate-600 dark:text-slate-400 dark:hover:text-slate-300 active:scale-[0.98]"
      )}
    >
      <span className={cn("transition-transform duration-300", active ? "scale-110 drop-shadow-sm" : "scale-100")}>{icon}</span>
      <span className="truncate">{label}</span>
    </button>
  );
}

function AutoParamsSelector({
  profile,
  isDark,
  onSelect,
}: {
  profile: any;
  isDark: boolean;
  onSelect: (colors: number, detail: number) => void;
}) {
  const options = calculateAutoParams(profile);

  return (
    <div className={cn("flex flex-col gap-3 p-4 rounded-2xl border transition-colors", isDark ? "bg-indigo-500/10 border-indigo-500/20" : "bg-indigo-50/50 border-indigo-100")}>
      <div className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="m21.64 3.64-1.28-1.28a1.21 1.21 0 0 0-1.72 0L2.36 18.64a1.21 1.21 0 0 0 0 1.72l1.28 1.28a1.2 1.2 0 0 0 1.72 0L21.64 5.36a1.2 1.2 0 0 0 0-1.72Z"/>
          <path d="m14 7 3 3"/>
          <path d="M5 6v4"/>
          <path d="M19 14v4"/>
          <path d="M10 2v2"/>
          <path d="M7 8H3"/>
          <path d="M21 16h-4"/>
          <path d="M11 3H9"/>
        </svg>
        <span className="text-xs font-black uppercase tracking-wider">Мастер подбора</span>
      </div>

      <div className="flex flex-col gap-2 pt-1 animate-fade-in-up">
        {options.map((opt) => (
          <button
            key={opt.level}
            onClick={() => onSelect(opt.numColors, opt.detail)}
            className={cn(
              "flex items-center justify-between p-3 rounded-xl border-2 transition-all active:scale-[0.98]",
              isDark 
                ? "bg-slate-800/80 border-slate-700 hover:border-indigo-500/50" 
                : "bg-white border-transparent hover:border-indigo-500/30 shadow-sm"
            )}
          >
            <div className="flex flex-col items-start gap-0.5">
              <span className={cn("text-xs font-bold uppercase tracking-wider", isDark ? "text-slate-200" : "text-slate-700")}>
                {opt.label}
              </span>
              <span className={cn("text-xs", isDark ? "text-slate-400" : "text-slate-500")}>
                Цветов: {opt.numColors} • Деталей: {opt.detail}
              </span>
            </div>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-indigo-500">
              <path d="M5 12h14" />
              <path d="m12 5 7 7-7 7" />
            </svg>
          </button>
        ))}
      </div>
    </div>
  );
}