import { useAppStore } from "../store";
import { ARTISTIC_PRESETS, ARTISTIC_PRESET_ORDER } from "../../config";
import { cn } from "../../utils/cn";

export function ArtisticPresetSelector({ isDark }: { isDark?: boolean }) {
  const presetKey = useAppStore((s) => s.presetKey);
  const artisticPresetId = useAppStore((s) => s.artisticPresetId);
  const setArtisticPreset = useAppStore((s) => s.setArtisticPreset);

  if (presetKey !== "artistic") return null;

  return (
    <div className="space-y-4">
      {/* Сетка: 1 колонка на мобилках, 2 на планшетах/десктопе. Текст гарантированно влезет. */}
      <div className="grid grid-cols-1 xs:grid-cols-2 gap-3" role="radiogroup" aria-label="Стили живописи">
        {ARTISTIC_PRESET_ORDER.map((presetId) => {
          const preset = ARTISTIC_PRESETS[presetId];
          const isSelected = artisticPresetId === presetId;

          return (
            <button key={presetId} onClick={() => setArtisticPreset(presetId)}
              role="radio"
              aria-checked={isSelected}
              className={cn(
                "relative flex items-center gap-3 p-3 rounded-2xl border-2 transition-all duration-300 active:scale-[0.98] text-left overflow-hidden",
                isSelected
                  ? "border-indigo-600 bg-white dark:bg-slate-900 shadow-premium z-10"
                  : "border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/30 text-slate-500 dark:text-slate-400"
              )}>
              
              <div className={cn(
                "w-10 h-10 rounded-xl flex items-center justify-center text-xl shrink-0 transition-all shadow-sm",
                isSelected ? "bg-indigo-600 text-white" : "bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400"
              )}>
                {preset.icon}
              </div>

              <div className="flex-1 min-w-0">
                 <div className={cn(
                   "text-xs font-black uppercase tracking-tight leading-none mb-1.5 truncate",
                   isSelected ? "text-slate-900 dark:text-white" : "text-slate-500"
                 )}>
                   {preset.name}
                 </div>
                 <div className="flex w-full h-1 rounded-full overflow-hidden opacity-40">
                    {preset.previewColors.map((c, idx) => (
                      <div key={idx} className="flex-1 h-full" style={{ backgroundColor: `rgb(${c})` }} />
                    ))}
                 </div>
              </div>
            </button>
          );
        })}
      </div>
      
      <div className="bg-indigo-50/50 dark:bg-indigo-900/10 p-3 rounded-2xl border border-indigo-100 dark:border-indigo-900/30 shadow-sm animate-fade-in" key={artisticPresetId}>
         <p className="text-xs text-indigo-800/80 dark:text-indigo-300/70 font-bold leading-relaxed uppercase tracking-tighter">
           {ARTISTIC_PRESETS[artisticPresetId]?.description}
         </p>
      </div>
    </div>
  );
}
