import ImageWorker from "../image.worker?worker";
import type { ArtisticPresetId, RGB } from "../../../config";
import type { ProcessingResult, ProgressCb } from "./types";

type WorkerJob =
  | {
      id: number;
      kind: "process";
      resolve: (res: ProcessingResult) => void;
      reject: (err: Error) => void;
      onProgress?: ProgressCb;
    }
  | {
      id: number;
      kind: "export";
      resolve: (res: string) => void;
      reject: (err: Error) => void;
    };

let sharedImageWorker: Worker | null = null;
let currentJob: WorkerJob | null = null;
let workerJobId = 0;

function ensureWorker(): Worker {
  if (!sharedImageWorker) {
    sharedImageWorker = new ImageWorker();

    sharedImageWorker.onmessage = (e) => {
      const job = currentJob;
      if (!job) return;

      const { type } = e.data;

      if (type === "progress") {
        if (job.kind === "process" && job.onProgress) {
          job.onProgress(e.data.msg, e.data.pct);
        }
        return;
      }

      if (type === "result") {
        if (job.kind !== "process") return;
        const {
          previewBuffer,
          imgW,
          imgH,
          contoursData,
          colorPalette,
          validLabels,
          scaleFactor,
          autoColors,
          autoDetail,
          labelMaskBuffer,
          boundaryEdgesBuffer,
        } = e.data.data;

        const flatEdges = new Float32Array(boundaryEdgesBuffer);
        const boundaryEdges: [number, number, number, number][] = [];
        for (let i = 0; i < flatEdges.length; i += 4) {
          boundaryEdges.push([flatEdges[i], flatEdges[i + 1], flatEdges[i + 2], flatEdges[i + 3]]);
        }

        const result: ProcessingResult = {
          previewImageData: new ImageData(new Uint8ClampedArray(previewBuffer), imgW, imgH),
          imgW,
          imgH,
          contoursData,
          colorPalette,
          validLabels: new Set(validLabels),
          scaleFactor,
          autoColors,
          autoDetail,
          labelMask: new Uint8Array(labelMaskBuffer),
          boundaryEdges,
        };

        currentJob = null;
        job.resolve(result);
        return;
      }

      if (type === "export_result") {
        if (job.kind !== "export") return;
        currentJob = null;
        job.resolve(e.data.data);
        return;
      }

      if (type === "error") {
        currentJob = null;
        job.reject(new Error(e.data.error));
      }
    };

    sharedImageWorker.onerror = (err) => {
      if (currentJob) {
        const job = currentJob;
        currentJob = null;
        job.reject(new Error(`Worker error: ${err.message}`));
      }
    };
  }
  return sharedImageWorker;
}

function rejectBusy(reject: (err: Error) => void) {
  reject(new Error("Another worker job is already running"));
}

export function processImage(
  imageData: ImageData,
  numColors: number,
  detail: number,
  onProgress: ProgressCb,
  signal?: AbortSignal,
): Promise<ProcessingResult> {
  return new Promise((resolve, reject) => {
    if (currentJob) {
      rejectBusy(reject);
      return;
    }

    const worker = ensureWorker();
    const jobId = ++workerJobId;

    currentJob = {
      id: jobId,
      kind: "process",
      resolve,
      reject,
      onProgress,
    };

    const abortHandler = () => {
      if (currentJob?.id === jobId) {
        currentJob = null;
        reject(new DOMException("Aborted", "AbortError"));
      }
    };

    if (signal) {
      if (signal.aborted) {
        abortHandler();
        return;
      }
      signal.addEventListener("abort", abortHandler, { once: true });
    }

    const imgBuffer = imageData.data.buffer.slice(0);
    worker.postMessage(
      {
        type: "process",
        payload: {
          imgBuffer,
          width: imageData.width,
          height: imageData.height,
          numColors,
          detail,
        },
      },
      [imgBuffer],
    );
  });
}

export function generateSVGContent(
  res: ProcessingResult,
  contourWeight: number,
  numberWeight: number,
  colored: boolean,
  active: Set<number>,
  showNums: boolean,
  isArtisticMode: boolean = false,
  artisticStep: number = 0,
  artisticPresetId?: ArtisticPresetId,
  notanLevels: number = 2,
  notanThreshold: number = 128,
  artIntensity: number = 100,
  customArtPalette?: RGB[],
): Promise<string> {
  return new Promise((resolve, reject) => {
    if (currentJob) {
      rejectBusy(reject);
      return;
    }

    const worker = ensureWorker();
    const jobId = ++workerJobId;

    currentJob = {
      id: jobId,
      kind: "export",
      resolve,
      reject,
    };

    worker.postMessage({
      type: "export_svg",
      payload: {
        res: { ...res, validLabels: Array.from(res.validLabels) },
        contourWeight,
        numberWeight,
        colored,
        activeArray: Array.from(active),
        showNums,
        isArtisticMode,
        artisticStep,
        artisticPresetId,
        notanLevels,
        notanThreshold,
        artIntensity,
        customArtPalette,
      },
    });
  });
}

