// src/components/dialogs/HistoryDialog.tsx
import { useState, useMemo } from 'react';
import { PAINT_PROFILES, formatParts, type PaintProfile } from '../../config';
import { cn } from '../../utils/cn';
import { formatSmartDate, favKey, getAccuracyInfo } from '../../utils/formatting';
import type { HistoryEntry } from '../../types';
import { Modal } from '../ui/Modal';

const StarIcon = ({ filled, className }: { filled?: boolean; className?: string }) => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill={filled ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
  </svg>
);

export function HistoryDialog({ entries, favorites, onViewRecipe, onClear, onClose, profile }: {
  entries: HistoryEntry[]; favorites: Set<string>; onViewRecipe: (e: HistoryEntry) => void;
  onClear: () => void; onClose: () => void; profile: PaintProfile;
}) {
  const [tab, setTab] = useState<'all' | 'favs'>('all');
  
  const shown = useMemo(() => 
    tab === 'favs' ? entries.filter(e => favorites.has(favKey(e))) : entries
  , [tab, entries, favorites]);

  const favCount = useMemo(() => 
    entries.filter(e => favorites.has(favKey(e))).length
  , [entries, favorites]);

  return (
    <Modal onClose={onClose} zClass="z-[70]">
      <div className="px-5 pt-4 sm:pt-5 pb-4 border-b border-slate-200/50 dark:border-slate-800/50 flex flex-col shrink-0">
        <div className="flex items-center justify-between mb-1">
          <div className="flex items-center gap-2.5">
            <span className="text-indigo-500 bg-indigo-50 dark:bg-indigo-500/10 p-1.5 rounded-lg shrink-0">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" /><path d="M3 3v5h5" /><path d="M12 7v5l4 2" />
              </svg>
            </span>
            <h2 className="text-base sm:text-lg font-bold text-slate-900 dark:text-white truncate">История расчётов</h2>
          </div>
          <div className="flex items-center gap-1">
            {entries.length > 0 && (
              <button onClick={onClear} className="w-10 h-10 rounded-full flex items-center justify-center text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors" title="Очистить историю" aria-label="Очистить историю">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18" /><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2" /></svg>
              </button>
            )}
            <button onClick={onClose} className="w-10 h-10 -mr-2 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" aria-label="Закрыть историю">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
        <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 dark:text-slate-400 ml-9 mb-4">
          Архив ваших подборов
        </div>

        <div className="flex bg-slate-100 dark:bg-slate-800/50 rounded-2xl p-1.5 shadow-inner">
          <button onClick={() => setTab('all')} className={cn("flex-1 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all", tab === 'all' ? "bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm scale-100" : "text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 scale-[0.98]")}>
            Все ({entries.length})
          </button>
          <button onClick={() => setTab('favs')} className={cn("flex-1 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2", tab === 'favs' ? "bg-white dark:bg-slate-700 text-amber-500 dark:text-white shadow-sm scale-100" : "text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 scale-[0.98]")}>
            <StarIcon filled={tab === 'favs'} className="w-3.5 h-3.5" />
            Избранное ({favCount})
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-24 custom-scrollbar">
        {shown.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 opacity-40">
            <svg className="w-16 h-16 text-slate-300 mb-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
            <p className="text-sm font-bold text-slate-500">{tab === 'favs' ? 'Нет избранных рецептов' : 'История пуста'}</p>
          </div>
        ) : shown.map(e => (
          <button key={e.id} onClick={() => onViewRecipe(e)}
            className="w-full group relative flex flex-col gap-3 p-4 rounded-2xl bg-white dark:bg-slate-800/40 border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-500/30 dark:hover:border-indigo-500/30 hover:shadow-md transition-all active:scale-[0.98] text-left overflow-hidden">
            
            {/* Фон-индикатор для избранного */}
            {favorites.has(favKey(e)) && (
              <div className="absolute top-0 right-0 w-16 h-16 pointer-events-none overflow-hidden">
                <div className="absolute top-0 right-0 w-full h-full bg-amber-500/10 rotate-45 translate-x-8 -translate-y-8" />
                <StarIcon filled className="absolute top-2 right-2 text-amber-500 w-4 h-4" />
              </div>
            )}

            <div className="flex items-center justify-between gap-4">
              <div className="flex items-center gap-3 min-w-0 flex-1">
                <div className="flex -space-x-2 shrink-0">
                  <div className="w-12 h-12 rounded-xl border-2 border-white dark:border-slate-800 shadow-sm relative z-10" style={{ backgroundColor: e.hex }} />
                  <div className="w-12 h-12 rounded-xl border-2 border-white dark:border-slate-800 shadow-sm relative z-0" style={{ backgroundColor: `rgb(${e.approxRgb})` }} />
                </div>
                <div className="min-w-0">
                  <div className="text-sm font-black font-mono text-slate-900 dark:text-white leading-none mb-1.5">{e.hex}</div>
                  <div className="flex items-center gap-2">
                    <span className={cn(
                      "px-2 py-0.5 rounded-md text-xs font-black tabular-nums border",
                      getAccuracyInfo(e.deltaE).badgeClass
                    )}>
                      ΔE {e.deltaE.toFixed(1)}
                    </span>
                    <span className="text-xs font-bold text-slate-600 dark:text-slate-400 uppercase tracking-tighter">
                      {formatParts(e.totalDrops, e.paintType ? PAINT_PROFILES[e.paintType] : profile)}
                    </span>
                  </div>
                </div>
              </div>

              <div className="text-right shrink-0">
                <div className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1 group-hover:text-indigo-500 transition-colors">
                  {formatSmartDate(e.timestamp)}
                </div>
                <div className="flex items-center justify-end gap-1.5 text-slate-500 dark:text-slate-400">
                   {e.paintType && <span className="text-xs">{PAINT_PROFILES[e.paintType].icon}</span>}
                   <span className="text-xs font-bold uppercase tracking-tighter">{e.recipe.length} компонентов</span>
                </div>
              </div>
            </div>
            
            {/* Мини-превью рецепта (только на десктопе или при наведении) */}
            <div className="flex gap-1 overflow-hidden opacity-60">
              {e.recipe.slice(0, 8).map((r, i) => (
                <div key={i} className="w-3 h-1.5 rounded-full border border-black/5" style={{ backgroundColor: `rgb(${r.rgb})` }} />
              ))}
              {e.recipe.length > 8 && <div className="text-xs font-black text-slate-500 self-center leading-none">+ {e.recipe.length - 8}</div>}
            </div>
          </button>
        ))}
      </div>
    </Modal>
  );
}