import type { RGB } from '../../config';

/**
 * Вычисляет относительную яркость (luminance) по формуле ITU-R BT.601
 */
export function getLuminance(rgb: RGB): number {
  return 0.299 * rgb[0] + 0.587 * rgb[1] + 0.114 * rgb[2];
}

/**
 * Ограничивает значение в диапазоне [0, 360] для hue
 */
export function clampHue(h: number): number {
  return ((h % 360) + 360) % 360;
}

/**
 * Ограничивает значение в диапазоне [0, 1] для saturation/lightness
 */
export function clamp01(v: number): number {
  return Math.max(0, Math.min(1, v));
}

/**
 * Линейная интерполяция между двумя значениями
 */
export function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

/**
 * Линейная интерполяция между двумя RGB цветами
 */
export function lerpRgb(c1: RGB, c2: RGB, t: number): RGB {
  return [
    Math.round(lerp(c1[0], c2[0], t)),
    Math.round(lerp(c1[1], c2[1], t)),
    Math.round(lerp(c1[2], c2[2], t)),
  ];
}

/**
 * Интерполяция hue с учётом цикличности (оба значения в градусах)
 */
export function lerpHue(h1: number, h2: number, t: number): number {
  let diff = h2 - h1;
  if (diff > 180) diff -= 360;
  if (diff < -180) diff += 360;
  return clampHue(h1 + diff * t);
}