// src/components/ui/ErrorBoundary.tsx
import { Component, ReactNode, ErrorInfo } from 'react';

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
}

interface State {
  hasError: boolean;
  errorMsg: string;
}

export class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    errorMsg: ''
  };

  public static getDerivedStateFromError(error: Error): State {
    // Обновляем состояние, чтобы следующий рендер показал запасной UI.
    return { hasError: true, errorMsg: error.message };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Здесь можно логировать ошибку в Sentry или другой сервис
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      // Запасной UI по умолчанию
      return (
        <div className="flex flex-col items-center justify-center p-6 text-center w-full h-full min-h-[200px] bg-slate-50 dark:bg-slate-900 rounded-xl border border-red-200 dark:border-red-900/30">
          <div className="w-16 h-16 mb-4 bg-red-100 dark:bg-red-900/20 text-red-500 rounded-full flex items-center justify-center">
            <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z" />
              <line x1="12" y1="9" x2="12" y2="13" />
              <line x1="12" y1="17" x2="12.01" y2="17" />
            </svg>
          </div>
          <h2 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Упс, что-то пошло не так</h2>
          <p className="text-sm text-slate-600 dark:text-slate-200 mb-6 max-w-md">
            Произошла ошибка при отображении этого блока. Ваша работа сохранена.
          </p>
          <button 
            onClick={() => window.location.reload()} 
            className="px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl transition-colors shadow-md"
          >
            Перезагрузить приложение
          </button>
          <p className="mt-4 text-xs text-slate-500 font-mono break-all line-clamp-2 max-w-full">
            {this.state.errorMsg}
          </p>
        </div>
      );
    }

    return this.props.children;
  }
}