// ============================================================
// СЛАЙДЕР
// ============================================================

interface SliderControlProps {
  label:    string;
  value:    number;
  min:      number;
  max:      number;
  step:     number;
  display:  string;
  onChange: (v: number) => void;
  color:    'indigo' | 'violet' | 'sky' | 'amber';
}

const SLIDER_COLORS: Record<string, string> = {
  indigo: 'accent-indigo-500',
  violet: 'accent-violet-500',
  sky:    'accent-sky-500',
  amber:  'accent-amber-500',
};

function SliderControl({
  label, value, min, max, step, display, onChange, color,
}: SliderControlProps) {
  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center justify-between">
        <span className="text-xs font-black uppercase tracking-wider text-slate-400">
          {label}
        </span>
        <span className="text-xs font-bold text-slate-600 dark:text-slate-300 font-mono">
          {display}
        </span>
      </div>
      <input
        type="range" min={min} max={max} step={step} value={value}
        onChange={e => onChange(parseFloat(e.target.value))}
        className={cn('w-full h-1.5 rounded-full cursor-pointer', SLIDER_COLORS[color])}
      />
    </div>
  );
}

// ============================================================
// ХОЛСТ
// ============================================================

function PaperCanvas() {
  const labState     = useLabStore();
  const canvasRef    = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  
  // Буфер для запекания старых мазков
  const bakedCanvasRef = useRef<HTMLCanvasElement | null>(null);
  const lastBakedIdxRef = useRef(0);
  const lastParamsRef = useRef({ showDry: false, surfaceType: '' });
  
  const isDrawing    = useRef(false);
  const surface      = SURFACE_PROFILES[labState.surfaceType];

  const render = useCallback(() => {
    const canvas    = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const rect = container.getBoundingClientRect();
    if (rect.width === 0 || rect.height === 0) return;

    const dpr = window.devicePixelRatio || 1;
    const bw  = Math.round(rect.width  * dpr);
    const bh  = Math.round(rect.height * dpr);

    if (canvas.width !== bw || canvas.height !== bh) {
      canvas.width  = bw; canvas.height = bh;
      if (bakedCanvasRef.current) { bakedCanvasRef.current.width = bw; bakedCanvasRef.current.height = bh; }
      lastBakedIdxRef.current = 0; // Сброс при ресайзе
    }

    // Инициализация буфера запекания
    if (!bakedCanvasRef.current) {
      bakedCanvasRef.current = document.createElement('canvas');
      bakedCanvasRef.current.width = bw;
      bakedCanvasRef.current.height = bh;
    }

    // Если изменились глобальные параметры, сбрасываем запекание
    if (lastParamsRef.current.showDry !== labState.showDry || lastParamsRef.current.surfaceType !== labState.surfaceType) {
      lastBakedIdxRef.current = 0;
      lastParamsRef.current = { showDry: labState.showDry, surfaceType: labState.surfaceType };
    }

    const bCtx = bakedCanvasRef.current.getContext('2d');
    const ctx = canvas.getContext('2d');
    if (!ctx || !bCtx) return;

    // 1. ЗАПЕКАНИЕ (Baking)
    // Оставляем последние 15 мазков динамичными, остальные вшиваем в фон
    const bakeLimit = Math.max(0, labState.swatches.length - 15);
    
    if (lastBakedIdxRef.current === 0) {
      // Полная перерисовка фона
      bCtx.save();
      bCtx.scale(dpr, dpr);
      bCtx.fillStyle = `rgb(${surface.color})`;
      bCtx.fillRect(0, 0, rect.width, rect.height);
      drawSurfaceTexture(bCtx, labState.surfaceType, rect.width, rect.height);
      bCtx.restore();
    }

    if (lastBakedIdxRef.current < bakeLimit) {
      // Дорисовываем новые созревшие мазки в буфер
      for (let i = lastBakedIdxRef.current; i < bakeLimit; i++) {
        drawSwatch(bCtx, labState.swatches[i], rect.width, rect.height, surface.absorption, labState.showDry, labState.surfaceType);
      }
      lastBakedIdxRef.current = bakeLimit;
    }

    // 2. ФИНАЛЬНЫЙ ВЫВОД
    ctx.clearRect(0, 0, bw, bh);
    // Рисуем запеченный фон
    ctx.drawImage(bakedCanvasRef.current, 0, 0);

    // Рисуем только активные (последние) мазки поверх
    ctx.save();
    ctx.scale(dpr, dpr);
    for (let i = lastBakedIdxRef.current; i < labState.swatches.length; i++) {
      drawSwatch(ctx, labState.swatches[i], rect.width, rect.height, surface.absorption, labState.showDry, labState.surfaceType);
    }
    ctx.restore();

  }, [labState.swatches, labState.surfaceType, labState.showDry, surface]);

  // Рисуем при любом изменении данных
  useLayoutEffect(() => {
    render();
  }, [render]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const ro = new ResizeObserver(entries => {
      const entry = entries[0];
      if (entry) {
        labState.setCanvasSize(entry.contentRect.width, entry.contentRect.height);
      }
    });
    ro.observe(container);
    return () => ro.disconnect();
  }, []);

  const handlePointerDown = (e: React.PointerEvent) => {
    if (e.button !== 0 && e.pointerType === 'mouse') return;
    isDrawing.current = true;
    const rect = containerRef.current!.getBoundingClientRect();
    const data = pointerEventToData(e, rect);
    labState.startStroke(data, rect.width, rect.height);
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDrawing.current) return;
    const rect = containerRef.current!.getBoundingClientRect();
    const data = pointerEventToData(e, rect);
    labState.continueStroke(data, rect.width, rect.height);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    isDrawing.current = false;
    labState.endStroke();
    (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  };

  return (
    <div ref={containerRef} className="absolute inset-0 w-full h-full">
      <canvas
        ref={canvasRef}
        className="w-full h-full touch-none"
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerCancel={handlePointerUp}
      />
      {labState.wells[labState.activeWellIndex]?.totalParts === 0 && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm rounded-2xl px-5 py-3 border border-slate-200/50 dark:border-slate-700/50 shadow-sm">
            <p className="text-xs font-black uppercase tracking-widest text-slate-400">Добавьте краску в лунку</p>
          </div>
        </div>
      )}
      <StylusIndicator />
    </div>
  );
}

