function StylusIndicator() {
  const [pointerType, setPointerType] = useState<string | null>(null);
  const [pressure,    setPressure]    = useState(0);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const onMove = (e: PointerEvent) => {
      if (e.pointerType === 'pen') {
        setPointerType('pen');
        setPressure(e.pressure);
        if (timerRef.current) clearTimeout(timerRef.current);
        timerRef.current = setTimeout(() => setPointerType(null), 2000);
      }
    };
    window.addEventListener('pointermove', onMove);
    return () => window.removeEventListener('pointermove', onMove);
  }, []);

  if (pointerType !== 'pen') return null;

  return (
    <div className="absolute top-3 right-3 flex items-center gap-2
      bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm rounded-xl
      px-3 py-1.5 border border-slate-200/50 dark:border-slate-700/50
      shadow-sm pointer-events-none">
      <svg width="12" height="12" viewBox="0 0 24 24" fill="none"
        stroke="currentColor" strokeWidth="2"
        className="text-indigo-500">
        <path d="M12 19l7-7 3 3-7 7-3-3z"/>
        <path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"/>
        <path d="M2 2l7.586 7.586"/>
        <circle cx="11" cy="11" r="2"/>
      </svg>
      <div className="flex flex-col">
        <span className="text-xs font-black uppercase tracking-wider
          text-slate-400">
          Стилус
        </span>
        <div className="flex items-center gap-1">
          <div className="w-16 h-1 bg-slate-200 dark:bg-slate-700 rounded-full">
            <div
              className="h-full bg-indigo-500 rounded-full transition-all duration-75"
              style={{ width: `${Math.round(pressure * 100)}%` }}
            />
          </div>
          <span className="text-xs font-mono text-slate-500">
            {Math.round(pressure * 100)}%
          </span>
        </div>
      </div>
    </div>
  );
}

