import { cn } from '../../utils/cn';

export function MetricCard({ title, value, accent }: { title: string; value: string; accent?: string }) {
  const isDE = title === 'ΔE';
  const isParts = title === 'Части';

  return (
    <div className="bg-white dark:bg-slate-900 rounded-xl p-3.5 sm:p-4 flex flex-col flex-1 min-w-0 border-2 border-slate-50 dark:border-slate-800 shadow-sm relative overflow-hidden group">
      <div className="absolute top-0 right-0 w-16 h-16 bg-slate-50 dark:bg-slate-800/50 rounded-bl-[2rem] pointer-events-none -mr-4 -mt-4 transition-transform" />
      
      <div className="flex items-center gap-2 mb-1.5 relative z-10">
        <span className="text-slate-600 dark:text-slate-400">
           {isDE && <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 2v20M2 12h20"/><circle cx="12" cy="12" r="10"/></svg>}
           {isParts && <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 21a9 9 0 1 0 0-18 9 9 0 0 0 0 18Z"/><path d="M12 7v5l4 2"/></svg>}
        </span>
        <div className="text-xs font-black uppercase tracking-widest text-slate-600 dark:text-slate-400">{title}</div>
      </div>

      <div className={cn("text-xl sm:text-2xl font-black tracking-tighter truncate relative z-10 leading-none", accent || "text-slate-900 dark:text-white")}>
        {value}
      </div>
    </div>
  );
}
